import * as THREE from 'three';
import { assetUrl } from '../utils/assetUrl.js';

const STAGE_BUILDERS = {
  village_akhara: buildVillageAkhara,
  karachi_rooftop: buildKarachiRooftop,
  karachi_seaview: buildKarachiSeaView,
  lahore_minar: buildLahoreMinar,
  islamabad_faisal: buildIslamabadFaisal,
};

export class Stage {
  constructor(stageData, assetLoader) {
    this.data = stageData;
    this.assetLoader = assetLoader;
    this.group = new THREE.Group();
    this.group.name = `stage_${stageData.id}`;
    this._animatedLayers = [];
  }

  async load() {
    if (this._loaded) return;
    const builder = STAGE_BUILDERS[this.data.id];
    if (!builder) {
      console.warn(`[Stage] no builder for stage "${this.data.id}"`);
      this._loaded = true;
      return;
    }
    await builder(this);
    this._loaded = true;
  }

  applyLighting(scene) {
    if (this._extraLights) {
      for (const l of this._extraLights) scene.remove(l);
      this._extraLights = [];
    }
    if (this.data.lighting?.fog) {
      const { color, near, far } = this.data.lighting.fog;
      scene.background = new THREE.Color(color);
      scene.fog = new THREE.Fog(color, near, far);
    }
    const profile = this.data.lighting;
    if (!profile) return;
    const sunset = new THREE.DirectionalLight(0xff8a3a, 0.55);
    sunset.position.set(2, 2.5, -7);
    sunset.name = 'stage_sunset_rim';
    scene.add(sunset);
    this._extraLights = [sunset];
  }

  update(_dt) {
    const t = performance.now() * 0.001;
    for (const layer of this._animatedLayers) {
      layer.mesh.position.x =
        layer.baseX + Math.sin(t * layer.swaySpeed + layer.swayPhase) * layer.swayAmp;
    }
  }
}

// ---- helpers --------------------------------------------------------------

function plane(w, h, mat) {
  const m = new THREE.Mesh(new THREE.PlaneGeometry(w, h), mat);
  m.frustumCulled = false;
  return m;
}

function addImageLayer(stage, url, opts = {}) {
  const {
    width = 40,
    height = 10,
    position = [0, 3, -10],
    alphaTest = 0.04,
    chromaKey = false,
    chromaKeyOptions = {},
    cleanLightBackdrop = true,
    opacity = 1,
    sway = null,
  } = opts;
  const tex = chromaKey
    ? loadTextureChromaKeyed(url, chromaKeyOptions)
    : cleanLightBackdrop
      ? loadTextureLightBackdropKeyed(url)
      : stage.assetLoader.loadTexture(url);
  const mesh = plane(width, height, new THREE.MeshBasicMaterial({
    map: tex,
    transparent: true,
    opacity,
    depthWrite: false,
    alphaTest,
    side: THREE.DoubleSide,
  }));
  mesh.position.set(...position);
  stage.group.add(mesh);
  if (sway) {
    stage._animatedLayers.push({
      mesh,
      baseX: mesh.position.x,
      swaySpeed: sway.speed ?? 0.5,
      swayPhase: sway.phase ?? 0,
      swayAmp: sway.amp ?? 0.05,
    });
  }
  return mesh;
}

function addGround(stage, url, opts = {}) {
  const {
    width = 24,
    depth = 10,
    repeat = [2, 1],
    roughness = 0.8,
    metalness = 0.0,
  } = opts;
  const groundTex = stage.assetLoader.loadTexture(url);
  groundTex.wrapS = THREE.RepeatWrapping;
  groundTex.wrapT = THREE.RepeatWrapping;
  groundTex.repeat.set(...repeat);
  groundTex.needsUpdate = true;
  const ground = new THREE.Mesh(
    new THREE.PlaneGeometry(width, depth),
    new THREE.MeshStandardMaterial({ map: groundTex, roughness, metalness }),
  );
  ground.rotation.x = -Math.PI / 2;
  ground.position.y = 0.001;
  ground.receiveShadow = true;
  ground.name = 'stage_ground';
  stage.group.add(ground);
  return ground;
}

function loadImageElement(url) {
  return new Promise((resolve) => {
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => resolve(img);
    img.onerror = () => {
      console.warn(`[image] ${url}: failed to load`);
      resolve(null);
    };
    img.src = url;
  });
}

function drawCover(ctx, img, x, y, w, h, ax = 0.5, ay = 0.5) {
  const iw = img.naturalWidth || img.width;
  const ih = img.naturalHeight || img.height;
  const scale = Math.max(w / iw, h / ih);
  const dw = iw * scale;
  const dh = ih * scale;
  ctx.drawImage(img, x + (w - dw) * ax, y + (h - dh) * ay, dw, dh);
}

function drawContain(ctx, img, x, y, w, h, ax = 0.5, ay = 0.5) {
  const iw = img.naturalWidth || img.width;
  const ih = img.naturalHeight || img.height;
  const scale = Math.min(w / iw, h / ih);
  const dw = iw * scale;
  const dh = ih * scale;
  ctx.drawImage(img, x + (w - dw) * ax, y + (h - dh) * ay, dw, dh);
}

function keyDarkBackdrop(img) {
  const canvas = document.createElement('canvas');
  canvas.width = img.naturalWidth || img.width;
  canvas.height = img.naturalHeight || img.height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.drawImage(img, 0, 0);
  const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
  const px = data.data;
  for (let i = 0; i < px.length; i += 4) {
    const r = px[i];
    const g = px[i + 1];
    const b = px[i + 2];
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);
    const avg = (r + g + b) / 3;
    const isDarkBackdrop = avg < 118 && max - min < 52;
    if (isDarkBackdrop) {
      px[i + 3] = 0;
    }
  }
  ctx.putImageData(data, 0, 0);
  return canvas;
}

function keyNeutralLightBackdrop(img) {
  const canvas = document.createElement('canvas');
  canvas.width = img.naturalWidth || img.width;
  canvas.height = img.naturalHeight || img.height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.drawImage(img, 0, 0);
  const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
  const px = data.data;
  for (let i = 0; i < px.length; i += 4) {
    const r = px[i];
    const g = px[i + 1];
    const b = px[i + 2];
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);
    const avg = (r + g + b) / 3;
    const lowSaturation = max - min < 46;
    const isTransparentChecker =
      (avg > 224 && lowSaturation) ||
      (avg > 184 && max - min < 22);
    if (isTransparentChecker) {
      px[i + 3] = 0;
    } else if (avg > 170 && lowSaturation) {
      const keep = Math.max(0, Math.min(1, (224 - avg) / 54));
      px[i + 3] = Math.floor(px[i + 3] * keep * 0.35);
    }
  }
  ctx.putImageData(data, 0, 0);
  return canvas;
}

function keyCheckerTileBackdrop(img) {
  const canvas = document.createElement('canvas');
  canvas.width = img.naturalWidth || img.width;
  canvas.height = img.naturalHeight || img.height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  ctx.drawImage(img, 0, 0);
  const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
  const px = data.data;
  for (let i = 0; i < px.length; i += 4) {
    const r = px[i];
    const g = px[i + 1];
    const b = px[i + 2];
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);
    const avg = (r + g + b) / 3;
    const lowSaturation = max - min < 48;
    const lightGrayTile = avg > 142 && lowSaturation;
    const paleTile = avg > 118 && max - min < 34;
    if (lightGrayTile || paleTile) {
      px[i + 3] = 0;
    }
  }
  ctx.putImageData(data, 0, 0);
  return canvas;
}

function loadLahoreBackdropTexture(base) {
  const canvas = document.createElement('canvas');
  canvas.width = 1600;
  canvas.height = 900;
  const ctx = canvas.getContext('2d');
  const tex = new THREE.CanvasTexture(canvas);
  tex.colorSpace = THREE.SRGBColorSpace;
  tex.anisotropy = 4;

  const fallback = ctx.createLinearGradient(0, 0, 0, canvas.height);
  fallback.addColorStop(0, '#4f9cc0');
  fallback.addColorStop(0.5, '#f3c568');
  fallback.addColorStop(1, '#6d7f40');
  ctx.fillStyle = fallback;
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  tex.needsUpdate = true;

  Promise.all([
    loadImageElement(`${base}/sky.png`),
    loadImageElement(`${base}/lawn.png`),
    loadImageElement(`${base}/minar.png`),
  ]).then(([sky, lawn, minar]) => {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    if (sky) drawCover(ctx, sky, 0, 0, canvas.width, canvas.height, 0.5, 0.5);

    if (lawn) {
      ctx.save();
      ctx.globalAlpha = 0.98;
      const cleanLawn = keyNeutralLightBackdrop(lawn);
      const sy = Math.floor(cleanLawn.height * 0.42);
      ctx.drawImage(
        cleanLawn,
        0,
        sy,
        cleanLawn.width,
        cleanLawn.height - sy,
        -60,
        430,
        canvas.width + 120,
        250,
      );
      ctx.restore();
    }

    if (minar) {
      ctx.save();
      ctx.globalAlpha = 0.98;
      drawContain(ctx, keyNeutralLightBackdrop(minar), 560, 210, 480, 430, 0.5, 1);
      ctx.restore();
    }

    const warmth = ctx.createLinearGradient(0, 240, 0, 700);
    warmth.addColorStop(0, 'rgba(255,221,128,0.10)');
    warmth.addColorStop(0.55, 'rgba(255,170,66,0.16)');
    warmth.addColorStop(1, 'rgba(255,210,140,0.04)');
    ctx.fillStyle = warmth;
    ctx.fillRect(0, 240, canvas.width, 460);
    tex.needsUpdate = true;
  });

  return tex;
}

