async function buildKarachiSeaView(stage) {
  const base = assetUrl('/stages/karachi_seaview');
  const loader = stage.assetLoader;

  // Sky — opaque golden-hour plate. Positioned so the sun disc lands roughly
  // around the in-game horizon (camera looks at y≈1.2 from z≈7.5).
  const skyTex = loader.loadTexture(`${base}/sky.png`);
  const sky = plane(48, 14, new THREE.MeshBasicMaterial({ map: skyTex, depthWrite: false }));
  sky.position.set(0, 5, -22);
  stage.group.add(sky);

  // Sea + horizon + distant ships + Manora lighthouse.
  // Sized so the waterline sits just above the ground plane.
  const seaTex = loader.loadTexture(`${base}/sea.png`);
  const sea = plane(40, 8, new THREE.MeshBasicMaterial({
    map: seaTex, transparent: true, depthWrite: false, alphaTest: 0.04,
  }));
  sea.position.set(0, 1.6, -15);
  stage.group.add(sea);

  addImageLayer(stage, `${base}/beach_back.png`, {
    width: 34,
    height: 7,
    position: [0, 1.55, -8],
    alphaTest: 0.04,
  });

  addImageLayer(stage, `${base}/foreground.png`, {
    width: 28,
    height: 5,
    position: [0, 0.9, -3.2],
    alphaTest: 0.04,
  });

  // Wet sand floor — warm with subtle wave reflection.
  addGround(stage, `${base}/ground.png`, {
    width: 26,
    depth: 10,
    repeat: [2, 1],
    roughness: 0.55,
    metalness: 0.12,
  });
}

