/**
 * moves.js
 * --------
 * Frame data for every move in the game. Engine code reads from here; nothing
 * is hardcoded in states. Each move is a sequence of phases:
 *
 *   startup → active → recovery
 *
 * with hitboxes only "live" during the active phase. Numbers are in *frames at
 * 60 FPS*; convert to seconds at runtime with frames / 60.
 *
 * Shape of a move entry:
 *
 *   {
 *     id:        string                // matches what characters.js references
 *     name:      string                // display name
 *     animation: string                // canonical game animation name
 *     startup:   number                // frames before hitbox is active
 *     active:    number                // frames hitbox is live
 *     recovery:  number                // frames before next action allowed
 *     damage:    number                // HP removed on clean hit
 *     chip:      number                // HP removed when blocked
 *     hitstun:   number                // frames defender is stunned on hit
 *     blockstun: number                // frames defender is stuck blocking
 *     pushback:  number                // metres of horizontal knockback
 *     hitLevel:  'high' | 'low' | 'mid' | 'overhead'
 *     hitbox:    { x, y, w, h }        // attached to attacker, mirrored by facing
 *     fx:        { sound, particle }   // optional juice hooks
 *     meterGain: number                // % of super meter built on hit (0–100)
 *     meterCost: number                // % of super meter required to use
 *   }
 *
 * Phase 4 wires these into AttackState. Numbers below are first-pass and
 * will need balancing once the game is playable.
 */

