/**
 * StateMachine
 * ------------
 * Lightweight FSM tailored to fighter behavior.
 *
 * Each state is an object that may implement:
 *   - enter(fighter, prev, payload)
 *   - update(dt, input, fighter)  -> next-state directive or null
 *   - exit(fighter, next)
 *
 * update() can return:
 *   - null / undefined        -> stay in current state
 *   - 'state_name'            -> transition with no payload
 *   - { next, payload }       -> transition with a payload object
 *
 * change() can also be called imperatively from outside (e.g. takeHit).
 */
export class StateMachine {
  /** @param {import('./Fighter.js').Fighter} fighter */
  constructor(fighter) {
    this.fighter = fighter;
    /** @type {Map<string, any>} */
    this.states = new Map();
    this.currentName = null;
    this.current = null;
  }

  register(name, state) {
    this.states.set(name, state);
  }

  /** Force a transition. */
  change(name, payload) {
    const next = this.states.get(name);
    if (!next) {
      console.warn(`[StateMachine] unknown state "${name}"`);
      return;
    }
    const prev = this.current;
    prev?.exit?.(this.fighter, name);
    this.currentName = name;
    this.current = next;
    next.enter?.(this.fighter, prev, payload);
  }

  update(dt, input) {
    if (!this.current) return;
    const directive = this.current.update?.(dt, input, this.fighter);
    if (directive == null) return;
    if (typeof directive === 'string') {
      if (directive !== this.currentName) this.change(directive);
    } else if (typeof directive === 'object' && directive.next) {
      this.change(directive.next, directive.payload);
    }
  }
}
