import { Physics } from '../engine/Physics.js';

/**
 * ProjectileManager
 * -----------------
 * Owns the list of live projectiles for both fighters, ticks them, and
 * resolves collisions:
 *   - projectile × opposing fighter hurtbox → damage/chip + despawn
 *   - projectile × opposing projectile      → both cancel (Hadoken clash)
 */
export class ProjectileManager {
  constructor({ scene }) {
    this.scene = scene;
    /** @type {import('./Projectile.js').Projectile[]} */
    this.projectiles = [];
  }

  add(p) { this.projectiles.push(p); }

  update(dt, fighters) {
    for (const p of this.projectiles) p.update(dt);

    // Pairwise opponent-projectile clash
    for (let i = 0; i < this.projectiles.length; i++) {
      const a = this.projectiles[i];
      if (a.dead) continue;
      for (let j = i + 1; j < this.projectiles.length; j++) {
        const b = this.projectiles[j];
        if (b.dead || a.owner === b.owner) continue;
        if (this._aabbHit(a.aabb(), b.aabb())) a.cancelWith(b);
      }
    }

    // Projectile vs opposing fighter hurtbox
    for (const p of this.projectiles) {
      if (p.dead || p.hasHit) continue;
      const target = fighters.find(f => f !== p.owner);
      if (!target || target.hp <= 0) continue;
      const hurts = target.activeHurtboxes?.() ?? [];
      const pBox = p.aabb();
      for (const hu of hurts) {
        if (this._aabbHit(pBox, hu)) {
          p.hasHit = true;
          const move = {
            id: 'hadoken',
            damage: p.config.damage,
            chip: p.config.chip,
            hitstun: p.config.hitstun,
            blockstun: Math.floor(p.config.hitstun * 0.7),
            pushback: 0.8,
            hitLevel: 'mid',
          };
          target.takeHit({ move, fromX: p.position.x });
          p.kill();
          break;
        }
      }
    }

    // Sweep the dead
    this.projectiles = this.projectiles.filter(p => !p.dead);
  }

  _aabbHit(a, b) {
    return (
      a.x < b.x + b.w &&
      a.x + a.w > b.x &&
      a.y < b.y + b.h &&
      a.y + a.h > b.y
    );
  }

  /** Tear down all live projectiles (e.g. on round reset). */
  clear() {
    for (const p of this.projectiles) p.kill();
    this.projectiles = [];
  }
}
