import * as THREE from 'three';
import { AABB } from '../engine/Physics.js';

/**
 * Projectile
 * ----------
 * A single fireball travelling along the X axis at constant speed.
 * Lives until it hits the opponent, collides with another projectile,
 * or its lifespan runs out.
 *
 *   const fb = new Projectile({
 *     owner: fighter,
 *     spawn: { x, y },
 *     facing: +1,
 *     config: { speed, damage, hitstun, chip, lifespan, color, radius },
 *     scene: sceneManager.scene,
 *   });
 */
export class Projectile {
  constructor({ owner, spawn, facing, config, scene }) {
    this.owner = owner;
    this.facing = facing;
    this.config = config;
    this.scene = scene;
    this.position = { x: spawn.x, y: spawn.y };
    this.age = 0;
    this.dead = false;
    this.hasHit = false;

    // --- Visual: a glowing sprite-like billboard ---
    const tex = Projectile._makeRadialTexture(config.color);
    const mat = new THREE.SpriteMaterial({
      map: tex,
      color: config.color,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      transparent: true,
    });
    this.sprite = new THREE.Sprite(mat);
    const d = config.radius * 2.2;
    this.sprite.scale.set(d, d, 1);
    this.sprite.position.set(this.position.x, this.position.y, 0.1);
    scene.add(this.sprite);

    // Trail — a short echo of fading sprites
    this._trail = [];
    for (let i = 0; i < 6; i++) {
      const t = new THREE.Sprite(mat.clone());
      t.scale.set(d * (1 - i * 0.12), d * (1 - i * 0.12), 1);
      t.material.opacity = 0.6 - i * 0.09;
      t.position.set(this.position.x, this.position.y, 0.1);
      scene.add(t);
      this._trail.push({ sprite: t, x: this.position.x, y: this.position.y });
    }
  }

  static _radialTexCache = new Map();
  static _makeRadialTexture(color) {
    if (Projectile._radialTexCache.has(color)) return Projectile._radialTexCache.get(color);
    const c = document.createElement('canvas');
    c.width = 128; c.height = 128;
    const ctx = c.getContext('2d');
    const g = ctx.createRadialGradient(64, 64, 6, 64, 64, 64);
    g.addColorStop(0.0, 'rgba(255,255,255,1.0)');
    g.addColorStop(0.3, 'rgba(255,255,200,0.9)');
    g.addColorStop(0.6, 'rgba(255,180,80,0.5)');
    g.addColorStop(1.0, 'rgba(255,80,0,0.0)');
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, 128, 128);
    const tex = new THREE.CanvasTexture(c);
    tex.colorSpace = THREE.SRGBColorSpace;
    Projectile._radialTexCache.set(color, tex);
    return tex;
  }

  update(dt) {
    this.age += dt;
    if (this.age > this.config.lifespan) {
      this.kill();
      return;
    }

    // Advance the trail one step
    for (let i = this._trail.length - 1; i > 0; i--) {
      this._trail[i].x = this._trail[i - 1].x;
      this._trail[i].y = this._trail[i - 1].y;
    }
    if (this._trail.length) {
      this._trail[0].x = this.position.x;
      this._trail[0].y = this.position.y;
    }

    this.position.x += this.config.speed * this.facing * dt;
    this.sprite.position.set(this.position.x, this.position.y, 0.1);
    for (const t of this._trail) t.sprite.position.set(t.x, t.y, 0.1);

    // Off-stage cull
    if (Math.abs(this.position.x) > 9.5) this.kill();
  }

  /** AABB for collision tests this frame. */
  aabb() {
    const r = this.config.radius;
    return new AABB(this.position.x - r, this.position.y - r * 0.6, r * 2, r * 1.6);
  }

  /** Cancel both projectiles when they collide. */
  cancelWith(other) {
    this.kill();
    other.kill();
  }

  kill() {
    if (this.dead) return;
    this.dead = true;
    this.scene.remove(this.sprite);
    this.sprite.material.dispose();
    for (const t of this._trail) {
      this.scene.remove(t.sprite);
      t.sprite.material.dispose();
    }
    this._trail = [];
  }
}
