import { MOVES } from '../../data/moves.js';

/**
 * ShoryukenState
 * --------------
 * Anti-air rising attack. Applies a strong upward velocity + slight
 * forward drift, plays a special clip, and exposes an active hitbox
 * during the ascent. On hit, the opponent is launched into the air.
 *
 * The state stays active until the fighter is grounded again, so the
 * Mixamo `special_1` clip plays over the full arc.
 *
 *   payload: { moveId: string }
 */
export const ShoryukenState = {
  name: 'shoryuken',

  enter(fighter, _prev, payload = {}) {
    const move = MOVES[payload.moveId] ?? MOVES.shoryuken_normal;
    this._move = move;
    this._frame = 0;
    this._hasHit = false;
    this._grounded = false;

    // Vertical launch — strong enough to fully leave the ground but
    // shorter than a normal jump so the recovery is tight.
    const selfY = move.launch?.selfY ?? 1.0;
    const selfX = move.launch?.selfX ?? 0.35;
    fighter.velocity.y = fighter.jumpVelocity * selfY;
    fighter.velocity.x = fighter.facing * selfX * fighter.walkSpeed;
    fighter.isGrounded = false;

    // Expose the active hitbox the resolver reads through Fighter.activeHitboxes.
    const self = this;
    fighter._currentAttack = {
      move,
      frame: 0,
      isActive: false,
      get hasHit() { return self._hasHit; },
    };

    fighter.playClip(move.animation ?? 'special_1', { loop: false, fade: 0.05 });
  },

  update(dt, _input, fighter) {
    this._frame += dt * 60;
    const m = this._move;
    const activeStart = m.startup ?? 4;
    const activeEnd = activeStart + (m.active ?? 14);

    if (fighter._currentAttack) {
      fighter._currentAttack.frame = this._frame;
      fighter._currentAttack.isActive =
        this._frame >= activeStart && this._frame < activeEnd && !this._hasHit;
    }

    // Once the attacker lands back on the ground, recover.
    if (fighter.isGrounded && this._frame > activeEnd) {
      return 'idle';
    }
    return null;
  },

  /** Called by combat resolver when the hit lands. */
  markHit(fighter) {
    this._hasHit = true;
    if (fighter && fighter._currentAttack) fighter._currentAttack.isActive = false;
  },

  exit(fighter) {
    fighter._currentAttack = null;
  },
};
