/**
 * Physics
 * -------
 * AABB collision + hit/hurtbox resolution for the fight plane.
 *
 * Fighting games don't need a full physics engine — they need *deterministic*
 * box-on-box checks that respect frame data. This module provides:
 *
 *   - AABB.intersects(a, b)               — generic overlap test
 *   - Physics.resolveHits(attacker, defender) — hitbox vs. hurtbox check
 *   - Physics.applyGravity(fighter, dt)   — vertical motion + ground clamp
 *
 * Phase 4 fleshes out hitstun/blockstun + knockback; this stub gives the
 * shape so Fighter and AttackState can be authored against it.
 */

export const GROUND_Y = 0;
export const GRAVITY = -22; // m/s² — heavier than real gravity, FG-feel
export const STAGE_BOUNDS = { minX: -7, maxX: 7 };

/** Axis-aligned bounding box in 2D (XY plane). */
export class AABB {
  /**
   * @param {number} x - left edge
   * @param {number} y - bottom edge
   * @param {number} w - width
   * @param {number} h - height
   */
  constructor(x, y, w, h) {
    this.x = x;
    this.y = y;
    this.w = w;
    this.h = h;
  }

  static intersects(a, b) {
    return (
      a.x < b.x + b.w &&
      a.x + a.w > b.x &&
      a.y < b.y + b.h &&
      a.y + a.h > b.y
    );
  }
}

export class Physics {
  /**
   * Apply gravity + ground clamp to a fighter. Mutates fighter.velocity.y
   * and fighter.position.y.
   *
   * @param {{position: {y:number}, velocity: {y:number}, isGrounded: boolean}} fighter
   * @param {number} dt - delta seconds
   */
  static applyGravity(fighter, dt) {
    if (fighter.position.y > GROUND_Y || fighter.velocity.y > 0) {
      fighter.velocity.y += GRAVITY * dt;
      fighter.position.y += fighter.velocity.y * dt;
      if (fighter.position.y <= GROUND_Y) {
        fighter.position.y = GROUND_Y;
        fighter.velocity.y = 0;
        fighter.isGrounded = true;
      } else {
        fighter.isGrounded = false;
      }
    } else {
      fighter.isGrounded = true;
    }
  }

  /** Clamp a fighter's X position inside the stage walls. */
  static clampToStage(fighter) {
    if (fighter.position.x < STAGE_BOUNDS.minX) fighter.position.x = STAGE_BOUNDS.minX;
    if (fighter.position.x > STAGE_BOUNDS.maxX) fighter.position.x = STAGE_BOUNDS.maxX;
  }

  /**
   * Check active hitboxes from `attacker` against active hurtboxes from
   * `defender`. Returns the first overlap found, or null.
   *
   * Phase 4 wires this into AttackState + HitState.
   *
   * @returns {{hitbox: AABB, hurtbox: AABB} | null}
   */
  static resolveHits(attacker, defender) {
    const hits = attacker.activeHitboxes?.() ?? [];
    const hurts = defender.activeHurtboxes?.() ?? [];
    for (const hb of hits) {
      for (const hu of hurts) {
        if (AABB.intersects(hb, hu)) return { hitbox: hb, hurtbox: hu };
      }
    }
    return null;
  }
}
