import { resolveAttackInput, resolveBlockInput, resolveDaavInput, resolveShoryukenInput } from './_inputMaps.js';

const BACKWARD_FACTOR = 0.75;

export const WalkState = {
  name: 'walk',

  enter(_fighter, _prev, _payload) {
    this._lastDir = 0;
  },

  update(_dt, input, fighter) {
    if (!fighter.isGrounded) return 'jump';
    if (input.wasPressed('up', fighter.playerId)) return 'jump';

    if (fighter.tryHadoken(input)) return null;

    const daav = resolveDaavInput(input, fighter);
    if (daav) return { next: 'attack', payload: { moveId: daav } };

    const dp = resolveShoryukenInput(input, fighter);
    if (dp) return { next: 'shoryuken', payload: { moveId: dp } };

    const atk = resolveAttackInput(input, fighter);
    if (atk) return { next: 'attack', payload: { moveId: atk } };

    if (resolveBlockInput(input, fighter)) {
      return { next: 'block', payload: { low: input.isDown('down', fighter.playerId) } };
    }

    if (input.isDown('down', fighter.playerId)) return 'crouch';

    const left = input.isDown('left', fighter.playerId);
    const right = input.isDown('right', fighter.playerId);
    if (left === right) return 'idle';

    const inputDir = right ? 1 : -1;
    const isForward = inputDir === fighter.facing;
    fighter.velocity.x = inputDir * fighter.walkSpeed * (isForward ? 1 : BACKWARD_FACTOR);

    const dirMode = isForward ? 1 : -1;
    if (dirMode !== this._lastDir) {
      fighter.playClip(isForward ? 'walk_forward' : 'walk_backward', {
        loop: true,
        timeScale: isForward ? 1 : -1,
      });
      this._lastDir = dirMode;
    }
    return null;
  },

  exit(fighter) {
    fighter.velocity.x = 0;
  },
};
