import * as THREE from 'three';

/**
 * SceneManager
 * ------------
 * Owns the active Three.js Scene plus shared lighting. Later phases will
 * add scene switching for menu vs. fight vs. results; Phase 1 just needs
 * one scene with placeholder ground + three-point lighting + two stand-in
 * fighter boxes.
 */
export class SceneManager {
  constructor() {
    this.scene = new THREE.Scene();
    this.scene.background = new THREE.Color(0x1b120a);
    this.scene.fog = new THREE.Fog(0x1b120a, 14, 28);

    this._addLights();
    this._addPlaceholderGround();
  }

  /** Three-point lighting tuned warm to match the truck-art palette. */
  _addLights() {
    const ambient = new THREE.AmbientLight(0xffd9a8, 0.35);
    this.scene.add(ambient);

    // Key light - warm, casts shadows.
    const key = new THREE.DirectionalLight(0xfff0c2, 1.6);
    key.position.set(4, 8, 6);
    key.castShadow = true;
    key.shadow.mapSize.set(1024, 1024);
    key.shadow.camera.near = 0.5;
    key.shadow.camera.far = 25;
    key.shadow.camera.left = -6;
    key.shadow.camera.right = 6;
    key.shadow.camera.top = 6;
    key.shadow.camera.bottom = -2;
    this.scene.add(key);

    // Fill light - cool, opposite side.
    const fill = new THREE.DirectionalLight(0x88aaff, 0.45);
    fill.position.set(-5, 4, 4);
    this.scene.add(fill);

    // Rim light - behind, to pop silhouettes off the background.
    const rim = new THREE.DirectionalLight(0xffaa66, 0.6);
    rim.position.set(0, 3, -6);
    this.scene.add(rim);
  }

  /**
   * Placeholder ground + two stand-in fighter boxes. Phase 5 replaces the
   * ground with the real stage; Phase 3 replaces the boxes with Fighters.
   */
  _addPlaceholderGround() {
    const geometry = new THREE.PlaneGeometry(20, 8);
    const material = new THREE.MeshStandardMaterial({
      color: 0x6b4a25,
      roughness: 0.95,
      metalness: 0.0,
    });
    const ground = new THREE.Mesh(geometry, material);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = 0;
    ground.receiveShadow = true;
    ground.name = 'placeholder_ground';
    this.scene.add(ground);

    // Subtle grid marker so the fight plane is visible during boot.
    // Hidden by hidePlaceholderGround() once a real Stage loads.
    const grid = new THREE.GridHelper(10, 10, 0xc79b3a, 0x3a2914);
    grid.position.y = 0.01;
    grid.name = 'placeholder_grid';
    this.scene.add(grid);
    this._placeholderGrid = grid;
    this._placeholderGround = ground;

    // Stand-in fighter markers.
    const p1Mat = new THREE.MeshStandardMaterial({ color: 0xc79b3a, roughness: 0.6 });
    const p2Mat = new THREE.MeshStandardMaterial({ color: 0x7a1f1f, roughness: 0.6 });
    const boxGeom = new THREE.BoxGeometry(0.6, 1.7, 0.4);

    const p1 = new THREE.Mesh(boxGeom, p1Mat);
    p1.position.set(-1.6, 0.85, 0);
    p1.castShadow = true;
    p1.name = 'p1_placeholder';
    this.scene.add(p1);

    const p2 = new THREE.Mesh(boxGeom, p2Mat);
    p2.position.set(1.6, 0.85, 0);
    p2.castShadow = true;
    p2.name = 'p2_placeholder';
    this.scene.add(p2);

    // Expose for the Phase 1 input bridge in main.js. Phase 3 will replace
    // these with real Fighter instances and this direct handle goes away.
    this.placeholders = { p1, p2 };
  }

  /**
   * Hide the boot-time placeholder ground and grid. Called once a real
   * Stage is added so we don't double-render the floor.
   */
  hidePlaceholderGround() {
    if (this._placeholderGround) this._placeholderGround.visible = false;
    if (this._placeholderGrid) this._placeholderGrid.visible = false;
  }

  /** Per-frame hook for scene-wide animation (parallax sway, fog pulse). */
  update(_dt) {
    /* no-op in Phase 1 */
  }
}
