export class MonetizationPanel {
  constructor({ host, economy, ads }) {
    this.host = host;
    this.economy = economy;
    this.ads = ads;
    this._visible = false;
    this._busy = false;
    this._build();
    this.economy.subscribe(() => this._render());
    this._render();
  }

  show() {
    this._visible = true;
    this._wrap.style.display = 'flex';
    this._render();
  }

  hide() {
    this._visible = false;
    this._wrap.style.display = 'none';
    this._setStatus('');
  }

  _build() {
    const wrap = document.createElement('div');
    wrap.dataset.dsfMonetizationPanel = 'rewarded-coins';
    wrap.style.cssText = `
      position: absolute;
      left: 50%;
      bottom: calc(max(118px, env(safe-area-inset-bottom)) + 14px);
      transform: translateX(-50%);
      z-index: 18;
      display: none;
      align-items: center;
      gap: 12px;
      padding: 10px 12px;
      border: 2px solid rgba(255,215,112,0.82);
      border-radius: 8px;
      background: linear-gradient(180deg, rgba(48,26,10,0.92), rgba(18,10,5,0.94));
      box-shadow: 0 0 22px rgba(255,176,56,0.24), inset 0 1px 0 rgba(255,255,255,0.08);
      color: #f5e9c9;
      font-family: 'Segoe UI', system-ui, sans-serif;
      pointer-events: auto;
      max-width: min(620px, calc(100vw - 28px));
    `;

    const coinText = document.createElement('div');
    coinText.style.cssText = `
      min-width: 92px;
      font-size: 12px;
      line-height: 1.2;
      letter-spacing: 0.08em;
      color: rgba(245,233,201,0.82);
      text-transform: uppercase;
    `;
    this._coinText = coinText;

    const btn = document.createElement('button');
    btn.type = 'button';
    btn.dataset.dsfRewardButton = 'coins';
    btn.style.cssText = `
      min-height: 44px;
      padding: 0 18px;
      border: 2px solid #ffd770;
      border-radius: 6px;
      background: linear-gradient(180deg, #f5b642, #9f5708);
      color: #1b120a;
      font-size: 13px;
      font-weight: 900;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      text-shadow: 0 1px 0 rgba(255,255,255,0.38);
      cursor: pointer;
      white-space: nowrap;
    `;
    btn.addEventListener('click', () => this._claimReward());
    this._button = btn;

    const status = document.createElement('div');
    status.setAttribute('aria-live', 'polite');
    status.style.cssText = `
      min-width: 150px;
      font-size: 11px;
      line-height: 1.25;
      color: rgba(245,233,201,0.72);
    `;
    this._status = status;

    wrap.appendChild(coinText);
    wrap.appendChild(btn);
    wrap.appendChild(status);
    this.host?.appendChild(wrap);
    this._wrap = wrap;
  }

  async _claimReward() {
    if (this._busy) return;
    this._busy = true;
    this._button.disabled = true;
    this._button.style.opacity = '0.7';
    this._setStatus('Loading ad...');
    try {
      const reward = await this.ads.showRewardedCoins();
      const amount = Number(reward?.amount) || this.ads.rewardAmount;
      this.economy.addCoins(amount);
      this._setStatus(`Added ${amount} ${this.ads.rewardItem}.`);
    } catch (err) {
      console.warn('[ads] rewarded ad failed', err);
      this._setStatus('Ad was not completed. Try again later.');
    } finally {
      this._busy = false;
      this._button.disabled = false;
      this._button.style.opacity = '1';
      this._render();
    }
  }

  _render() {
    if (!this._wrap) return;
    this._coinText.textContent = `Coins: ${this.economy.coins}`;
    this._button.textContent = `Watch Ad +${this.ads.rewardAmount}`;
  }

  _setStatus(text) {
    this._status.textContent = text;
  }
}
