/**
 * Desi Street Fighter - entry point
 * ---------------------------------
 * Phase 7: full match flow + truck-art HUD with character portraits.
 * Phase 9: TouchControls overlay + Gamepad API polling.
 * Phase 12: Settings store + PauseMenu (ESC or on-screen ⏸ to pause).
 *
 *   Movement:  P1 A/D walk, W jump
 *   Attacks:   J K L (light/med/hvy punch)
 *              U I O (light/med/hvy kick)
 *   Block:     ;
 *
 * MatchController drives round_intro -> fighting -> round_ko -> round_reset
 * and best-of-3 -> match_end. Inputs are gated to the 'fighting' phase only,
 * so neither fighter can swing during the "FIGHT!" banner.
 */
import { Renderer } from './engine/Renderer.js';
import { SceneManager } from './engine/SceneManager.js';
import { AssetLoader } from './engine/AssetLoader.js';
import { Input } from './engine/Input.js';
import { TouchControls } from './engine/TouchControls.js';
import { BRANDING } from './data/branding.js';
import { AudioManager } from './engine/AudioManager.js';
import { Physics } from './engine/Physics.js';
import { Juice } from './engine/Juice.js';
import { ProceduralAudio } from './engine/ProceduralAudio.js';
import { Fighter } from './game/Fighter.js';
import { Stage } from './game/Stage.js';
import { AI } from './game/AI.js';
import { MatchController } from './game/MatchController.js';
import { ProjectileManager } from './game/ProjectileManager.js';
import { MainMenu } from './ui/MainMenu.js';
import { CharacterSelect } from './ui/CharacterSelect.js';
import { StageSelect } from './ui/StageSelect.js';
import { PauseMenu } from './ui/PauseMenu.js';
import { Settings } from './engine/Settings.js';
import { Economy } from './engine/Economy.js';
import { AdMobService } from './engine/AdMobService.js';
import { Capacitor } from '@capacitor/core';
import { ROSTER, V1_ROSTER } from './data/characters.js';
import { STAGES, DEFAULT_STAGE_ID } from './data/stages.js';
import { MonetizationPanel } from './ui/MonetizationPanel.js';
import * as THREE from 'three';

// ---- Bootstrap ------------------------------------------------------------

const canvas = document.getElementById('game-canvas');
if (!(canvas instanceof HTMLCanvasElement)) {
  throw new Error('#game-canvas not found in DOM');
}

const renderer = new Renderer(canvas);
const sceneManager = new SceneManager();
const assetLoader = new AssetLoader();
const input = new Input(window);
const audio = new AudioManager(); // Howler-based; not used by Phase 8
const uiRoot = document.getElementById('ui-root');

// Phase 9 — touch overlay (auto-shows on touch devices) + gamepad polling.
const touchControls = new TouchControls({
  host: uiRoot,
  input,
  playerId: 0,
});

// Phase 12 — settings store + pause menu.
const settings = new Settings();
const economy = new Economy();
const adMobService = new AdMobService();
const isNativeAndroid = Capacitor.isNativePlatform() && Capacitor.getPlatform() === 'android';

// Apply touch-controls visibility preference at boot.
function applyTouchControlsFromSettings() {
  if (isSelectionMenuActive) {
    touchControls.hide();
    return;
  }
  const touchPref = settings.get('touchControlsVisible');
  if (touchPref === 'on') touchControls.show();
  else if (touchPref === 'off') touchControls.hide();
  else if (touchControls.isTouchDevice()) touchControls.show();
  else touchControls.hide();
}
let isSelectionMenuActive = true;
settings.subscribe(applyTouchControlsFromSettings);
applyTouchControlsFromSettings();
// 'auto' is the constructor default (visible iff touch device).

// Apply branding to the document so the tab title shows the right name.
document.title = BRANDING.displayName;

// PauseMenu — ESC + on-screen ⏸. Restart / Quit currently reload the page;
// later phases can hook real flow handlers in here.
const pauseMenu = new PauseMenu({
  host: uiRoot,
  settings,
  branding: BRANDING,
  onRestart: () => { requestRematch(); },
  onQuit:    () => { showMainMenu(); },
});

const mainMenu = new MainMenu(uiRoot, { branding: BRANDING });

const monetizationPanel = new MonetizationPanel({
  host: uiRoot,
  economy,
  ads: adMobService,
});
adMobService.initialize().catch((err) => {
  console.warn('[ads] AdMob unavailable at boot', err);
});

// Phase 8 — juice + procedural audio.
const juice = new Juice({
  camera: renderer.camera,
  scene: sceneManager.scene,
});
const synth = new ProceduralAudio();

// Audio volumes track settings. Defined AFTER synth so the subscribe handler
// can write through. Applied once at boot to honour saved preferences.
function applyAudioFromSettings() {
  synth.setMasterVolume(settings.get('masterVolume'));
  synth.setMusicVolume(settings.get('musicVolume'));
  synth.setSfxVolume(settings.get('sfxVolume'));
  if (settings.get('musicVolume') <= 0) {
    synth.stopDholLoop();
  }
}
settings.subscribe(applyAudioFromSettings);
applyAudioFromSettings();

canvas.focus();
canvas.addEventListener('click', () => canvas.focus());

// Browsers block audio until first user gesture — resume the context and
// keep the procedural dhol loop disabled; resume short SFX only.
let _audioStarted = false;
function unlockAudio() {
  if (_audioStarted) return;
  _audioStarted = true;
  synth.resume();
}
window.addEventListener('pointerdown', unlockAudio, { once: false });
window.addEventListener('keydown', unlockAudio, { once: false });

const overlay = document.getElementById('boot-overlay');
function setOverlay(html, variant = '') {
  if (!overlay) return;
  const isMatchHelp = variant === 'match-help' || html.includes('Hadoken') || html.includes('Shoryuken');
  overlay.classList.toggle('match-help', isMatchHelp);
  overlay.innerHTML = html;
}
setOverlay(`${BRANDING.displayName} · Choose your fighter`);

console.info(
  `%c ${BRANDING.displayName} — booting `,
  'background:#c79b3a;color:#1b120a;font-weight:bold;padding:4px 8px;border-radius:4px;',
);

// ---- Truck-art HUD --------------------------------------------------------

/** @type {{p1:HTMLElement|null,p2:HTMLElement|null,timer:HTMLElement|null,pips:HTMLElement[][],banner:HTMLElement|null,portraits:HTMLImageElement[]}} */
const hud = {
  p1: null, p2: null, timer: null, banner: null,
  pips: [[], []],
  portraits: [],
};

function buildHud(p1Char, p2Char) {
  if (!uiRoot) return;
  document.getElementById('hud-root')?.remove();

  const hudRoot = document.createElement('div');
  hudRoot.id = 'hud-root';
  hudRoot.style.cssText = `
    position:absolute; inset:0;
    pointer-events:none;
    z-index: 12;
  `;
  uiRoot.appendChild(hudRoot);

  const wrap = document.createElement('div');
  wrap.style.cssText = `
    position:absolute; top:0; left:0; right:0;
    padding: 14px 28px 0;
    pointer-events:none;
    font-family: 'Segoe UI', system-ui, sans-serif;
    color:#f5e9c9;
    display:grid;
    grid-template-columns: 1fr auto 1fr;
    column-gap: 24px;
    align-items: start;
  `;

  function makeSide(charData, mirror) {
    const side = document.createElement('div');
    side.style.cssText = `display:flex; gap:12px; ${mirror ? 'flex-direction:row-reverse;' : ''}`;

    const portraitFrame = document.createElement('div');
    portraitFrame.style.cssText = `
      width: 78px; height: 78px;
      border: 3px solid #c79b3a;
      background: linear-gradient(135deg, #4a1818, #2a0d0d);
      border-radius: 6px;
      overflow: hidden; flex: 0 0 auto;
      box-shadow: 0 0 14px rgba(199,155,58,0.4);
      position: relative;
    `;
    const portrait = document.createElement('img');
    portrait.src = charData.portrait;
    portrait.alt = charData.name;
    portrait.style.cssText = `
      width: 100%; height: 100%; object-fit: cover;
      object-position: center top;
      ${mirror ? 'transform: scaleX(-1);' : ''}
    `;
    portrait.onerror = () => { portrait.style.display = 'none'; };
    portraitFrame.appendChild(portrait);

    const meta = document.createElement('div');
    meta.style.cssText = `flex:1; min-width: 0;`;

    const nameRow = document.createElement('div');
    nameRow.style.cssText = `
      display:flex; align-items:center; gap:8px;
      ${mirror ? 'flex-direction:row-reverse;' : ''}
    `;

    const name = document.createElement('div');
    name.textContent = charData.name;
    name.style.cssText = `
      font-size:14px; font-weight:700;
      letter-spacing:0.10em; text-transform:uppercase;
      color:#ffd770;
      text-shadow: 1px 1px 0 #1b120a, 0 0 8px rgba(255,215,112,0.4);
      white-space: nowrap;
    `;

    const pipRow = document.createElement('div');
    pipRow.style.cssText = `display:flex; gap:5px;`;
    const pipElements = [];
    for (let i = 0; i < 2; i++) {
      const p = document.createElement('div');
      p.style.cssText = `
        width:10px; height:10px; border-radius:50%;
        background: rgba(199,155,58,0.18);
        border: 2px solid #6a4a16;
        box-shadow: inset 0 0 4px rgba(0,0,0,0.5);
        transition: background 200ms ease, box-shadow 200ms ease;
      `;
      pipRow.appendChild(p);
      pipElements.push(p);
    }

    nameRow.appendChild(name);
    nameRow.appendChild(pipRow);
    meta.appendChild(nameRow);

    const barFrame = document.createElement('div');
    barFrame.style.cssText = `
      margin-top:6px; height:24px; position:relative;
      border: 3px solid #c79b3a;
      background:
        linear-gradient(90deg, #1b120a 0%, #3a2218 100%);
      border-radius: 4px; overflow:hidden;
      box-shadow:
        0 0 14px rgba(199,155,58,0.4),
        inset 0 1px 0 rgba(255,235,180,0.25),
        inset 0 -2px 6px rgba(0,0,0,0.5);
    `;
    const bar = document.createElement('div');
    bar.style.cssText = `
      height:100%; width:100%;
      background: linear-gradient(${mirror ? '270deg' : '90deg'},
        #b81818 0%, #d83838 32%, #e88830 64%, #ffd770 100%);
      box-shadow: inset 0 0 8px rgba(255,255,255,0.25);
      transition: width 120ms ease-out;
      ${mirror ? 'float:right;' : ''}
    `;
    barFrame.appendChild(bar);
    meta.appendChild(barFrame);

    // Hadoken pip row — 3 fireball dots under the lifebar.
    // Filled when the projectile is available, dim when spent. Refills on
    // round reset (MatchController._resetFighters -> Fighter.refillHadoken).
    const hadokenRow = document.createElement('div');
    hadokenRow.style.cssText = `
      margin-top:5px; display:flex; gap:6px;
      ${mirror ? 'flex-direction:row-reverse;' : ''}
    `;
    const hadokenPips = [];
    for (let i = 0; i < 3; i++) {
      const p = document.createElement('div');
      p.style.cssText = `
        width: 12px; height: 12px; border-radius: 50%;
        background: radial-gradient(circle at 35% 30%, #ffd770 0%, #ff8a3a 55%, #c44a18 100%);
        border: 2px solid #ffd770;
        box-shadow:
          0 0 8px rgba(255,138,58,0.85),
          inset 0 0 4px rgba(255,255,255,0.55);
        transition: background 200ms ease, opacity 200ms ease, box-shadow 200ms ease, transform 120ms ease;
      `;
      hadokenRow.appendChild(p);
      hadokenPips.push(p);
    }
    meta.appendChild(hadokenRow);

    side.appendChild(portraitFrame);
    side.appendChild(meta);

    return { side, bar, pipElements, hadokenPips, portrait };
  }

  const p1 = makeSide(p1Char, false);
  const p2 = makeSide(p2Char, true);

  const center = document.createElement('div');
  center.style.cssText = `
    display:flex; flex-direction:column; align-items:center; gap:4px;
    min-width: 96px;
  `;
  const timerFrame = document.createElement('div');
  timerFrame.style.cssText = `
    width: 96px; height: 78px;
    border: 3px solid #c79b3a;
    background: linear-gradient(180deg, #4a1818, #2a0d0d);
    border-radius: 6px;
    display:flex; align-items:center; justify-content:center;
    box-shadow: 0 0 16px rgba(199,155,58,0.45);
  `;
  const timer = document.createElement('div');
  timer.textContent = '99';
  timer.style.cssText = `
    font-size: 52px; font-weight: 900;
    color: #ffd770;
    text-shadow: 2px 2px 0 #1b120a, 0 0 16px rgba(255,215,112,0.65);
    line-height: 1;
    font-variant-numeric: tabular-nums;
  `;
  timerFrame.appendChild(timer);
  const roundLabel = document.createElement('div');
  roundLabel.textContent = 'ROUND 1';
  roundLabel.style.cssText = `
    font-size: 11px; letter-spacing: 0.18em; color: #ffd770;
    text-shadow: 1px 1px 0 #1b120a;
  `;
  center.appendChild(timerFrame);
  center.appendChild(roundLabel);

  wrap.appendChild(p1.side);
  wrap.appendChild(center);
  wrap.appendChild(p2.side);
  hudRoot.appendChild(wrap);

  const banner = document.createElement('div');
  banner.style.cssText = `
    position:absolute; top: 38%; left:50%; transform:translateX(-50%);
    font-size: 56px; font-weight: 900; letter-spacing: 0.18em;
    color:#ffd770;
    text-shadow:
      3px 3px 0 #1b120a,
      0 0 28px rgba(255,215,112,0.75),
      0 0 60px rgba(216,56,56,0.5);
    pointer-events:none; opacity:0;
    transition: opacity 220ms ease-out;
    text-align:center; white-space: nowrap;
  `;
  hudRoot.appendChild(banner);

  hud.p1 = p1.bar;
  hud.p2 = p2.bar;
  hud.timer = timer;
  hud.banner = banner;
  hud.roundLabel = roundLabel;
  hud.pips = [p1.pipElements, p2.pipElements];
  hud.hadokenPips = [p1.hadokenPips, p2.hadokenPips];
  hud.portraits = [p1.portrait, p2.portrait];
}

function updateHud(fighters, match) {
  if (!hud.p1 || !hud.p2 || fighters.length < 2) return;
  const [a, b] = fighters;
  hud.p1.style.width = `${(a.hp / a.maxHp) * 100}%`;
  hud.p2.style.width = `${(b.hp / b.maxHp) * 100}%`;
  if (match) {
    if (hud.timer) hud.timer.textContent = String(Math.ceil(match.roundTime));
    if (hud.roundLabel) hud.roundLabel.textContent = `ROUND ${match.round}`;
    for (let side = 0; side < 2; side++) {
      const won = match.roundsWon[side];
      const pipsForSide = hud.pips[side];
      for (let i = 0; i < pipsForSide.length; i++) {
        if (i < won) {
          pipsForSide[i].style.background = '#ffd770';
          pipsForSide[i].style.boxShadow =
            '0 0 8px rgba(255,215,112,0.9), inset 0 0 4px rgba(255,255,255,0.4)';
        } else {
          pipsForSide[i].style.background = 'rgba(199,155,58,0.18)';
          pipsForSide[i].style.boxShadow = 'inset 0 0 4px rgba(0,0,0,0.5)';
        }
      }
    }

    // Hadoken counter pips — fireball dots that dim as projectiles are spent.
    if (hud.hadokenPips) {
      for (let side = 0; side < 2; side++) {
        const fighter = fighters[side];
        const remaining = fighter?.hadokenCount ?? 0;
        const pipsForSide = hud.hadokenPips[side];
        for (let i = 0; i < pipsForSide.length; i++) {
          const lit = i < remaining;
          pipsForSide[i].style.opacity = lit ? '1' : '0.22';
          pipsForSide[i].style.boxShadow = lit
            ? '0 0 10px rgba(255,138,58,0.95), inset 0 0 4px rgba(255,255,255,0.6)'
            : 'inset 0 0 4px rgba(0,0,0,0.55)';
          pipsForSide[i].style.transform = lit ? 'scale(1)' : 'scale(0.78)';
        }
      }
    }
  }
}

function setBanner(text, durationMs = 1500) {
  if (!hud.banner) return;
  hud.banner.textContent = text;
  hud.banner.style.opacity = '1';
  clearTimeout(setBanner._t);
  setBanner._t = setTimeout(() => {
    hud.banner.style.opacity = '0';
  }, durationMs);
}

// ---- Async asset boot -----------------------------------------------------

/** @type {Fighter[]} */
const fighters = [];
/** @type {Stage | null} */
let stage = null;
/** @type {AI | null} */
let opponentAI = null;
/** @type {MatchController | null} */
let matchController = null;
/** @type {ProjectileManager | null} */
let projectiles = null;
let _lastMonetizedMatchState = null;
let currentMatchConfig = null;
let postMatchPanel = null;
let flowMode = 'menu';
let championship = null;

let _stageLoadPromise = null;
let _loadedStageId = null;
function getStagePromise(stageId = DEFAULT_STAGE_ID) {
  // If the requested stage matches what's already loaded, reuse the promise.
  if (_stageLoadPromise && _loadedStageId === stageId) return _stageLoadPromise;

  // Different stage requested: dispose old, build new.
  if (stage && stage.group) {
    sceneManager.scene.remove(stage.group);
  }

  const stageData = STAGES[stageId] ?? STAGES[DEFAULT_STAGE_ID];
  stage = new Stage(stageData, assetLoader);
  _loadedStageId = stageId;
  _stageLoadPromise = stage.load().then(() => {
    sceneManager.hidePlaceholderGround();
    sceneManager.scene.add(stage.group);
    stage.applyLighting(sceneManager.scene);
  });
  return _stageLoadPromise;
}

function hidePostMatchPanel() {
  if (postMatchPanel?.parentNode) postMatchPanel.parentNode.removeChild(postMatchPanel);
  postMatchPanel = null;
}

function clearCurrentMatch({ keepStage = true } = {}) {
  hidePostMatchPanel();
  document.getElementById('hud-root')?.remove();
  monetizationPanel.hide();
  projectiles?.clear?.();
  projectiles = null;
  opponentAI = null;
  matchController = null;
  _lastMonetizedMatchState = null;
  for (const fighter of fighters.splice(0)) {
    if (fighter?.rig?.parent) fighter.rig.parent.remove(fighter.rig);
  }
  if (!keepStage && stage?.group?.parent) {
    sceneManager.scene.remove(stage.group);
    stage = null;
    _stageLoadPromise = null;
    _loadedStageId = null;
  }
}

function getP2ModeForMatch(modeOverride) {
  return modeOverride || settings.get('p2Mode') || 'cpu_medium';
}

async function startMatch(p1Data, p2Data, stageId = DEFAULT_STAGE_ID, opts = {}) {
  try {
    clearCurrentMatch({ keepStage: true });
    currentMatchConfig = { p1Data, p2Data, stageId, opts };
    isSelectionMenuActive = false;
    applyTouchControlsFromSettings();
    setOverlay(`${BRANDING.displayName} · Loading fighters…`);

    const { p1: boxP1, p2: boxP2 } = sceneManager.placeholders;
    boxP1.visible = false;
    boxP2.visible = false;

    const [p1Asset, p2Asset] = await Promise.all([
      assetLoader.loadCharacter({
        url: p1Data.model,
        animationMap: p1Data.animationMap,
        externalAnimations: p1Data.externalAnimations,
      }),
      assetLoader.loadCharacter({
        url: p2Data.model,
        animationMap: p2Data.animationMap,
        externalAnimations: p2Data.externalAnimations,
      }),
      getStagePromise(stageId),
    ]);

    buildHud(p1Data, p2Data);

    const p1 = new Fighter({
      characterData: p1Data,
      asset: p1Asset,
      playerId: 0,
      facing: +1,
      spawn: { x: -1.6, y: 0 },
    });
    const p2 = new Fighter({
      characterData: p2Data,
      asset: p2Asset,
      playerId: 1,
      facing: -1,
      spawn: { x: 1.6, y: 0 },
    });
    sceneManager.scene.add(p1.rig);
    sceneManager.scene.add(p2.rig);
    fighters.push(p1, p2);

    // Player 2 controller — driven by settings.p2Mode.
    //   'human'      → no AI; P2 reads keyboard (arrows + numpad) + Gamepad 2.
    //   'cpu_easy'   → AI on easy
    //   'cpu_medium' → AI on medium (default)
    //   'cpu_hard'   → AI on hard
    const savedP2Mode = getP2ModeForMatch(opts.p2Mode);
    const p2Mode = isNativeAndroid && savedP2Mode === 'human'
      ? 'cpu_medium'
      : savedP2Mode;
    if (p2Mode !== savedP2Mode) settings.set('p2Mode', p2Mode);
    if (p2Mode === 'human') {
      opponentAI = null;
      console.info('[boot] P2 = Human (keyboard / gamepad 2)');
    } else {
      const difficulty = p2Mode.startsWith('cpu_') ? p2Mode.slice(4) : 'medium';
      opponentAI = new AI({ self: p2, opponent: p1, difficulty });
      console.info(`[boot] P2 = CPU (${difficulty})`);
    }

    matchController = new MatchController({
      fighters,
      hud: { setBanner },
      onMatchEnd: (result) => showPostMatchPanel(result),
    });
    if (import.meta.env.DEV && window.__dsf) {
      window.__dsf.matchController = matchController;
    }

    // Hadoken — wire projectile manager + scene ref into each fighter.
    projectiles = new ProjectileManager({ scene: sceneManager.scene });
    if (import.meta.env.DEV && window.__dsf) {
      window.__dsf.projectiles = projectiles;
    }
    p1._projectiles = projectiles;
    p2._projectiles = projectiles;
    p1._sceneRef = sceneManager.scene;
    p2._sceneRef = sceneManager.scene;

    setOverlay(
      `<span class="match-title">${p1Data.name} vs ${p2Data.name}</span>` +
        '<span class="match-controls">Move A/D · Jump W · Crouch S · Punch J/K/L · Kick U/I/O · Block ; · Hadoken ↓→J or HADO · DP →↓L/B</span>',
      'match-help',
    );
    console.info(`[boot] match started — ${p1Data.name} vs ${p2Data.name}`);
  } catch (err) {
    console.error('[boot] fighter load failed:', err);
    setOverlay(
      `${BRANDING.displayName} · LOAD ERROR<br>` +
        '<span style="font-size:11px;color:#ff8888;">' +
        String(err?.message ?? err) +
        '</span>',
    );
  }
}

// Boot preload of the default stage so the first match snaps in fast.
// If the player picks a different stage in StageSelect, that stage will be
// built on demand and the default discarded.
getStagePromise().catch((e) => console.warn('[boot] stage preload failed', e));

function showMainMenu() {
  flowMode = 'menu';
  championship = null;
  clearCurrentMatch({ keepStage: true });
  isSelectionMenuActive = true;
  applyTouchControlsFromSettings();
  setOverlay(`${BRANDING.displayName} - Main menu`);
  mainMenu.show({
    onQuickFight: showQuickFightSelect,
    onChampionship: showChampionshipSelect,
    onHowToPlay: showHowToPlay,
  });
}

function showQuickFightSelect() {
  flowMode = 'quick';
  championship = null;
  mainMenu.hide();
  clearCurrentMatch({ keepStage: true });
  isSelectionMenuActive = true;
  applyTouchControlsFromSettings();
  setOverlay(`${BRANDING.displayName} - Choose fighters`);
  const select = new CharacterSelect(uiRoot, ROSTER, (p1Data, p2Data) => {
    showStageSelect({
      onBack: showQuickFightSelect,
      onStage: (stageId) => startMatch(p1Data, p2Data, stageId, { mode: 'quick' }),
    });
  }, {
    settings,
    hideHumanP2: isNativeAndroid,
    onBack: showMainMenu,
  });
  select.show();
}

function showChampionshipSelect() {
  flowMode = 'championship';
  mainMenu.hide();
  clearCurrentMatch({ keepStage: true });
  isSelectionMenuActive = true;
  applyTouchControlsFromSettings();
  setOverlay(`${BRANDING.displayName} - Choose champion`);
  const select = new CharacterSelect(uiRoot, ROSTER, (player) => {
    beginChampionship(player);
  }, {
    settings,
    mode: 'single',
    hideHumanP2: true,
    onBack: showMainMenu,
  });
  select.show();
}

function showStageSelect({ onStage, onBack }) {
  isSelectionMenuActive = true;
  applyTouchControlsFromSettings();
  setOverlay(`${BRANDING.displayName} - Choose stage`);
  const stageSelect = new StageSelect(
    uiRoot,
    STAGES,
    (stageId) => onStage(stageId),
    { defaultStageId: DEFAULT_STAGE_ID, onBack },
  );
  stageSelect.show();
}

function beginChampionship(player) {
  const opponents = V1_ROSTER.filter((char) => char.id !== player.id);
  const stageIds = Object.keys(STAGES);
  championship = { player, opponents, stageIds, index: 0, wins: 0 };
  startChampionshipFight();
}

function getChampionshipDifficulty(index) {
  if (index <= 1) return 'cpu_easy';
  if (index <= 3) return 'cpu_medium';
  return 'cpu_hard';
}

function startChampionshipFight() {
  if (!championship) return showMainMenu();
  const opponent = championship.opponents[championship.index];
  if (!opponent) return showChampionshipComplete();
  const stageId = championship.stageIds[championship.index % championship.stageIds.length] || DEFAULT_STAGE_ID;
  startMatch(championship.player, opponent, stageId, {
    mode: 'championship',
    p2Mode: getChampionshipDifficulty(championship.index),
    ladderIndex: championship.index,
    ladderTotal: championship.opponents.length,
  });
}

