function showChampionshipComplete() {
  showPostMatchPanel({
    winnerIdx: 0,
    winnerName: championship?.player?.name ?? 'Champion',
    roundsWon: [championship?.wins ?? 0, 0],
    championshipComplete: true,
  });
}

function requestRematch() {
  if (!currentMatchConfig) return showMainMenu();
  const { p1Data, p2Data, stageId, opts } = currentMatchConfig;
  startMatch(p1Data, p2Data, stageId, opts);
}

function showPostMatchPanel(result) {
  hidePostMatchPanel();
  const isChampionship = currentMatchConfig?.opts?.mode === 'championship';
  const playerWon = result.winnerIdx === 0;
  const complete = result.championshipComplete ||
    (isChampionship && playerWon && championship && championship.index >= championship.opponents.length - 1);

  if (isChampionship && playerWon && championship && !complete) championship.wins++;

  const panel = document.createElement('div');
  panel.style.cssText = `
    position:absolute; inset:0; z-index:65; pointer-events:auto;
    display:grid; place-items:center;
    padding:24px;
    background:linear-gradient(180deg, rgba(12,7,4,0.36), rgba(12,7,4,0.84));
    font-family:'Segoe UI', system-ui, sans-serif;
    color:#f5e9c9;
  `;
  postMatchPanel = panel;
  const title = complete ? 'CHAMPIONSHIP COMPLETE' : `${result.winnerName} WINS`;
  const subtitle = isChampionship
    ? complete
      ? `${championship?.player?.name ?? result.winnerName} cleared the ladder.`
      : playerWon
        ? `Fight ${(championship?.index ?? 0) + 1} cleared. Next rival awaits.`
        : 'Championship run ended. Train, adjust difficulty, and try again.'
    : `Final score ${result.roundsWon?.[0] ?? 0}-${result.roundsWon?.[1] ?? 0}.`;
  panel.innerHTML = `
    <section style="width:min(680px, calc(100vw - 36px));border:2px solid #c79b3a;border-radius:8px;background:rgba(20,12,6,0.92);box-shadow:0 18px 48px rgba(0,0,0,0.58);padding:24px;text-align:center;">
      <h2 style="margin:0;color:#ffd770;font-size:clamp(24px, 5vw, 42px);letter-spacing:0.12em;text-transform:uppercase;">${title}</h2>
      <p style="margin:12px auto 20px;max-width:560px;line-height:1.45;color:rgba(245,233,201,0.82);">${subtitle}</p>
      <div id="post-actions" style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap;"></div>
    </section>
  `;
  const actions = panel.querySelector('#post-actions');
  const addButton = (label, onClick, primary = false) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.textContent = label;
    btn.style.cssText = `
      min-width:150px;
      padding:11px 16px;
      border:2px solid ${primary ? '#ffd770' : '#8d6421'};
      border-radius:6px;
      background:${primary ? '#6a2714' : '#2a160d'};
      color:#ffd770;
      font-weight:900;
      letter-spacing:0.10em;
      cursor:pointer;
      font-family:inherit;
    `;
    btn.addEventListener('click', onClick);
    actions.appendChild(btn);
  };

  if (isChampionship && playerWon && !complete) {
    addButton('NEXT FIGHT', () => {
      championship.index++;
      startChampionshipFight();
    }, true);
  } else {
    addButton(isChampionship ? 'TRY AGAIN' : 'REMATCH', () => {
      if (isChampionship) showChampionshipSelect();
      else requestRematch();
    }, true);
  }
  addButton('QUICK FIGHT', showQuickFightSelect);
  addButton('MAIN MENU', showMainMenu);
  uiRoot.appendChild(panel);
}

showMainMenu();

