// ---- Combat resolver ------------------------------------------------------

function resolveDirectionalHit(attacker, defender) {
  if (!attacker._currentAttack) return;
  const result = Physics.resolveHits(attacker, defender);
  if (!result) return;
  const move = attacker._currentAttack.move;
  attacker.stateMachine.current?.markHit?.(attacker);
  const wasAliveBefore = defender.hp > 0;
  const { blocked, damage } = defender.takeHit({
    move,
    fromX: attacker.position.x,
  });
  console.debug(
    `[hit] ${attacker.character.name} -> ${defender.character.name}: ` +
      `${move.name ?? move.id} ${blocked ? '(blocked, chip ' : '('}${damage} dmg) ` +
      `HP ${defender.hp}/${defender.maxHp}`,
  );

  const dmg = move.damage ?? 0;
  const tier = dmg >= 100 ? 'heavy' : dmg >= 60 ? 'medium' : 'light';
  const hitPos = new THREE.Vector3(
    (attacker.position.x + defender.position.x) / 2,
    1.2,
    0.05,
  );
  if (blocked) {
    juice.spawnHitSpark(hitPos, 0xb0c4d8, 6, 0.55);
    juice.shake(0.025, 0.12);
    synth.block();
  } else {
    const sparkColor =
      tier === 'heavy' ? 0xff8a3a : tier === 'medium' ? 0xffd770 : 0xfff0c2;
    const sparkCount = tier === 'heavy' ? 16 : tier === 'medium' ? 12 : 9;
    const sparkSpeed = tier === 'heavy' ? 1.4 : tier === 'medium' ? 1.1 : 0.9;
    juice.spawnHitSpark(hitPos, sparkColor, sparkCount, sparkSpeed);
    const shakeAmp = tier === 'heavy' ? 0.16 : tier === 'medium' ? 0.08 : 0.035;
    const shakeDur = tier === 'heavy' ? 0.32 : tier === 'medium' ? 0.20 : 0.12;
    juice.shake(shakeAmp, shakeDur);
    synth.hit(tier);

    if (wasAliveBefore && defender.hp <= 0) {
      juice.slowMo(0.75, 0.55);
      juice.shake(0.3, 0.55);
      juice.spawnHitSpark(hitPos, 0xffd770, 28, 1.6);
      synth.ko();
    }
  }
}

function autoFaceOpponents() {
  if (fighters.length < 2) return;
  const [a, b] = fighters;
  const neutralA = a.stateMachine.currentName === 'idle' || a.stateMachine.currentName === 'walk';
  const neutralB = b.stateMachine.currentName === 'idle' || b.stateMachine.currentName === 'walk';
  if (neutralA) a.faceOpponent(b);
  if (neutralB) b.faceOpponent(a);
}

function updateMonetizationState() {
  const state = matchController?.state ?? null;
  if (state === _lastMonetizedMatchState) return;
  _lastMonetizedMatchState = state;

  if (state === 'match_end') {
    monetizationPanel.show();
    adMobService.showPostMatchInterstitial().catch((err) => {
      console.warn('[ads] post-match interstitial skipped', err);
    });
    return;
  }

  if (state === 'round_intro' || state === 'fighting') {
    monetizationPanel.hide();
  }
}

// ---- Game loop ------------------------------------------------------------

const MAX_DT = 1 / 30;
let lastTime = performance.now();
let frameCount = 0;
let fpsAccumulator = 0;

const _wasGrounded = [true, true];

function frame(now) {
  const rawDt = (now - lastTime) / 1000;
  lastTime = now;
  const realDt = Math.min(rawDt, MAX_DT);
  const dt = realDt * juice.getDtScale();

  // Phase 12 — when paused, skip game logic but keep rendering the last frame.
  if (pauseMenu.isPaused()) {
    renderer.render(sceneManager.scene);
    requestAnimationFrame(frame);
    return;
  }

  // Phase 9 — poll gamepads before any game system reads input.
  input.pollGamepads();

  matchController?.update(dt);
  updateMonetizationState();

  sceneManager.update(dt);
  stage?.update(dt);

  if (fighters.length === 2) {
    const locked = matchController ? matchController.isInputLocked() : false;
    opponentAI?.update(dt);
    const p1Input = locked ? matchController.noopInput : input;
    const p2Input = locked
      ? matchController.noopInput
      : (opponentAI ? opponentAI.input : input);
    fighters[0].update(dt, p1Input);
    fighters[1].update(dt, p2Input);

    for (let i = 0; i < 2; i++) {
      if (_wasGrounded[i] && !fighters[i].isGrounded) synth.jump();
      _wasGrounded[i] = fighters[i].isGrounded;
    }
  }

  if (matchController?.isCombatActive() && fighters.length === 2) {
    resolveDirectionalHit(fighters[0], fighters[1]);
    resolveDirectionalHit(fighters[1], fighters[0]);
  }

  autoFaceOpponents();
  projectiles?.update(dt, fighters);

  updateHud(fighters, matchController);
  juice.update(realDt);
  renderer.render(sceneManager.scene);

  input.endFrame();
  opponentAI?.input.endFrame();

  fpsAccumulator += dt;
  frameCount += 1;
  if (fpsAccumulator >= 1) {
    const fps = Math.round(frameCount / fpsAccumulator);
    console.debug(`[boot] fps ≈ ${fps}`);
    fpsAccumulator = 0;
    frameCount = 0;
  }

  requestAnimationFrame(frame);
}

requestAnimationFrame((t) => {
  lastTime = t;
  frame(t);
});

