import { Howl, Howler } from 'howler';

/**
 * AudioManager
 * ------------
 * Thin Howler.js wrapper. Three logical channels with independent volume:
 *   - sfx    (hit, block, jump, voice)
 *   - music  (stage BGM)
 *   - voice  (announcer + character taglines)
 *
 * Sounds are registered up front via `register()` with stable string IDs,
 * then played by ID from gameplay code. This keeps systems decoupled from
 * file paths and lets us swap assets without touching combat code.
 *
 * In Phase 1 we just instantiate the manager (no audio assets exist yet).
 */
export class AudioManager {
  constructor() {
    /** @type {Map<string, Howl>} */
    this._sounds = new Map();
    this._volumes = { master: 1.0, sfx: 1.0, music: 0.7, voice: 1.0 };
    this._channelOf = new Map(); // id → 'sfx' | 'music' | 'voice'
    Howler.volume(this._volumes.master);
    this._muted = false;
  }

  /**
   * Register a sound under a stable id.
   * @param {string} id            Stable identifier ("sfx_hit_heavy", "music_akhara").
   * @param {string} src           URL under /public/audio/.
   * @param {'sfx'|'music'|'voice'} channel
   * @param {object} [opts]        Extra Howl options (loop, sprite, etc.).
   */
  register(id, src, channel = 'sfx', opts = {}) {
    if (this._sounds.has(id)) return;
    const howl = new Howl({
      src: [src],
      volume: this._volumes[channel] ?? 1.0,
      loop: channel === 'music',
      ...opts,
    });
    this._sounds.set(id, howl);
    this._channelOf.set(id, channel);
  }

  /** Play a registered sound. Returns the Howler sound id (for stop/fade). */
  play(id) {
    const s = this._sounds.get(id);
    if (!s) {
      console.warn(`[AudioManager] play(): unknown sound "${id}"`);
      return null;
    }
    return s.play();
  }

  stop(id) {
    this._sounds.get(id)?.stop();
  }

  setVolume(channel, value) {
    this._volumes[channel] = value;
    if (channel === 'master') {
      Howler.volume(value);
      return;
    }
    for (const [id, ch] of this._channelOf) {
      if (ch === channel) this._sounds.get(id)?.volume(value);
    }
  }

  mute(muted) {
    this._muted = muted;
    Howler.mute(muted);
  }

  dispose() {
    for (const s of this._sounds.values()) s.unload();
    this._sounds.clear();
    this._channelOf.clear();
  }
}
