/**
 * ProceduralAudio
 * ---------------
 * Synthesizes all game SFX + a looping dhol-style beat with raw Web Audio
 * — zero audio file dependencies. Sounds aren't perfectly desi but they
 * land in the same family (low percussive thumps for hits, bandpassed
 * noise for blocks, sweeping tone for jumps, two-beat tabla-ish loop for
 * background atmosphere).
 *
 * Browsers block audio until a user gesture, so call `resume()` from a
 * click/keydown handler before the first sound. Once resumed it stays.
 *
 * If WebAudio is unavailable (older browsers, sandboxed contexts), every
 * method silently no-ops — the game still runs.
 */
export class ProceduralAudio {
  constructor() {
    /** @type {AudioContext | null} */
    this.ctx = null;
    /** @type {GainNode | null} */
    this.masterGain = null;
    try {
      const Ctor = window.AudioContext || window.webkitAudioContext;
      if (Ctor) this.ctx = new Ctor();
    } catch (_) {
      // no-op
    }
    if (this.ctx) {
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = 0.55;
      this.masterGain.connect(this.ctx.destination);
      this._musicGain = this.ctx.createGain();
      this._musicGain.gain.value = 0.35;
      this._musicGain.connect(this.masterGain);
      this._sfxGain = this.ctx.createGain();
      this._sfxGain.gain.value = 0.8;
      this._sfxGain.connect(this.masterGain);
    }
    this._dholRunning = false;
    this._dholTimer = null;
  }

  /** Browser autoplay policy: call from a click/keydown handler. */
  resume() {
    if (this.ctx?.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
  }

  setMasterVolume(v) {
    if (this.masterGain) this.masterGain.gain.value = v;
  }
  setMusicVolume(v) {
    if (this._musicGain) this._musicGain.gain.value = v;
  }
  setSfxVolume(v) {
    if (this._sfxGain) this._sfxGain.gain.value = v;
  }

  // ---- SFX ----------------------------------------------------------------

  hit(tier = 'light') {
    if (!this.ctx) return;
    if (tier === 'heavy') this._impact(95, 0.10, 0.18, 0.85, 0.35);
    else if (tier === 'medium') this._impact(150, 0.07, 0.13, 0.7, 0.3);
    else this._impact(220, 0.05, 0.08, 0.55, 0.25);
  }

  block() {
    if (!this.ctx) return;
    // Bright bandpassed clack.
    this._noiseBurst(0.07, 0.5, 1800, 4500);
    // Plus a short low thud for body.
    this._impact(180, 0.05, 0.06, 0.3, 0.1);
  }

  jump() {
    if (!this.ctx) return;
    this._sweep(180, 380, 0.14, 0.22, 'sine');
  }

  ko() {
    if (!this.ctx) return;
    // Big multi-thump for KO impact.
    this._impact(70, 0.18, 0.4, 1.0, 0.6);
    setTimeout(() => this._impact(55, 0.15, 0.35, 0.8, 0.5), 80);
    setTimeout(() => this._noiseBurst(0.4, 0.4, 200, 1200), 30);
  }

  // ---- Music --------------------------------------------------------------

  /** Start the procedural dhol loop. Idempotent. */
  startDholLoop() {
    if (!this.ctx || this._dholRunning) return;
    this._dholRunning = true;
    const bpm = 100;
    const beatDur = 60 / bpm; // seconds per quarter
    let beat = 0;
    // 8-step pattern across 2 beats — alternating low "dha" and high "tin".
    const pattern = [
      { freq: 80, gain: 0.9, dur: 0.12 },  // dha
      { freq: 220, gain: 0.4, dur: 0.06 }, // tin
      { freq: 120, gain: 0.6, dur: 0.09 }, // ge
      { freq: 220, gain: 0.4, dur: 0.06 }, // tin
      { freq: 80, gain: 0.85, dur: 0.12 }, // dha
      { freq: 220, gain: 0.4, dur: 0.06 }, // tin
      { freq: 95, gain: 0.7, dur: 0.10 },  // ge
      { freq: 220, gain: 0.5, dur: 0.06 }, // tin
    ];
    const tick = () => {
      if (!this._dholRunning) return;
      const step = pattern[beat % pattern.length];
      this._dholHit(step.freq, step.dur, step.gain);
      beat++;
      this._dholTimer = setTimeout(tick, beatDur * 1000 * 0.5); // each step = eighth note
    };
    tick();
  }

  stopDholLoop() {
    this._dholRunning = false;
    if (this._dholTimer) {
      clearTimeout(this._dholTimer);
      this._dholTimer = null;
    }
  }

  // ---- Internal synth primitives -----------------------------------------

  _impact(freq, attackDur, decay, gain, snapGain = 0.25) {
    const now = this.ctx.currentTime;
    // Pitched body.
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq * 2, now);
    osc.frequency.exponentialRampToValueAtTime(freq * 0.6, now + attackDur + decay);
    const g = this.ctx.createGain();
    g.gain.setValueAtTime(gain, now);
    g.gain.exponentialRampToValueAtTime(0.001, now + attackDur + decay);
    osc.connect(g);
    g.connect(this._sfxGain);
    osc.start(now);
    osc.stop(now + attackDur + decay);
    // Noise snap on top for transient bite.
    if (snapGain > 0) {
      this._noiseBurst(attackDur * 0.6, snapGain, 1000, 3500);
    }
  }

  _dholHit(freq, dur, gain) {
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq * 1.8, now);
    osc.frequency.exponentialRampToValueAtTime(freq * 0.7, now + dur);
    const g = this.ctx.createGain();
    g.gain.setValueAtTime(gain, now);
    g.gain.exponentialRampToValueAtTime(0.001, now + dur * 1.6);
    osc.connect(g);
    g.connect(this._musicGain);
    osc.start(now);
    osc.stop(now + dur * 1.6);
    // Small noise transient for the drum-skin slap.
    const buf = this.ctx.createBuffer(1, Math.floor(this.ctx.sampleRate * 0.02), this.ctx.sampleRate);
    const d = buf.getChannelData(0);
    for (let i = 0; i < d.length; i++) d[i] = (Math.random() * 2 - 1) * (1 - i / d.length);
    const src = this.ctx.createBufferSource();
    src.buffer = buf;
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = freq * 4;
    filter.Q.value = 1.5;
    const sg = this.ctx.createGain();
    sg.gain.setValueAtTime(gain * 0.4, now);
    sg.gain.exponentialRampToValueAtTime(0.001, now + 0.03);
    src.connect(filter);
    filter.connect(sg);
    sg.connect(this._musicGain);
    src.start(now);
  }

  _noiseBurst(duration, gain, lowF, highF) {
    const now = this.ctx.currentTime;
    const samples = Math.floor(this.ctx.sampleRate * duration);
    const buffer = this.ctx.createBuffer(1, samples, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < samples; i++) data[i] = Math.random() * 2 - 1;
    const source = this.ctx.createBufferSource();
    source.buffer = buffer;
    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = (lowF + highF) / 2;
    filter.Q.value = 1.2;
    const g = this.ctx.createGain();
    g.gain.setValueAtTime(gain, now);
    g.gain.exponentialRampToValueAtTime(0.001, now + duration);
    source.connect(filter);
    filter.connect(g);
    g.connect(this._sfxGain);
    source.start(now);
  }

  _sweep(startF, endF, duration, gain, type = 'sine') {
    const now = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    osc.type = type;
    osc.frequency.setValueAtTime(startF, now);
    osc.frequency.exponentialRampToValueAtTime(endF, now + duration);
    const g = this.ctx.createGain();
    g.gain.setValueAtTime(gain, now);
    g.gain.exponentialRampToValueAtTime(0.001, now + duration);
    osc.connect(g);
    g.connect(this._sfxGain);
    osc.start(now);
    osc.stop(now + duration);
  }
}
