/**
 * StageSelect
 * -----------
 * Picked after CharacterSelect, before the match starts. Shows each
 * available stage as a tile with a preview thumbnail + name + region,
 * lets the player highlight with arrows / WASD and confirm with Enter.
 *
 * onConfirm(stageId) is called once the user picks.
 */
export class StageSelect {
  /**
   * @param {HTMLElement} root
   * @param {Record<string, object>} stages   STAGES map from stages.js
   * @param {(stageId: string) => void} onConfirm
   * @param {{defaultStageId?: string}} [opts]
   */
  constructor(root, stages, onConfirm, opts = {}) {
    this.root = root;
    this.stages = Object.values(stages);
    this.onConfirm = onConfirm;
    this.onBack = opts.onBack ?? null;
    this.cursor = Math.max(
      0,
      this.stages.findIndex((s) => s.id === opts.defaultStageId),
    );
    if (this.cursor < 0) this.cursor = 0;
    this.elements = {};
    this._onKey = this._onKey.bind(this);
    this._imageCache = new Map();
  }

  show() {
    this._build();
    window.addEventListener('keydown', this._onKey);
  }

  hide() {
    window.removeEventListener('keydown', this._onKey);
    if (this._wrap && this._wrap.parentNode) {
      this._wrap.parentNode.removeChild(this._wrap);
    }
  }

  _build() {
    const wrap = document.createElement('div');
    wrap.style.cssText = `
      position: absolute; inset: 0;
      background: linear-gradient(180deg, rgba(20,12,6,0.94) 0%, rgba(40,18,12,0.9) 100%);
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      gap: clamp(10px, 2vh, 18px);
      padding:
        max(18px, env(safe-area-inset-top))
        max(18px, env(safe-area-inset-right))
        max(18px, env(safe-area-inset-bottom))
        max(18px, env(safe-area-inset-left));
      pointer-events: auto;
      font-family: 'Segoe UI', system-ui, sans-serif;
      color: #f5e9c9;
      z-index: 40;
      box-sizing: border-box;
      overflow: hidden;
    `;
    this._wrap = wrap;

    const title = document.createElement('div');
    title.textContent = 'CHOOSE YOUR STAGE';
    title.style.cssText = `
      display: none;
      font-size: clamp(18px, 4.2vh, 32px); letter-spacing: 0.22em; font-weight: 900;
      color: #ffd770;
      text-shadow: 2px 2px 0 #1b120a, 0 0 24px rgba(255,215,112,0.55);
    `;
    wrap.appendChild(title);

    const subtitle = document.createElement('div');
    subtitle.style.cssText = `
      font-size: clamp(11px, 2.2vh, 14px); letter-spacing: 0.18em; color: #f5e9c9; opacity: 0.85;
    `;
    subtitle.textContent = 'Where will the duel happen?';
    wrap.appendChild(subtitle);

    if (this.onBack) {
      const back = document.createElement('button');
      back.type = 'button';
      back.textContent = 'BACK';
      back.style.cssText = `
        padding: clamp(5px, 1.3vh, 7px) clamp(12px, 2.4vw, 16px);
        background:#2a160d;
        color:#f5e9c9;
        border:2px solid #8d6421;
        border-radius:4px;
        font-size:clamp(10px, 2vh, 12px);
        font-weight:800;
        letter-spacing:0.14em;
        font-family:inherit;
        cursor:pointer;
      `;
      back.addEventListener('click', () => {
        this.hide();
        this.onBack?.();
      });
      wrap.appendChild(back);
    }

    const grid = document.createElement('div');
    grid.style.cssText = `
      display: grid;
      width: min(1500px, calc(100vw - 72px));
      grid-template-columns: repeat(${this.stages.length}, minmax(0, 1fr));
      gap: clamp(10px, 1.8vw, 18px);
      align-items: stretch;
    `;
    wrap.appendChild(grid);

    this.elements.tiles = [];
    for (let i = 0; i < this.stages.length; i++) {
      const stage = this.stages[i];
      const tile = document.createElement('div');
      tile.style.cssText = `
        position: relative;
        border: 3px solid #6a4a16;
        border-radius: 8px;
        background: linear-gradient(135deg, #2a0d0d, #1b120a);
        overflow: hidden;
        cursor: pointer;
        transition: transform 120ms ease-out, border-color 120ms, box-shadow 120ms;
        display: flex; flex-direction: column;
        box-shadow: inset 0 0 0 1px rgba(255,215,112,0.12);
      `;

      const preview = this._buildPreview(stage);
      tile.appendChild(preview);

      const caption = document.createElement('div');
      caption.style.cssText = `
        padding: 12px 14px;
        background: linear-gradient(180deg, rgba(27,18,10,0.96), rgba(12,7,4,0.98));
        border-top: 1px solid rgba(255,215,112,0.18);
      `;
      const name = document.createElement('div');
      name.textContent = stage.name;
      name.style.cssText = `
        font-size: clamp(14px, 3.3vh, 16px); font-weight: 800;
        letter-spacing: 0.10em; color: #ffd770;
        text-shadow: 1px 1px 0 #1b120a;
        line-height: 1.08;
        overflow-wrap: anywhere;
      `;
      const region = document.createElement('div');
      region.textContent = stage.region;
      region.style.cssText = `
        font-size: clamp(9px, 2vh, 11px); letter-spacing: 0.10em;
        color: #f5e9c9; opacity: 0.7; margin-top: 3px;
      `;
      caption.appendChild(name);
      caption.appendChild(region);
      tile.appendChild(caption);

      tile.addEventListener('click', () => {
        this.cursor = i;
        this._confirmCurrent();
      });
      tile.addEventListener('mouseenter', () => {
        this.cursor = i;
        this._renderState();
      });

      grid.appendChild(tile);
      this.elements.tiles.push({ tile });
    }

    const desc = document.createElement('div');
    desc.style.cssText = `
      max-width: min(720px, calc(100vw - 48px)); min-height: clamp(28px, 6vh, 44px);
      font-size: clamp(10px, 2vh, 13px); line-height: 1.35; color: #f5e9c9; opacity: 0.85;
      text-align: center; padding: 0 16px;
      font-style: italic;
    `;
    wrap.appendChild(desc);
    this.elements.desc = desc;

    const hints = document.createElement('div');
    hints.style.cssText = `
      font-size: clamp(9px, 1.8vh, 11px); letter-spacing: 0.14em; color: #f5e9c9; opacity: 0.65;
    `;
    hints.textContent = 'Arrows or WASD to move - Enter to confirm - Esc to go back - Click to pick';
    wrap.appendChild(hints);

    this.root.appendChild(wrap);
    this._renderState();
  }

  _buildPreview(stage) {
    const preview = document.createElement('div');
    preview.style.cssText = `
      position: relative; width: 100%; aspect-ratio: 16 / 9;
      background:
        radial-gradient(circle at 50% 20%, rgba(255,215,112,0.16), transparent 42%),
        linear-gradient(180deg, #372013 0%, #120906 100%);
      overflow: hidden;
    `;

    if (stage.preview) {
      const img = document.createElement('img');
      img.src = stage.preview;
      img.alt = `${stage.name} preview`;
      img.decoding = 'async';
      img.style.cssText = `
        position: absolute; inset: 0;
        width: 100%; height: 100%;
        object-fit: cover;
        display: block;
      `;
      preview.appendChild(img);
      return preview;
    }

    const canvas = document.createElement('canvas');
    canvas.width = 640;
    canvas.height = 360;
    canvas.style.cssText = `
      position:absolute; inset:0; width:100%; height:100%;
      display:block;
    `;
    preview.appendChild(canvas);

    this._paintPreview(canvas, stage);
    return preview;
  }

  async _paintPreview(canvas, stage) {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const w = canvas.width;
    const h = canvas.height;
    ctx.clearRect(0, 0, w, h);
    this._paintFallbackGradient(ctx, w, h);

    if (stage.id === 'islamabad_faisal') {
      await this._paintIslamabadPreview(ctx, w, h, stage);
      return;
    }
    if (stage.id === 'lahore_minar') {
      await this._paintLahorePreview(ctx, w, h, stage);
      return;
    }
    if (stage.id === 'karachi_rooftop') {
      await this._paintKarachiRooftopPreview(ctx, w, h, stage);
      return;
    }
    if (stage.id === 'karachi_seaview') {
      await this._paintKarachiSeaViewPreview(ctx, w, h, stage);
      return;
    }
    if (stage.id === 'village_akhara') {
      await this._paintVillageAkharaPreview(ctx, w, h, stage);
      return;
    }

    const layers = stage.layers ?? [];
    const sky = layers.find((layer) => layer.role === 'sky') ?? layers[0];
    if (sky?.src) {
      const img = await this._loadImage(sky.src);
      if (img) this._drawCover(ctx, img, 0, 0, w, h, 0.5, 0.52);
    }

    const drawOrder = layers.filter((layer) => layer !== sky && layer.role !== 'ground');
    for (const layer of drawOrder) {
      const img = await this._loadImage(layer.src);
      if (!img) continue;
      const cleaned = this._cleanCheckerboard(img);
      if (layer.role === 'background') {
        this._drawCover(ctx, cleaned, 0, 38, w, h - 48, 0.5, 0.55);
      } else if (layer.role === 'midground') {
        this._drawContain(ctx, cleaned, 0, 76, w, h - 82, 0.5, 1.0);
      } else {
        this._drawContain(ctx, cleaned, 0, 90, w, h - 76, 0.5, 1.0);
      }
    }

    const ground = layers.find((layer) => layer.role === 'ground');
    if (ground?.src) {
      const img = await this._loadImage(ground.src);
      if (img) {
        ctx.save();
        ctx.globalAlpha = 0.24;
        this._drawCover(ctx, img, 0, h * 0.66, w, h * 0.34, 0.5, 0.72);
        ctx.restore();
      }
    }

    const vignette = ctx.createLinearGradient(0, 0, 0, h);
    vignette.addColorStop(0, 'rgba(0,0,0,0.02)');
    vignette.addColorStop(0.70, 'rgba(0,0,0,0.06)');
    vignette.addColorStop(1, 'rgba(0,0,0,0.34)');
    ctx.fillStyle = vignette;
    ctx.fillRect(0, 0, w, h);
  }

  async _paintIslamabadPreview(ctx, w, h, stage) {
    const layer = (role) => stage.layers?.find((item) => item.role === role);
    const sky = await this._loadImage(layer('sky')?.src);
    const hills = await this._loadImage(layer('background')?.src);
    const mosque = await this._loadImage(layer('foreground')?.src);

    if (sky) this._drawCover(ctx, sky, 0, 0, w, h, 0.5, 0.5);
    if (hills) {
      ctx.save();
      ctx.globalAlpha = 0.95;
      const cleanHills = this._cleanCheckerboard(hills);
      const sy = Math.floor(cleanHills.height * 0.22);
      ctx.drawImage(
        cleanHills,
        0,
        sy,
        cleanHills.width,
        cleanHills.height - sy,
        -20,
        82,
        w + 40,
        150,
      );
      ctx.restore();
    }
    if (mosque) {
      ctx.save();
      ctx.globalAlpha = 0.94;
      this._drawContain(ctx, this._cleanNeutralLightBackdrop(mosque), 118, 154, 404, 126, 0.5, 1);
      ctx.restore();
    }

    const ground = await this._loadImage(layer('ground')?.src);
    if (ground) {
      ctx.save();
      ctx.globalAlpha = 0.32;
      this._drawCover(ctx, ground, 0, 250, w, 110, 0.5, 0.68);
      ctx.restore();
    }

    const vignette = ctx.createLinearGradient(0, 0, 0, h);
    vignette.addColorStop(0, 'rgba(0,0,0,0.00)');
    vignette.addColorStop(0.75, 'rgba(0,0,0,0.06)');
    vignette.addColorStop(1, 'rgba(0,0,0,0.30)');
    ctx.fillStyle = vignette;
    ctx.fillRect(0, 0, w, h);
  }

  async _paintLahorePreview(ctx, w, h, stage) {
    const layer = (role) => stage.layers?.find((item) => item.role === role);
    const sky = await this._loadImage(layer('sky')?.src);
    const lawn = await this._loadImage(layer('midground')?.src);
    const minar = await this._loadImage(layer('background')?.src);
    const ground = await this._loadImage(layer('ground')?.src);

    if (sky) this._drawCover(ctx, sky, 0, 0, w, h, 0.5, 0.5);
    if (lawn) {
      const cleanLawn = this._cleanCheckerboard(this._cleanNeutralLightBackdrop(lawn));
      const sy = Math.floor(cleanLawn.height * 0.42);
      ctx.drawImage(cleanLawn, 0, sy, cleanLawn.width, cleanLawn.height - sy, -18, 170, w + 36, 95);
    }
    if (minar) {
      this._drawContain(ctx, this._cleanCheckerboard(this._cleanNeutralLightBackdrop(minar)), 207, 68, 226, 198, 0.5, 1);
    }
    if (ground) {
      ctx.save();
      ctx.globalAlpha = 0.22;
      this._drawCover(ctx, ground, 0, 250, w, 110, 0.5, 0.70);
      ctx.restore();
    }

    const warmth = ctx.createLinearGradient(0, 0, 0, h);
    warmth.addColorStop(0, 'rgba(0,0,0,0.02)');
    warmth.addColorStop(0.62, 'rgba(255,176,56,0.10)');
    warmth.addColorStop(1, 'rgba(0,0,0,0.32)');
    ctx.fillStyle = warmth;
    ctx.fillRect(0, 0, w, h);
  }

  async _paintKarachiRooftopPreview(ctx, w, h, stage) {
    const layer = (role) => stage.layers?.find((item) => item.role === role);
    const sky = await this._loadImage(layer('sky')?.src);
    const midrise = await this._loadImage(layer('background')?.src);
    const rooftop = await this._loadImage(layer('midground')?.src);
    const ground = await this._loadImage(layer('ground')?.src);

    if (sky) this._drawCover(ctx, sky, 0, 0, w, h, 0.5, 0.48);
    if (midrise) {
      ctx.save();
      ctx.globalAlpha = 0.96;
      this._drawContain(ctx, this._cleanCheckerTileBackdrop(midrise), -42, 130, w + 84, 126, 0.5, 1);
      ctx.restore();
    }
    if (rooftop) {
      ctx.save();
      ctx.globalAlpha = 1;
      this._drawContain(ctx, this._cleanCheckerTileBackdrop(rooftop), 4, 190, w - 8, 98, 0.5, 1);
      ctx.restore();
    }
    if (ground) {
      ctx.save();
      ctx.globalAlpha = 0.24;
      this._drawCover(ctx, ground, 0, 252, w, 108, 0.5, 0.70);
      ctx.restore();
    }

    const mood = ctx.createLinearGradient(0, 0, 0, h);
    mood.addColorStop(0, 'rgba(0,0,0,0.08)');
    mood.addColorStop(0.60, 'rgba(255,84,64,0.10)');
    mood.addColorStop(1, 'rgba(0,0,0,0.34)');
    ctx.fillStyle = mood;
    ctx.fillRect(0, 0, w, h);
  }

  async _paintKarachiSeaViewPreview(ctx, w, h, stage) {
    const layer = (role) => stage.layers?.find((item) => item.role === role);
    const sky = await this._loadImage(layer('sky')?.src);
    const sea = await this._loadImage(layer('background')?.src);
    const beach = await this._loadImage(layer('midground')?.src);
    const foreground = await this._loadImage(layer('foreground')?.src);
    const ground = await this._loadImage(layer('ground')?.src);

    if (sky) this._drawCover(ctx, sky, 0, 0, w, h, 0.5, 0.48);
    if (sea) {
      ctx.save();
      ctx.globalAlpha = 0.92;
      this._drawCover(ctx, this._cleanCheckerboard(sea), 0, 86, w, 158, 0.5, 0.58);
      ctx.restore();
    }
    if (beach) {
      ctx.save();
      ctx.globalAlpha = 0.76;
      this._drawCover(ctx, this._cleanCheckerboard(beach), -10, 145, w + 20, 104, 0.5, 0.72);
      ctx.restore();
    }
    if (foreground) {
      ctx.save();
      ctx.globalAlpha = 0.96;
      this._drawContain(ctx, this._cleanCheckerboard(foreground), 30, 154, w - 60, 118, 0.5, 1);
      ctx.restore();
    }
    if (ground) {
      ctx.save();
      ctx.globalAlpha = 0.30;
      this._drawCover(ctx, ground, 0, 250, w, 110, 0.5, 0.72);
      ctx.restore();
    }

    const glow = ctx.createLinearGradient(0, 0, 0, h);
    glow.addColorStop(0, 'rgba(0,0,0,0.00)');
    glow.addColorStop(0.62, 'rgba(255,184,86,0.08)');
    glow.addColorStop(1, 'rgba(0,0,0,0.32)');
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, w, h);
  }

  async _paintVillageAkharaPreview(ctx, w, h, stage) {
    const layer = (role) => stage.layers?.find((item) => item.role === role);
    const sky = await this._loadImage(layer('sky')?.src);
    const hills = await this._loadImage(layer('background')?.src);
    const cane = await this._loadImage(layer('midground')?.src);
    const charpai = await this._loadImage(layer('foreground')?.src);
    const ground = await this._loadImage(layer('ground')?.src);

    if (sky) this._drawCover(ctx, sky, 0, 0, w, h, 0.5, 0.48);
    if (hills) {
      ctx.save();
      ctx.globalAlpha = 0.34;
      const cleanHills = this._cleanNeutralLightBackdrop(hills);
      const sy = Math.floor(cleanHills.height * 0.60);
      ctx.drawImage(cleanHills, 0, sy, cleanHills.width, cleanHills.height - sy, -24, 148, w + 48, 72);
      ctx.restore();
    }
    ctx.save();
    const dust = ctx.createLinearGradient(0, 122, 0, 236);
    dust.addColorStop(0, 'rgba(111,70,35,0.00)');
    dust.addColorStop(0.55, 'rgba(132,75,31,0.30)');
    dust.addColorStop(1, 'rgba(81,38,15,0.72)');
    ctx.fillStyle = dust;
    ctx.fillRect(0, 122, w, 114);
    ctx.restore();
    if (cane) {
      ctx.save();
      ctx.globalAlpha = 0.96;
      const iw = cane.naturalWidth || cane.width;
      const ih = cane.naturalHeight || cane.height;
      const sy = Math.floor(ih * 0.42);
      ctx.drawImage(cane, 0, sy, iw, ih - sy, -18, 122, w + 36, 118);
      ctx.restore();
    }
    if (ground) {
      ctx.save();
      ctx.globalAlpha = 0.50;
      this._drawCover(ctx, ground, 0, 222, w, 138, 0.5, 0.62);
      ctx.restore();
    }
    if (charpai) {
      const cleanCharpai = this._cleanDarkBackdrop(charpai);
      ctx.save();
      ctx.globalAlpha = 0.96;
      this._drawContain(ctx, cleanCharpai, 104, 176, 432, 100, 0.5, 1);
      ctx.restore();
    }

    const warmth = ctx.createLinearGradient(0, 0, 0, h);
    warmth.addColorStop(0, 'rgba(0,0,0,0.00)');
    warmth.addColorStop(0.68, 'rgba(255,170,56,0.08)');
    warmth.addColorStop(1, 'rgba(0,0,0,0.34)');
    ctx.fillStyle = warmth;
    ctx.fillRect(0, 0, w, h);
  }

  _paintFallbackGradient(ctx, w, h) {
    const bg = ctx.createLinearGradient(0, 0, 0, h);
    bg.addColorStop(0, '#513019');
    bg.addColorStop(0.48, '#a75d2d');
    bg.addColorStop(1, '#20100a');
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, w, h);
  }

  _loadImage(src) {
    if (!src) return Promise.resolve(null);
    if (this._imageCache.has(src)) return this._imageCache.get(src);
    const p = new Promise((resolve) => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = () => resolve(null);
      img.src = src;
    });
    this._imageCache.set(src, p);
    return p;
  }

  _cleanCheckerboard(img) {
    const c = document.createElement('canvas');
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const scale = Math.min(1, 960 / iw);
    c.width = Math.max(1, Math.round(iw * scale));
    c.height = Math.max(1, Math.round(ih * scale));
    const ctx = c.getContext('2d', { willReadFrequently: true });
    if (!ctx) return img;
    ctx.drawImage(img, 0, 0, c.width, c.height);

    const image = ctx.getImageData(0, 0, c.width, c.height);
    const px = image.data;
    for (let i = 0; i < px.length; i += 4) {
      const r = px[i];
      const g = px[i + 1];
      const b = px[i + 2];
      const max = Math.max(r, g, b);
      const min = Math.min(r, g, b);
      const avg = (r + g + b) / 3;
      const y = Math.floor((i / 4) / c.width);
      const inUpperBand = y < c.height * 0.62;
      const isChecker =
        (avg > 178 && max - min < 58) ||
        (inUpperBand && avg > 120 && max - min < 46);
      if (isChecker) {
        const fade = Math.max(0, Math.min(1, (avg - 178) / 45));
        const alphaKeep = inUpperBand ? 0 : 1 - fade;
        px[i + 3] = Math.floor(px[i + 3] * alphaKeep);
      } else if (inUpperBand && avg > 150 && max - min < 70) {
        px[i + 3] = Math.floor(px[i + 3] * 0.28);
      }
    }
    ctx.putImageData(image, 0, 0);
    return c;
  }

  _cleanDarkBackdrop(img) {
    const c = document.createElement('canvas');
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const scale = Math.min(1, 960 / iw);
    c.width = Math.max(1, Math.round(iw * scale));
    c.height = Math.max(1, Math.round(ih * scale));
    const ctx = c.getContext('2d', { willReadFrequently: true });
    if (!ctx) return img;
    ctx.drawImage(img, 0, 0, c.width, c.height);

    const image = ctx.getImageData(0, 0, c.width, c.height);
    const px = image.data;
    for (let i = 0; i < px.length; i += 4) {
      const r = px[i];
      const g = px[i + 1];
      const b = px[i + 2];
      const max = Math.max(r, g, b);
      const min = Math.min(r, g, b);
      const avg = (r + g + b) / 3;
      if (avg < 118 && max - min < 52) {
        px[i + 3] = 0;
      }
    }
    ctx.putImageData(image, 0, 0);
    return c;
  }

  _cleanNeutralLightBackdrop(img) {
    const c = document.createElement('canvas');
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const scale = Math.min(1, 960 / iw);
    c.width = Math.max(1, Math.round(iw * scale));
    c.height = Math.max(1, Math.round(ih * scale));
    const ctx = c.getContext('2d', { willReadFrequently: true });
    if (!ctx) return img;
    ctx.drawImage(img, 0, 0, c.width, c.height);

    const image = ctx.getImageData(0, 0, c.width, c.height);
    const px = image.data;
    for (let i = 0; i < px.length; i += 4) {
      const r = px[i];
      const g = px[i + 1];
      const b = px[i + 2];
      const max = Math.max(r, g, b);
      const min = Math.min(r, g, b);
      const avg = (r + g + b) / 3;
      if (avg > 214 && max - min < 18) {
        const keep = Math.max(0, Math.min(1, (238 - avg) / 24));
        px[i + 3] = Math.floor(px[i + 3] * keep);
      } else if (avg > 178 && max - min < 42) {
        const keep = Math.max(0, Math.min(1, (220 - avg) / 42));
        px[i + 3] = Math.floor(px[i + 3] * keep);
      }
    }
    ctx.putImageData(image, 0, 0);
    return c;
  }

  _cleanCheckerTileBackdrop(img) {
    const c = document.createElement('canvas');
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const scale = Math.min(1, 960 / iw);
    c.width = Math.max(1, Math.round(iw * scale));
    c.height = Math.max(1, Math.round(ih * scale));
    const ctx = c.getContext('2d', { willReadFrequently: true });
    if (!ctx) return img;
    ctx.drawImage(img, 0, 0, c.width, c.height);

    const image = ctx.getImageData(0, 0, c.width, c.height);
    const px = image.data;
    for (let i = 0; i < px.length; i += 4) {
      const r = px[i];
      const g = px[i + 1];
      const b = px[i + 2];
      const max = Math.max(r, g, b);
      const min = Math.min(r, g, b);
      const avg = (r + g + b) / 3;
      const lowSaturation = max - min < 48;
      const lightGrayTile = avg > 150 && lowSaturation;
      const paleTile = avg > 126 && max - min < 28;
      if (lightGrayTile || paleTile) {
        px[i + 3] = 0;
      }
    }
    ctx.putImageData(image, 0, 0);
    return c;
  }

  _drawCover(ctx, img, x, y, w, h, ax = 0.5, ay = 0.5) {
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const scale = Math.max(w / iw, h / ih);
    const dw = iw * scale;
    const dh = ih * scale;
    ctx.drawImage(img, x + (w - dw) * ax, y + (h - dh) * ay, dw, dh);
  }

  _drawContain(ctx, img, x, y, w, h, ax = 0.5, ay = 0.5) {
    const iw = img.naturalWidth || img.width;
    const ih = img.naturalHeight || img.height;
    const scale = Math.min(w / iw, h / ih);
    const dw = iw * scale;
    const dh = ih * scale;
    ctx.drawImage(img, x + (w - dw) * ax, y + (h - dh) * ay, dw, dh);
  }

  _renderState() {
    for (let i = 0; i < this.elements.tiles.length; i++) {
      const { tile } = this.elements.tiles[i];
      const isCursor = i === this.cursor;
      tile.style.borderColor = isCursor ? '#ffd770' : '#6a4a16';
      tile.style.transform = isCursor ? 'translateY(-4px) scale(1.02)' : 'none';
      tile.style.boxShadow = isCursor
        ? '0 0 24px rgba(255,215,112,0.55), 0 0 4px rgba(255,215,112,0.4)'
        : 'none';
    }
    if (this.elements.desc) {
      this.elements.desc.textContent = this.stages[this.cursor]?.description ?? '';
    }
  }

  _moveCursor(dx) {
    this.cursor = (this.cursor + dx + this.stages.length) % this.stages.length;
    this._renderState();
  }

  _confirmCurrent() {
    const picked = this.stages[this.cursor];
    if (!picked) return;
    this.hide();
    this.onConfirm(picked.id);
  }

  _onKey(e) {
    switch (e.code) {
      case 'ArrowLeft': case 'KeyA':  this._moveCursor(-1); break;
      case 'ArrowRight': case 'KeyD': this._moveCursor(1); break;
      case 'ArrowUp': case 'KeyW':    this._moveCursor(-1); break;
      case 'ArrowDown': case 'KeyS':  this._moveCursor(1); break;
      case 'Enter': case 'Space':     this._confirmCurrent(); break;
      case 'Escape':
        if (this.onBack) {
          this.hide();
          this.onBack();
        }
        break;
      default: return;
    }
    e.preventDefault();
  }
}
