/**
 * BlockState
 * ----------
 * Holding block. Plays block_high or block_low based on payload.low.
 * When struck while blocking, takeHit re-enters BlockState with a
 * blockstun timer; the fighter cannot act until stun expires.
 */
export const BlockState = {
  name: 'block',

  enter(fighter, _prev, payload = {}) {
    this._low = !!payload.low;
    this._stunRemaining = payload.stun ?? 0;
    fighter.velocity.x = 0;
    fighter.playClip(this._low ? 'block_low' : 'block_high', { loop: true });
  },

  update(dt, input, fighter) {
    if (this._stunRemaining > 0) {
      this._stunRemaining -= dt;
      return null;
    }
    if (!input.isDown('block', fighter.playerId)) {
      return 'idle';
    }
    const wantLow = input.isDown('down', fighter.playerId);
    if (wantLow !== this._low) {
      this._low = wantLow;
      fighter.playClip(this._low ? 'block_low' : 'block_high', { loop: true });
    }
    return null;
  },
};
