/**
 * Input
 * -----
 * Keyboard input manager with a short input buffer for combo/special detection.
 *
 * Each frame the game can ask:
 *   - input.isDown('punch_light', playerId)  — held this frame?
 *   - input.wasPressed('jump', playerId)     — newly pressed this frame?
 *   - input.recentSequence(playerId)         — last N actions for special motion matching
 *
 * Phase 9: touch overlay (TouchControls.js) and Gamepad API both feed this same
 * state via setDown() / setUp() — the rest of the engine does not know or care
 * whether the input came from keyboard, touchscreen, or controller.
 */

/** @typedef {'up'|'down'|'left'|'right'|'punch_light'|'punch_medium'|'punch_heavy'|'kick_light'|'kick_medium'|'kick_heavy'|'block'|'special'|'throw'|'shoryuken'|'hadoken'} GameAction */

const DEFAULT_BINDINGS_P1 = {
  KeyA: 'left',
  KeyD: 'right',
  KeyW: 'up',
  KeyS: 'down',
  KeyJ: 'punch_light',
  KeyK: 'punch_medium',
  KeyL: 'punch_heavy',
  KeyU: 'kick_light',
  KeyI: 'kick_medium',
  KeyO: 'kick_heavy',
  Semicolon: 'block',
  Space: 'special',
  // Dedicated single-button daav (throw) — much easier than LP+LK timing.
  KeyH: 'throw',
  // Dedicated single-button shoryuken (rising anti-air).
  KeyB: 'shoryuken',
};

// P2 bindings (only used for local-2P; in v1 P2 is AI-controlled).
const DEFAULT_BINDINGS_P2 = {
  ArrowLeft: 'left',
  ArrowRight: 'right',
  ArrowUp: 'up',
  ArrowDown: 'down',
  Numpad1: 'punch_light',
  Numpad2: 'punch_medium',
  Numpad3: 'punch_heavy',
  Numpad4: 'kick_light',
  Numpad5: 'kick_medium',
  Numpad6: 'kick_heavy',
  Numpad0: 'block',
  NumpadEnter: 'special',
  Numpad7: 'throw',
  Numpad9: 'shoryuken',
};

const BUFFER_MS = 400; // how long a buffered input stays valid for combo matching

export class Input {
  constructor(target = window) {
    this.target = target;
    this.bindings = [DEFAULT_BINDINGS_P1, DEFAULT_BINDINGS_P2];

    // Per-player state: which actions are currently held + which were pressed this frame.
    this._down = [new Set(), new Set()];
    this._pressedThisFrame = [new Set(), new Set()];
    this._releasedThisFrame = [new Set(), new Set()];
    this._sourceHolds = [new Map(), new Map()];
    /** @type {Array<Array<{action: GameAction, t: number}>>} */
    this._buffer = [[], []];

    this._onKeyDown = this._onKeyDown.bind(this);
    this._onKeyUp = this._onKeyUp.bind(this);
    target.addEventListener('keydown', this._onKeyDown);
    target.addEventListener('keyup', this._onKeyUp);
  }

  _resolveAction(code) {
    for (let playerId = 0; playerId < this.bindings.length; playerId++) {
      const action = this.bindings[playerId][code];
      if (action) return { playerId, action };
    }
    return null;
  }

  _onKeyDown(e) {
    const hit = this._resolveAction(e.code);
    if (!hit) return;
    if (e.repeat) return; // ignore OS auto-repeat for press edges
    const { playerId, action } = hit;
    this.setDown(action, playerId, `keyboard:${e.code}`);
    // Prevent page scroll on space/arrows.
    if (
      e.code === 'Space' ||
      e.code.startsWith('Arrow') ||
      e.code === 'Semicolon'
    ) {
      e.preventDefault();
    }
  }

  _onKeyUp(e) {
    const hit = this._resolveAction(e.code);
    if (!hit) return;
    const { playerId, action } = hit;
    this.setUp(action, playerId, `keyboard:${e.code}`);
  }

  /**
   * Inject a virtual press (touch button, gamepad button). Idempotent — calling
   * twice in the same frame does not register a second press edge.
   */
  setDown(action, playerId = 0, source = 'virtual') {
    const sources = this._sourcesFor(action, playerId);
    if (sources.has(source)) return;
    sources.add(source);
    if (this._down[playerId].has(action)) return;
    this._down[playerId].add(action);
    this._pressedThisFrame[playerId].add(action);
    this._buffer[playerId].push({ action, t: performance.now() });
  }

  /** Inject a virtual release. */
  setUp(action, playerId = 0, source = 'virtual') {
    const sources = this._sourceHolds[playerId].get(action);
    if (sources) {
      sources.delete(source);
      if (sources.size > 0) return;
      this._sourceHolds[playerId].delete(action);
    }
    if (!this._down[playerId].has(action)) return;
    this._down[playerId].delete(action);
    this._releasedThisFrame[playerId].add(action);
  }

  _sourcesFor(action, playerId) {
    let sources = this._sourceHolds[playerId].get(action);
    if (!sources) {
      sources = new Set();
      this._sourceHolds[playerId].set(action, sources);
    }
    return sources;
  }

  // --- Gamepad polling -----------------------------------------------------

  /**
   * Standard Gamepad-API → action map. Matches Xbox-style layout:
   *   A=punch_light, B=punch_medium, X=kick_light, Y=kick_medium,
   *   LB=punch_heavy, RB=kick_heavy, LT=block, RT=throw,
   *   D-pad up/down/left/right.
   */
  static GAMEPAD_BUTTON_MAP = {
    0: 'punch_light',
    1: 'punch_medium',
    2: 'kick_light',
    3: 'kick_medium',
    4: 'punch_heavy',
    5: 'kick_heavy',
    6: 'block',
    7: 'throw',
    8: 'special',
    9: 'shoryuken',
    12: 'up',
    13: 'down',
    14: 'left',
    15: 'right',
  };

  /**
   * Poll connected gamepads and translate their state into virtual actions.
   * Call once per frame BEFORE game systems read input. Player 0 is the first
   * connected gamepad; subsequent gamepads map to player 1.
   */
  pollGamepads() {
    if (typeof navigator === 'undefined' || !navigator.getGamepads) return;
    const pads = navigator.getGamepads();
    const seenGamepadSources = new Set();
    let playerId = 0;
    for (const pad of pads) {
      if (!pad) continue;
      const padSource = `gamepad:${pad.index}`;
      // Buttons
      for (const [idx, action] of Object.entries(Input.GAMEPAD_BUTTON_MAP)) {
        const button = pad.buttons[+idx];
        if (!button) continue;
        const source = `${padSource}:button:${idx}`;
        seenGamepadSources.add(source);
        if (button.pressed) this.setDown(action, playerId, source);
        else this.setUp(action, playerId, source);
      }
      // Left analog stick → left/right/up (jump). 0.5 deadzone.
      const axX = pad.axes[0] ?? 0;
      const axY = pad.axes[1] ?? 0;
      const axisSources = {
        left: `${padSource}:axis:left`,
        right: `${padSource}:axis:right`,
        up: `${padSource}:axis:up`,
        down: `${padSource}:axis:down`,
      };
      for (const source of Object.values(axisSources)) seenGamepadSources.add(source);
      if (axX < -0.5) this.setDown('left', playerId, axisSources.left);
      else this.setUp('left', playerId, axisSources.left);
      if (axX > 0.5) this.setDown('right', playerId, axisSources.right);
      else this.setUp('right', playerId, axisSources.right);
      if (axY < -0.5) this.setDown('up', playerId, axisSources.up);
      else if (axY < 0.3) this.setUp('up', playerId, axisSources.up);
      if (axY > 0.5) this.setDown('down', playerId, axisSources.down);
      else if (axY > -0.3) this.setUp('down', playerId, axisSources.down);

      playerId++;
      if (playerId >= 2) break;
    }
    this._releaseMissingGamepadSources(seenGamepadSources);
  }

  _releaseMissingGamepadSources(seen) {
    for (let playerId = 0; playerId < this._sourceHolds.length; playerId++) {
      for (const [action, sources] of Array.from(this._sourceHolds[playerId].entries())) {
        for (const source of Array.from(sources)) {
          if (source.startsWith('gamepad:') && !seen.has(source)) {
            this.setUp(action, playerId, source);
          }
        }
      }
    }
  }

  /** Action is being held this frame. */
  isDown(action, playerId = 0) {
    return this._down[playerId].has(action);
  }

  /** Action transitioned from up→down this frame. */
  wasPressed(action, playerId = 0) {
    return this._pressedThisFrame[playerId].has(action);
  }

  /** Action transitioned from down→up this frame. */
  wasReleased(action, playerId = 0) {
    return this._releasedThisFrame[playerId].has(action);
  }

  /**
   * Recent action sequence within the buffer window (oldest → newest).
   * Use this to detect special-move motions like quarter-circle-forward + punch.
   */
  recentSequence(playerId = 0, now = performance.now()) {
    const buf = this._buffer[playerId];
    return buf.filter((e) => now - e.t <= BUFFER_MS).map((e) => e.action);
  }

  /**
   * Was the given action pressed within the last `withinMs` milliseconds?
   * Useful for "press-both-near-simultaneously" detection (throws).
   */
  recentlyPressed(action, playerId = 0, withinMs = 80, now = performance.now()) {
    const buf = this._buffer[playerId];
    for (let i = buf.length - 1; i >= 0; i--) {
      if (now - buf[i].t > withinMs) return false;
      if (buf[i].action === action) return true;
    }
    return false;
  }

  /**
   * Call once per frame AFTER all game systems have read input. Clears
   * per-frame edge flags and trims the stale tail of the combo buffer.
   */
  endFrame() {
    const now = performance.now();
    for (let i = 0; i < 2; i++) {
      this._pressedThisFrame[i].clear();
      this._releasedThisFrame[i].clear();
      const buf = this._buffer[i];
      while (buf.length > 0 && now - buf[0].t > BUFFER_MS) buf.shift();
    }
  }

  dispose() {
    this.target.removeEventListener('keydown', this._onKeyDown);
    this.target.removeEventListener('keyup', this._onKeyUp);
  }
}
