/**
 * _inputMaps.js — Shared input -> move-id mapping for ground states.
 */
const ATTACK_BINDINGS = [
  ['punch_light', 'punch_light'],
  ['punch_medium', 'punch_medium'],
  ['punch_heavy', 'punch_heavy'],
  ['kick_light', 'kick_light'],
  ['kick_medium', 'kick_medium'],
  ['kick_heavy', 'kick_heavy'],
];

export function resolveAttackInput(input, fighter) {
  for (const [action, moveId] of ATTACK_BINDINGS) {
    if (input.wasPressed(action, fighter.playerId)) return moveId;
  }
  return null;
}

export function resolveBlockInput(input, fighter) {
  return input.isDown('block', fighter.playerId);
}

export function resolveDaavInput(input, fighter) {
  const pid = fighter.playerId;

  if (input.wasPressed('throw', pid)) {
    return fighter.character?.signatureDaav ?? 'daav_normal';
  }

  const lpPressed = input.wasPressed('punch_light', pid);
  const lkPressed = input.wasPressed('kick_light', pid);

  if (lpPressed && input.recentlyPressed?.('kick_light', pid, 80)) {
    return fighter.character?.signatureDaav ?? 'daav_normal';
  }
  if (lkPressed && input.recentlyPressed?.('punch_light', pid, 80)) {
    return fighter.character?.signatureDaav ?? 'daav_normal';
  }
  return null;
}

/**
 * Shoryuken — fired by either the dedicated button (B / Numpad 9) or by
 * DP motion (forward + down + heavy punch within ~280ms).
 */
export function resolveShoryukenInput(input, fighter) {
  const pid = fighter.playerId;

  if (input.wasPressed('shoryuken', pid)) {
    return fighter.character?.signatureShoryuken ?? 'shoryuken_normal';
  }

  if (!input.wasPressed('punch_heavy', pid)) return null;
  const forwardKey = fighter.facing === 1 ? 'right' : 'left';
  const sawForward = input.recentlyPressed?.(forwardKey, pid, 280);
  const sawDown    = input.recentlyPressed?.('down',     pid, 280);
  if (sawForward && sawDown) {
    return fighter.character?.signatureShoryuken ?? 'shoryuken_normal';
  }
  return null;
}
