import * as THREE from 'three';

/**
 * Renderer
 * --------
 * Thin wrapper around THREE.WebGLRenderer + a side-view PerspectiveCamera
 * tuned for a 2.5D fighting game.
 *
 * Conventions for the game world:
 *   +X = player 1's "forward" direction (rightward on screen)
 *   +Y = up
 *   +Z = toward the camera (camera sits on +Z, looks down -Z)
 *
 * Fighters live on the Z = 0 plane; the camera looks at them from +Z so the
 * action plays out on the screen-aligned XY plane (classic Street Fighter view).
 */
export class Renderer {
  /**
   * @param {HTMLCanvasElement} canvas
   */
  constructor(canvas) {
    this.canvas = canvas;

    this.renderer = new THREE.WebGLRenderer({
      canvas,
      antialias: true,
      powerPreference: 'high-performance',
    });
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.renderer.toneMapping = THREE.ACESFilmicToneMapping;
    this.renderer.toneMappingExposure = 1.0;
    this.renderer.shadowMap.enabled = true;
    this.renderer.shadowMap.type = THREE.PCFSoftShadowMap;

    // Side-view camera. 35° FOV gives a slight telephoto feel that flatters
    // characters and matches the look of SFIV / KOFXV.
    this.camera = new THREE.PerspectiveCamera(35, 1, 0.1, 100);
    this.camera.position.set(0, 1.6, 7.5);
    this.camera.lookAt(0, 1.2, 0);

    this._handleResize = this._handleResize.bind(this);
    window.addEventListener('resize', this._handleResize);
    this._handleResize();
  }

  /** Resize the renderer + camera to fill the canvas's display size. */
  _handleResize() {
    const { clientWidth, clientHeight } = this.canvas;
    const width = Math.max(1, clientWidth);
    const height = Math.max(1, clientHeight);
    this.renderer.setSize(width, height, false);
    this.camera.aspect = width / height;
    this.camera.updateProjectionMatrix();
  }

  /**
   * Draw a scene from this renderer's camera.
   * @param {THREE.Scene} scene
   */
  render(scene) {
    this.renderer.render(scene, this.camera);
  }

  dispose() {
    window.removeEventListener('resize', this._handleResize);
    this.renderer.dispose();
  }
}
