/**
 * Settings
 * --------
 * Player-facing preferences (audio, controls, quality). Persisted to
 * localStorage so settings survive between sessions and across the Capacitor
 * Android WebView.
 *
 * Anything in here is safe to expose in the Settings UI. Anything that should
 * not be user-tunable belongs elsewhere.
 */

const STORAGE_KEY = 'dsf.settings.v1';

const DEFAULTS = Object.freeze({
  // Audio volumes are normalised 0..1. Defaults match ProceduralAudio's
  // hand-tuned defaults so the player hears the same thing first launch.
  masterVolume: 0.55,
  musicVolume:  0.00,
  sfxVolume:    0.80,
  voiceVolume:  0.80, // reserved for Phase 11 voice lines

  // UI
  touchControlsVisible: 'auto', // 'auto' | 'on' | 'off'
  qualityPreset:        'high', // 'low' | 'medium' | 'high'

  // Match — who controls player 2.
  //   'human'      → P2 reads keyboard (arrows + numpad) and/or Gamepad 2
  //   'cpu_easy'   → AI on easy difficulty
  //   'cpu_medium' → AI on medium difficulty (default)
  //   'cpu_hard'   → AI on hard difficulty
  p2Mode: 'cpu_medium',

  // Localisation (Phase 12)
  language: 'en',
});

function readStored() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === 'object' ? parsed : {};
  } catch {
    return {};
  }
}

function writeStored(value) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(value));
  } catch {
    /* private mode, quota, etc. — fail silently */
  }
}

export class Settings {
  constructor() {
    this._values = { ...DEFAULTS, ...readStored() };
    /** @type {Set<(s: Settings) => void>} */
    this._listeners = new Set();
  }

  get(key) {
    return this._values[key];
  }

  set(key, value) {
    if (this._values[key] === value) return;
    this._values[key] = value;
    writeStored(this._values);
    this._notify();
  }

  /** Bulk update without notifying for each individual change. */
  setMany(patch) {
    let changed = false;
    for (const [k, v] of Object.entries(patch)) {
      if (this._values[k] !== v) {
        this._values[k] = v;
        changed = true;
      }
    }
    if (changed) {
      writeStored(this._values);
      this._notify();
    }
  }

  /** Reset to defaults. */
  reset() {
    this._values = { ...DEFAULTS };
    writeStored(this._values);
    this._notify();
  }

  /** Subscribe to any settings change. Returns an unsubscribe function. */
  subscribe(listener) {
    this._listeners.add(listener);
    return () => this._listeners.delete(listener);
  }

  _notify() {
    for (const cb of this._listeners) {
      try { cb(this); } catch { /* listener errors must not break the loop */ }
    }
  }

  /** Snapshot of current values (read-only). */
  snapshot() {
    return Object.freeze({ ...this._values });
  }

  static get DEFAULTS() { return DEFAULTS; }
}
