/**
 * branding.js
 * -----------
 * Single source of truth for store-facing brand metadata.
 *
 * Two store names ship in parallel:
 *
 *   - Google Play: "Desi Street Fighter"   (com.desistreetfighter.game)
 *   - Microsoft Store: "Desi Street Brawler" (com.desistreetbrawler.windows)
 *
 * The build picks one by setting `VITE_BUILD_TARGET=play` or
 * `VITE_BUILD_TARGET=store` at `vite build` time. Default is "play".
 *
 * Anywhere a title/byline string appears (boot overlay, HUD splash, pause
 * menu, settings header, win screen), read from BRANDING — never hard-code.
 */

const TARGETS = {
  play: {
    target:        'play',
    displayName:   'Desi Street Fighter',
    shortName:     'Desi SF',
    tagline:       'A 2.5D Lollywood fighter',
    packageId:     'com.desistreetfighter.game',
    storeName:     'Google Play',
    supportEmail:  'support@desistreetfighter.com',
    privacyUrl:    'https://desistreetfighter.com/privacy',
  },
  store: {
    target:        'store',
    displayName:   'Desi Street Brawler',
    shortName:     'Desi Brawler',
    tagline:       'A Pakistani 2.5D action brawler',
    packageId:     'com.desistreetbrawler.windows',
    storeName:     'Microsoft Store',
    supportEmail:  'netsamabdus@gmail.com',
    privacyUrl:    'https://netsammy.github.io/DesiStreetFighterV2/privacy.html',
  },
};

// Resolve target from Vite env var (set at build time) or fall back to play.
const ENV_TARGET = (import.meta.env?.VITE_BUILD_TARGET ?? 'play').toLowerCase();
const RESOLVED = TARGETS[ENV_TARGET] ?? TARGETS.play;

export const BRANDING = Object.freeze(RESOLVED);

/** Convenience: also expose the raw targets so dev tools can preview the other build. */
export const BRANDING_TARGETS = Object.freeze(TARGETS);
