/**
 * SyntheticInput
 * --------------
 * A drop-in input source that mimics the public surface of `Input` but is
 * driven by an AI controller instead of the keyboard.
 *
 * The Fighter / state machine reads inputs the same way regardless of
 * whether the player is a human pressing keys or an AI calling `set()`
 * each frame. That symmetry means we don't fork combat logic for
 * human-vs-AI — same FSM, same physics, same hit resolution.
 *
 * Lifecycle per frame:
 *   1. AI controller decides which actions are held / newly pressed
 *      and calls `set(held, pressed)`. New presses are auto-detected
 *      by comparing `held` against the previous frame too, so AI code
 *      can just say "walk right" and the state machine sees both
 *      `isDown('right')` and `wasPressed('right')` on the first frame.
 *   2. Fighter.update reads via stateMachine.update -> states.
 *   3. main loop calls `endFrame()` to clear the pressed-this-frame edges,
 *      symmetric with how the keyboard Input class behaves.
 */
export class SyntheticInput {
  constructor() {
    this._held = new Set();
    this._pressedThisFrame = new Set();
  }

  /** @param {string} action @param {number} [_playerId] ignored — synthetic input is per-fighter */
  isDown(action, _playerId) {
    return this._held.has(action);
  }

  wasPressed(action, _playerId) {
    return this._pressedThisFrame.has(action);
  }

  /** Not used by current states, but present for API parity. */
  wasReleased(_action, _playerId) {
    return false;
  }

  /** Buffer / combo motion API parity (not yet used by AI). */
  recentSequence() {
    return [];
  }

  /**
   * Set the AI's intent for this frame.
   * @param {Iterable<string>} held    - actions to be considered "held"
   * @param {Iterable<string>} pressed - explicit one-shot presses this frame
   */
  set(held, pressed) {
    const nextHeld = new Set(held);
    const presses = new Set(pressed);
    // Auto-detect press edges: anything newly added to held this frame
    // counts as wasPressed too.
    for (const a of nextHeld) {
      if (!this._held.has(a)) presses.add(a);
    }
    this._pressedThisFrame = presses;
    this._held = nextHeld;
  }

  endFrame() {
    this._pressedThisFrame.clear();
  }
}
