/**
 * HitState
 * --------
 * Brief stun after taking an unblocked hit. Duration + low/high clip
 * supplied via payload from Fighter.takeHit.
 */
export const HitState = {
  name: 'hit',

  enter(fighter, _prev, payload = {}) {
    this._stun = payload.stun ?? 0.3;
    this._elapsed = 0;
    fighter.velocity.x *= 0.5; // some knockback carries through
    fighter.playClip(payload.low ? 'hit_low' : 'hit_high', { loop: false, fade: 0.04 });
  },

  update(dt, _input, _fighter) {
    this._elapsed += dt;
    if (this._elapsed >= this._stun) return 'idle';
    return null;
  },
};
