/**
 * ThrownState
 * -----------
 * Defender state when caught in a daav. For V1 this uses a compact,
 * grounded throw presentation: slide to the opposite side, then knock down.
 * Keeping the victim grounded avoids rig-specific floating/sinking issues.
 */
export const ThrownState = {
  name: 'thrown',

  enter(fighter, _prev, payload = {}) {
    fighter.position.y = 0;
    fighter.velocity.y = 0;
    fighter.isGrounded = true;
    fighter.visualOffsetY = 0;
    fighter.forceVisualGrounding = true;
    this._t = 0;
    this._duration = payload.duration ?? 0.42;
    this._startX = payload.startX ?? fighter.position.x;
    this._targetX = payload.targetX ?? null;
    this._initialVel = payload.slideBack ?? fighter.velocity.x;
    this._visualDrop = payload.visualDrop ?? 0;
    this._arcHeight = payload.arcHeight ?? 0;
    this._knockdownVisualOffset = payload.knockdownVisualOffset ?? 0;
    fighter.position.x = this._startX;
    if (this._targetX != null) {
      fighter.velocity.x = 0;
    } else if (payload.slideBack != null) {
      fighter.velocity.x = payload.slideBack;
    }
    fighter.playClip(payload.thrownAnimation ?? 'knockdown', {
      loop: false,
      fade: 0.025,
      timeScale: payload.thrownTimeScale ?? 1.15,
      animationStart: payload.thrownAnimationStart ?? 0,
    });
  },

  update(dt, _input, fighter) {
    this._t += dt;
    const progress = Math.min(1, this._t / this._duration);
    const smooth = progress * progress * (3 - 2 * progress);
    if (this._targetX != null) {
      fighter.position.x = this._startX + (this._targetX - this._startX) * smooth;
      fighter.velocity.x = 0;
    } else {
      const k = Math.max(0, 1 - progress);
      fighter.velocity.x = this._initialVel * k;
    }
    fighter.position.y = 0;
    fighter.velocity.y = 0;
    fighter.isGrounded = true;
    const lift = Math.sin(progress * Math.PI) * this._arcHeight;
    const drop = this._visualDrop * smooth;
    fighter.visualOffsetY = Math.min(0, lift + drop);
    if (this._t >= this._duration) {
      if (this._targetX != null) fighter.position.x = this._targetX;
      fighter.position.y = 0;
      fighter.velocity.x = 0;
      fighter.velocity.y = 0;
      fighter.isGrounded = true;
      fighter.visualOffsetY = 0;
      return {
        next: 'knockdown',
        payload: {
          fromThrow: true,
          visualOffset: this._knockdownVisualOffset,
        },
      };
    }
    return null;
  },

  exit(fighter, next) {
    if (this._targetX != null) fighter.position.x = this._targetX;
    fighter.visualOffsetY = 0;
    if (next !== 'knockdown') fighter.forceVisualGrounding = false;
    fighter.position.y = 0;
    fighter.velocity.y = 0;
    fighter.isGrounded = true;
  },
};
