import { SyntheticInput } from '../engine/SyntheticInput.js';

/**
 * MatchController
 * ---------------
 * Drives the match-level state machine that sits on top of per-fighter
 * combat:
 *
 *   round_intro  -> banner shows "Round N", then "FIGHT!"; inputs locked
 *   fighting     -> combat lives; timer counts down
 *   round_ko     -> winner declared; victory/defeat clips play; brief pause
 *   round_reset  -> fighters reset to spawn; HP refilled
 *   match_end    -> banner shows match winner; waits for player choice
 *
 * The controller exposes:
 *   - isCombatActive()  — only true during 'fighting'
 *   - isInputLocked()   — true except during 'fighting'
 *   - state, round, roundsWon[], roundTime, etc. — for HUD reads
 *   - noopInput         — a SyntheticInput with no held/pressed, fed to
 *                          fighters while input is locked
 */

const ROUND_TIME = 99;        // seconds per round
const INTRO_DURATION = 2.4;   // total intro screen duration
const FIGHT_FLASH = 0.9;      // "FIGHT!" flashes during the second half of intro
const KO_PAUSE = 3.2;         // beat after a K.O. before reset
const RESET_PAUSE = 0.6;      // brief blank between rounds
const MATCH_END_PAUSE = 1.2;  // delay before showing post-match menu
const WINS_TO_TAKE = 2;        // best-of-3 (first to 2 round wins)

export class MatchController {
  /**
   * @param {object} opts
   * @param {Array<import('./Fighter.js').Fighter>} opts.fighters  - [p1, p2]
   * @param {{setBanner: Function}} opts.hud                       - banner emitter
   * @param {(result: object) => void} [opts.onMatchEnd]            - called once when the match is over
   */
  constructor({ fighters, hud, onMatchEnd = null }) {
    this.fighters = fighters;
    this.hud = hud;
    this.onMatchEnd = onMatchEnd;

    this.state = 'round_intro';
    this.round = 1;
    this.maxRounds = 3;
    this.roundsWon = [0, 0];
    this.roundTime = ROUND_TIME;
    this.stateTimer = INTRO_DURATION;

    this.roundWinnerIdx = -1;
    this.matchWinnerIdx = -1;
    this._matchEndNotified = false;

    /** A fixed empty input we feed fighters while combat is paused. */
    this.noopInput = new SyntheticInput();
    this.noopInput.set([], []);

    this._fightShown = false;
    this._showBanner(`Round ${this.round}`, INTRO_DURATION * 0.55);
  }

  /** Per-frame update. Returns nothing; reads/writes fighter state. */
  update(dt) {
    this.stateTimer -= dt;

    switch (this.state) {
      case 'round_intro':
        // After the round-number banner, flash "FIGHT!" for the remainder.
        if (!this._fightShown && this.stateTimer <= FIGHT_FLASH) {
          this._fightShown = true;
          this._showBanner('FIGHT!', FIGHT_FLASH * 1000);
        }
        if (this.stateTimer <= 0) {
          this.state = 'fighting';
          this.roundTime = ROUND_TIME;
        }
        break;

      case 'fighting':
        this.roundTime -= dt;
        // Detect KO via HP.
        for (let i = 0; i < 2; i++) {
          if (this.fighters[i].hp <= 0) {
            this._endRound(1 - i);
            return;
          }
        }
        // Time out.
        if (this.roundTime <= 0) {
          this.roundTime = 0;
          const [a, b] = this.fighters;
          let winnerIdx;
          if (a.hp > b.hp) winnerIdx = 0;
          else if (b.hp > a.hp) winnerIdx = 1;
          else winnerIdx = -1;
          this._endRound(winnerIdx, true);
        }
        break;

      case 'round_ko':
        if (this.stateTimer <= 0) {
          // Match over?
          if (
            this.roundsWon[0] >= WINS_TO_TAKE ||
            this.roundsWon[1] >= WINS_TO_TAKE
          ) {
            this._endMatch();
          } else {
            this._beginRoundReset();
          }
        }
        break;

      case 'round_reset':
        if (this.stateTimer <= 0) this._beginRoundIntro();
        break;

      case 'match_end':
        if (this.stateTimer <= 0 && !this._matchEndNotified) {
          this._matchEndNotified = true;
          this.onMatchEnd?.(this.getResult());
        }
        break;
    }
  }

  isCombatActive() {
    return this.state === 'fighting';
  }

  isInputLocked() {
    return this.state !== 'fighting';
  }

  // -------------------------------------------------------------------------
  // Internal transitions
  // -------------------------------------------------------------------------

  _endRound(winnerIdx, timeOut = false) {
    this.state = 'round_ko';
    this.stateTimer = KO_PAUSE;
    this.roundWinnerIdx = winnerIdx;

    if (winnerIdx >= 0) {
      this.roundsWon[winnerIdx]++;
      const winnerName = this.fighters[winnerIdx].character.name;
      const tag = timeOut ? 'TIME OUT' : 'K.O.';
      this._showBanner(`${tag} — ${winnerName}`, KO_PAUSE * 1000);
      // Play victory clip on the winner if it isn't already in KO somehow.
      const winner = this.fighters[winnerIdx];
      if (winner.stateMachine.currentName !== 'ko') {
        winner.playClip('victory', { loop: false, fade: 0.2 });
      }
      // Loser should already be in 'ko' via Fighter.takeHit; if a timeout
      // ended the round with both alive, force the loser into defeat.
      const loser = this.fighters[1 - winnerIdx];
      if (loser.stateMachine.currentName !== 'ko' && timeOut) {
        loser.playClip('defeat', { loop: false, fade: 0.2 });
      }
    } else {
      this._showBanner('TIME OUT — DRAW', KO_PAUSE * 1000);
    }
  }

  _beginRoundReset() {
    this.state = 'round_reset';
    this.stateTimer = RESET_PAUSE;
    this._resetFighters();
  }

  _beginRoundIntro() {
    this.round++;
    this.state = 'round_intro';
    this.stateTimer = INTRO_DURATION;
    this._fightShown = false;
    this._showBanner(`Round ${this.round}`, INTRO_DURATION * 0.55 * 1000);
  }

  _resetFighters() {
    for (let i = 0; i < 2; i++) {
      const f = this.fighters[i];
      f.hp = f.maxHp;
      f.position.x = i === 0 ? -1.6 : 1.6;
      f.position.y = 0;
      f.velocity.x = 0;
      f.velocity.y = 0;
      f.facing = i === 0 ? 1 : -1;
      f.isGrounded = true;
      f._currentAttack = null;
      f.refillHadoken?.();
      f._projectiles?.clear?.();
      f.stateMachine.change('idle');
    }
  }

  _endMatch() {
    this.state = 'match_end';
    this.stateTimer = MATCH_END_PAUSE;
    this.matchWinnerIdx =
      this.roundsWon[0] >= WINS_TO_TAKE ? 0 : 1;
    const winnerName = this.fighters[this.matchWinnerIdx].character.name;
    this._showBanner(`${winnerName} WINS THE MATCH`, 4200);
  }

  getResult() {
    return {
      winnerIdx: this.matchWinnerIdx,
      loserIdx: this.matchWinnerIdx === 0 ? 1 : 0,
      winnerName: this.matchWinnerIdx >= 0
        ? this.fighters[this.matchWinnerIdx].character.name
        : '',
      loserName: this.matchWinnerIdx >= 0
        ? this.fighters[this.matchWinnerIdx === 0 ? 1 : 0].character.name
        : '',
      roundsWon: [...this.roundsWon],
      round: this.round,
      bestOf: 3,
      winsToTake: WINS_TO_TAKE,
    };
  }

  _showBanner(text, durationMs) {
    this.hud?.setBanner?.(text, durationMs);
  }
}
