/**
 * KnockdownState
 * --------------
 * Floored. Plays knockdown clip, then get_up, then returns to idle. The
 * fighter cannot be hit again while down (invulnerable wake-up frames are
 * configured here in Phase 4).
 */
export const KnockdownState = {
  name: 'knockdown',

  enter(fighter, _prev, payload = {}) {
    this._phase = 'down';
    this._timer = 0.8;
    this._downDuration = this._timer;
    this._fromThrow = !!payload.fromThrow;
    this._throwVisualOffset = this._fromThrow
      ? (payload.visualOffset ?? 0)
      : (payload.visualOffset ?? -0.42);
    fighter.position.y = 0;
    fighter.velocity.y = 0;
    fighter.isGrounded = true;
    fighter.visualOffsetY = this._fromThrow ? this._throwVisualOffset : 0;
    fighter.forceVisualGrounding = this._fromThrow;
    fighter.playClip('knockdown', { loop: false });
  },

  update(dt, _input, fighter) {
    fighter.position.y = 0;
    fighter.velocity.y = 0;
    fighter.isGrounded = true;
    this._timer -= dt;
    if (this._phase === 'down') {
      if (this._fromThrow) {
        fighter.visualOffsetY = this._throwVisualOffset;
      } else {
        const progress = Math.min(1, Math.max(0, 1 - this._timer / this._downDuration));
        const fallProgress = Math.min(1, Math.max(0, (progress - 0.34) / 0.42));
        const smoothFall = fallProgress * fallProgress * (3 - 2 * fallProgress);
        fighter.visualOffsetY = this._throwVisualOffset * smoothFall;
      }
    }
    if (this._phase === 'down' && this._timer <= 0) {
      this._phase = 'getup';
      this._timer = 0.6;
      fighter.visualOffsetY = 0;
      fighter.forceVisualGrounding = false;
      fighter.playClip('get_up', { loop: false });
    } else if (this._phase === 'getup' && this._timer <= 0) {
      return 'idle';
    }
    return null;
  },

  exit(fighter) {
    fighter.visualOffsetY = 0;
    fighter.forceVisualGrounding = false;
    fighter.position.y = 0;
    fighter.velocity.y = 0;
    fighter.isGrounded = true;
  },
};
