import { MOVES } from '../../data/moves.js';

const MIN_ATTACK_ANIM_SCALE = 1;
const MAX_ATTACK_ANIM_SCALE = 7.5;
const DEFAULT_NORMAL_FADE = 0.02;

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function getAttackAnimOptions(fighter, move, totalFrames) {
  const moveSeconds = Math.max(1 / 60, totalFrames / 60);
  const clip = fighter.getClip?.(move.animation, move.animationFallbacks);
  const fitToMove = move.animationFit !== false;
  const maxScale = move.animationMaxScale ?? MAX_ATTACK_ANIM_SCALE;
  const fitScale = fitToMove && clip
    ? clamp(clip.duration / moveSeconds, MIN_ATTACK_ANIM_SCALE, MAX_ATTACK_ANIM_SCALE)
    : (move.animationTimeScale ?? 1);
  const timeScale = clamp(
    fitScale * (move.animationSpeedMultiplier ?? 1),
    MIN_ATTACK_ANIM_SCALE,
    maxScale,
  );

  return {
    fade: move.animationFade ?? DEFAULT_NORMAL_FADE,
    timeScale,
    animationStart: move.animationStart ?? 0,
    fallbackNames: move.animationFallbacks ?? [],
  };
}

/**
 * AttackState
 * -----------
 * Plays one attack start-to-finish. Move data from moves.js drives the
 * frame timings (60 fps reference). The hitbox is "active" only inside
 * the active-frames window; before is startup, after is recovery.
 *
 * payload: { moveId: string }
 */
export const AttackState = {
  name: 'attack',

  enter(fighter, _prev, payload = {}) {
    const move = MOVES[payload.moveId] ?? MOVES.punch_light;
    this._move = move;
    this._frame = 0;
    this._total = (move.startup ?? 5) + (move.active ?? 3) + (move.recovery ?? 8);
    this._hasHit = false;

    // Live attack handle Fighter.activeHitboxes() reads from.
    // We use a getter so the state can flip hasHit after the resolver
    // calls markHit().
    const self = this;
    fighter._currentAttack = {
      move,
      frame: 0,
      isActive: false,
      get hasHit() { return self._hasHit; },
    };

    fighter.velocity.x = 0;
    fighter.playClip(move.animation, {
      loop: false,
      ...getAttackAnimOptions(fighter, move, this._total),
    });
  },

  update(dt, _input, fighter) {
    this._frame += dt * 60;
    const m = this._move;
    const activeStart = m.startup ?? 0;
    const activeEnd = activeStart + (m.active ?? 0);

    if (fighter._currentAttack) {
      fighter._currentAttack.frame = this._frame;
      fighter._currentAttack.isActive =
        this._frame >= activeStart && this._frame < activeEnd && !this._hasHit;
    }

    if (this._frame >= this._total) return 'idle';
    return null;
  },

  /** Called by the combat resolver in main.js when this attack lands. */
  markHit(fighter) {
    this._hasHit = true;
    if (fighter && fighter._currentAttack) fighter._currentAttack.isActive = false;
  },

  exit(fighter, _next) {
    fighter._currentAttack = null;
  },
};
