import { Capacitor } from '@capacitor/core';
import { AdMob, MaxAdContentRating } from '@capacitor-community/admob';

const REWARD_AMOUNT = 50;
const REWARD_ITEM = 'Coins';

const TEST_ADS = Object.freeze({
  rewardedCoins: 'ca-app-pub-3940256099942544/5224354917',
  postMatchInterstitial: 'ca-app-pub-3940256099942544/1033173712',
});

const PRODUCTION_ADS = Object.freeze({
  appId: 'ca-app-pub-1797269464593835~5850402093',
  rewardedCoins: 'ca-app-pub-1797269464593835/3982786659',
  postMatchInterstitial: 'ca-app-pub-1797269464593835/2669704983',
});

const USE_LIVE_ADS = import.meta.env?.VITE_ADMOB_LIVE_ADS === 'true';
const INTERSTITIAL_COOLDOWN_MS = 3 * 60 * 1000;

export class AdMobService {
  constructor() {
    this._initialized = false;
    this._initializing = null;
    this._lastInterstitialAt = Date.now();
    this._native = Capacitor.isNativePlatform();
    this._adIds = USE_LIVE_ADS ? PRODUCTION_ADS : TEST_ADS;
  }

  get isNative() {
    return this._native;
  }

  get usingLiveAds() {
    return USE_LIVE_ADS;
  }

  get rewardAmount() {
    return REWARD_AMOUNT;
  }

  get rewardItem() {
    return REWARD_ITEM;
  }

  async initialize() {
    if (!this._native) {
      this._initialized = true;
      return { native: false, testing: true };
    }
    if (this._initialized) return { native: true, testing: !USE_LIVE_ADS };
    if (this._initializing) return this._initializing;

    this._initializing = (async () => {
      await AdMob.initialize({
        initializeForTesting: !USE_LIVE_ADS,
        maxAdContentRating: MaxAdContentRating.Teen,
      });
      await AdMob.setApplicationMuted({ muted: false });
      this._initialized = true;
      return { native: true, testing: !USE_LIVE_ADS };
    })().catch((err) => {
      this._initializing = null;
      console.warn('[ads] AdMob initialization failed', err);
      throw err;
    });

    return this._initializing;
  }

  async showRewardedCoins() {
    await this.initialize();

    if (!this._native) {
      return {
        amount: REWARD_AMOUNT,
        type: REWARD_ITEM,
        simulated: true,
      };
    }

    const options = {
      adId: this._adIds.rewardedCoins,
      isTesting: !USE_LIVE_ADS,
      immersiveMode: true,
    };
    await AdMob.prepareRewardVideoAd(options);
    const reward = await AdMob.showRewardVideoAd();
    return {
      amount: Number(reward?.amount) || REWARD_AMOUNT,
      type: reward?.type || REWARD_ITEM,
      simulated: false,
    };
  }

  async showPostMatchInterstitial() {
    await this.initialize();

    const now = Date.now();
    if (!this._native) return { shown: false, reason: 'browser' };
    if (now - this._lastInterstitialAt < INTERSTITIAL_COOLDOWN_MS) {
      return { shown: false, reason: 'cooldown' };
    }

    this._lastInterstitialAt = now;
    const options = {
      adId: this._adIds.postMatchInterstitial,
      isTesting: !USE_LIVE_ADS,
      immersiveMode: true,
    };
    await AdMob.prepareInterstitial(options);
    await AdMob.showInterstitial();
    return { shown: true };
  }
}

export const ADMOB_PRODUCTION_IDS = PRODUCTION_ADS;
