/**
 * PauseMenu
 * ---------
 * Mid-match pause overlay + settings sub-screen.
 *
 * Behaviour:
 *   - ESC (keyboard) or the on-screen ⏸ button toggles the menu.
 *   - When open, the engine's frame loop checks `pauseMenu.isPaused()` and
 *     skips the game update — but rendering continues so the frame underneath
 *     is visible.
 *   - Settings panel writes through the Settings store, which persists to
 *     localStorage and notifies subscribers (so audio gains update live).
 *
 * Screens:
 *   - 'pause':    Resume / Restart / Controls / Settings / Quit
 *   - 'controls': Keyboard, touch, gamepad, and special-move reference
 *   - 'settings': Audio sliders, touch toggle, quality preset, Back
 *   - 'privacy':  Local privacy and ad disclosure summary
 */

const PANEL_STYLE = `
  position: absolute;
  inset: 0;
  background: rgba(8, 6, 4, 0.78);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  display: none;
  align-items: center;
  justify-content: center;
  flex-direction: column;
  padding: 16px;
  overflow-y: auto;
  z-index: 30;
  pointer-events: auto;
  font-family: 'Segoe UI', system-ui, sans-serif;
  color: #f5e9c9;
  user-select: none;
  -webkit-user-select: none;
`;

const CARD_STYLE = `
  background: linear-gradient(180deg, rgba(40, 22, 8, 0.96), rgba(20, 12, 6, 0.96));
  border: 2px solid #c79b3a;
  border-radius: 14px;
  padding: 28px 36px;
  min-width: 320px;
  max-width: 480px;
  max-height: calc(100vh - 32px);
  overflow-y: auto;
  box-shadow: 0 10px 40px rgba(0,0,0,0.6), inset 0 1px 0 rgba(255,255,255,0.05);
`;

const TITLE_STYLE = `
  font-size: 22px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: #ffd770;
  text-align: center;
  margin: 0 0 18px 0;
  text-shadow: 0 2px 4px rgba(0,0,0,0.6);
`;

const BUTTON_STYLE = `
  display: block;
  width: 100%;
  margin: 8px 0;
  padding: 12px 16px;
  font-size: 16px;
  font-weight: 600;
  letter-spacing: 0.04em;
  background: linear-gradient(180deg, #2a1a0c, #1a0f06);
  color: #f5e9c9;
  border: 1.5px solid #c79b3a;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.12s ease, transform 0.05s ease;
  font-family: inherit;
`;

const ROW_STYLE = `
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin: 10px 0;
  gap: 16px;
`;

const LABEL_STYLE = `
  font-size: 14px;
  font-weight: 600;
  letter-spacing: 0.05em;
  color: #f5e9c9;
  flex-shrink: 0;
  min-width: 110px;
`;

const PAUSE_BUTTON_STYLE = `
  position: absolute;
  top: 14px;
  right: 14px;
  width: 38px;
  height: 38px;
  background: rgba(20, 12, 6, 0.7);
  border: 2px solid #c79b3a;
  border-radius: 8px;
  color: #ffd770;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  pointer-events: auto;
  z-index: 20;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: inherit;
`;

export class PauseMenu {
  /**
   * @param {object} opts
   * @param {HTMLElement} opts.host           - DOM element (#ui-root)
   * @param {import('../engine/Settings.js').Settings} opts.settings
   * @param {{displayName: string}} opts.branding
   * @param {() => void} [opts.onRestart]     - called when user picks Restart
   * @param {() => void} [opts.onQuit]        - called when user picks Quit
   */
  constructor({ host, settings, branding, onRestart, onQuit }) {
    this.host = host;
    this.settings = settings;
    this.branding = branding;
    this.onRestart = onRestart || (() => {});
    this.onQuit = onQuit || (() => {});

    this._paused = false;
    this._screen = 'pause'; // 'pause' | 'controls' | 'settings' | 'privacy'

    this._buildDom();
    this._bindHotkeys();
  }

  // -- Public API ---------------------------------------------------------

  isPaused() { return this._paused; }

  pause() {
    if (this._paused) return;
    this._paused = true;
    this._screen = 'pause';
    this._render();
    this.panel.style.display = 'flex';
  }

  resume() {
    if (!this._paused) return;
    this._paused = false;
    this.panel.style.display = 'none';
  }

  toggle() {
    this._paused ? this.resume() : this.pause();
  }

  // -- DOM build ----------------------------------------------------------

  _buildDom() {
    // On-screen pause button (always visible)
    this.pauseButton = document.createElement('button');
    this.pauseButton.textContent = '⏸';
    this.pauseButton.style.cssText = PAUSE_BUTTON_STYLE;
    this.pauseButton.setAttribute('aria-label', 'Pause');
    this.pauseButton.addEventListener('click', (e) => {
      e.preventDefault();
      this.toggle();
    });
    this.host.appendChild(this.pauseButton);

    // Full-screen panel
    this.panel = document.createElement('div');
    this.panel.id = 'pause-menu';
    this.panel.style.cssText = PANEL_STYLE;

    this.card = document.createElement('div');
    this.card.style.cssText = CARD_STYLE;
    this.panel.appendChild(this.card);

    this.host.appendChild(this.panel);
  }

  // -- Render -------------------------------------------------------------

  _render() {
    this.card.innerHTML = '';

    if (this._screen === 'pause') {
      this._renderPauseScreen();
    } else if (this._screen === 'controls') {
      this._renderControlsScreen();
    } else if (this._screen === 'settings') {
      this._renderSettingsScreen();
    } else if (this._screen === 'privacy') {
      this._renderPrivacyScreen();
    }
  }

  _renderPauseScreen() {
    this.card.style.maxWidth = '480px';

    const title = document.createElement('h2');
    title.textContent = 'Paused';
    title.style.cssText = TITLE_STYLE;
    this.card.appendChild(title);

    const subtitle = document.createElement('div');
    subtitle.textContent = this.branding.displayName;
    subtitle.style.cssText = 'font-size:12px;letter-spacing:0.18em;text-transform:uppercase;color:#c79b3a;text-align:center;margin:-10px 0 18px 0;';
    this.card.appendChild(subtitle);

    this._addButton('Resume', () => this.resume());
    this._addButton('Restart Match', () => {
      this.resume();
      this.onRestart();
    });
    this._addButton('Controls / Moves', () => {
      this._screen = 'controls';
      this._render();
    });
    this._addButton('Settings', () => {
      this._screen = 'settings';
      this._render();
    });
    this._addButton('Privacy & Ads', () => {
      this._screen = 'privacy';
      this._render();
    });
    this._addButton('Quit to Menu', () => {
      this.resume();
      this.onQuit();
    });
  }

  _renderControlsScreen() {
    this.card.style.maxWidth = '720px';

    const title = document.createElement('h2');
    title.textContent = 'Controls';
    title.style.cssText = TITLE_STYLE;
    this.card.appendChild(title);

    const grid = document.createElement('div');
    grid.style.cssText = `
      display:grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 18px 24px;
      font-size: 13px;
      line-height: 1.45;
    `;
    this.card.appendChild(grid);

    this._addHelpSection(grid, 'Keyboard - Player 1', [
      ['Move', 'A / D'],
      ['Jump', 'W'],
      ['Crouch', 'S'],
      ['Punches', 'J light, K medium, L heavy'],
      ['Kicks', 'U light, I medium, O heavy'],
      ['Block', '; hold'],
      ['Hadoken', 'Down, Forward, J'],
      ['Shoryuken shortcut', 'B'],
    ]);

    this._addHelpSection(grid, 'Touch Controls', [
      ['D-pad', 'Move, crouch, jump'],
      ['LP MP HP', 'Light / medium / heavy punch'],
      ['LK MK HK', 'Light / medium / heavy kick'],
      ['BLK', 'Hold to block'],
      ['HADO', 'Hadoken shortcut'],
      ['DP', 'Shoryuken shortcut'],
    ]);

    this._addHelpSection(grid, 'Gamepad', [
      ['Move', 'D-pad or left stick'],
      ['A / B', 'Light punch / medium punch'],
      ['X / Y', 'Light kick / medium kick'],
      ['LB / RB', 'Heavy punch / heavy kick'],
      ['LT', 'Block'],
      ['Start', 'Shoryuken shortcut'],
    ]);

    this._addHelpSection(grid, 'Special Moves', [
      ['Hadoken', 'Down, Forward, LP'],
      ['Facing right', 'Down, Right, J / LP'],
      ['Facing left', 'Down, Left, J / LP'],
      ['Shoryuken', 'Forward, Down, HP quickly'],
      ['Shortcuts', 'HADO on touch, B / DP for Shoryuken'],
      ['Chakra pips', 'Hadoken uses one fire pip; one pip refills every 14 seconds'],
    ]);

    const note = document.createElement('div');
    note.textContent = 'Tip: Forward means toward the opponent, so the direction flips when your fighter turns around.';
    note.style.cssText = `
      margin-top: 18px;
      color: #f5e9c9;
      opacity: 0.78;
      font-size: 13px;
      line-height: 1.45;
      text-align: center;
    `;
    this.card.appendChild(note);

    const spacer = document.createElement('div');
    spacer.style.height = '12px';
    this.card.appendChild(spacer);

    this._addButton('Back', () => {
      this.card.style.maxWidth = '480px';
      this._screen = 'pause';
      this._render();
    });
  }

  _addHelpSection(parent, titleText, rows) {
    const section = document.createElement('div');
    section.style.cssText = `
      min-width: 0;
      padding: 12px 14px;
      border: 1px solid rgba(199,155,58,0.45);
      border-radius: 8px;
      background: rgba(12, 7, 4, 0.42);
    `;

    const title = document.createElement('div');
    title.textContent = titleText;
    title.style.cssText = `
      color: #ffd770;
      font-size: 12px;
      font-weight: 800;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      margin-bottom: 8px;
    `;
    section.appendChild(title);

    for (const [label, value] of rows) {
      const row = document.createElement('div');
      row.style.cssText = `
        display:grid;
        grid-template-columns: minmax(82px, 0.8fr) minmax(0, 1.2fr);
        gap: 10px;
        margin: 5px 0;
      `;
      const k = document.createElement('div');
      k.textContent = label;
      k.style.cssText = 'color:#c79b3a;font-weight:700;';
      const v = document.createElement('div');
      v.textContent = value;
      v.style.cssText = 'color:#f5e9c9;opacity:0.9;';
      row.appendChild(k);
      row.appendChild(v);
      section.appendChild(row);
    }

    parent.appendChild(section);
  }

  _renderSettingsScreen() {
    this.card.style.maxWidth = '480px';

    const title = document.createElement('h2');
    title.textContent = 'Settings';
    title.style.cssText = TITLE_STYLE;
    this.card.appendChild(title);

    // Audio sliders
    const audioHeader = document.createElement('div');
    audioHeader.textContent = 'Audio';
    audioHeader.style.cssText = 'font-size:13px;letter-spacing:0.15em;text-transform:uppercase;color:#c79b3a;margin:8px 0 6px 0;';
    this.card.appendChild(audioHeader);

    this._addSlider('Master',  'masterVolume');
    this._addSlider('Music',   'musicVolume');
    this._addSlider('SFX',     'sfxVolume');
    this._addSlider('Voice',   'voiceVolume');

    // Display
    const dispHeader = document.createElement('div');
    dispHeader.textContent = 'Display & Controls';
    dispHeader.style.cssText = 'font-size:13px;letter-spacing:0.15em;text-transform:uppercase;color:#c79b3a;margin:16px 0 6px 0;';
    this.card.appendChild(dispHeader);

    this._addSelect('Quality', 'qualityPreset', [
      ['low',    'Low'],
      ['medium', 'Medium'],
      ['high',   'High'],
    ]);
    this._addSelect('Touch UI', 'touchControlsVisible', [
      ['auto', 'Auto-detect'],
      ['on',   'Always show'],
      ['off',  'Hide'],
    ]);

    // Back button
    const spacer = document.createElement('div');
    spacer.style.height = '14px';
    this.card.appendChild(spacer);

    this._addButton('Back', () => {
      this._screen = 'pause';
      this._render();
    });
  }

  _renderPrivacyScreen() {
    this.card.style.maxWidth = '640px';

    const title = document.createElement('h2');
    title.textContent = 'Privacy & Ads';
    title.style.cssText = TITLE_STYLE;
    this.card.appendChild(title);

    const wrap = document.createElement('div');
    wrap.style.cssText = `
      font-size: 13px;
      line-height: 1.55;
      color: rgba(245,233,201,0.9);
    `;
    this.card.appendChild(wrap);

    const rows = [
      ['Local data', 'Coins, settings, touch UI preference, quality, and P2 mode are stored on this device.'],
      ['Ads', 'The game uses Google AdMob for optional rewarded coin ads and post-match ads. Ads do not interrupt active fighting.'],
      ['Network', 'Internet is used for ads. Core gameplay can run without network, but ad rewards may be unavailable offline.'],
      ['Privacy policy', 'Publish public/privacy.html to the official HTTPS site before store submission.'],
    ];

    for (const [label, text] of rows) {
      const row = document.createElement('div');
      row.style.cssText = `
        display: grid;
        grid-template-columns: 120px minmax(0, 1fr);
        gap: 14px;
        margin: 10px 0;
      `;
      const key = document.createElement('div');
      key.textContent = label;
      key.style.cssText = 'color:#ffd770;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;';
      const value = document.createElement('div');
      value.textContent = text;
      row.appendChild(key);
      row.appendChild(value);
      wrap.appendChild(row);
    }

    const spacer = document.createElement('div');
    spacer.style.height = '14px';
    this.card.appendChild(spacer);

    this._addButton('Back', () => {
      this._screen = 'pause';
      this._render();
    });
  }

  _addButton(label, onClick) {
    const btn = document.createElement('button');
    btn.textContent = label;
    btn.style.cssText = BUTTON_STYLE;
    btn.addEventListener('mouseenter', () => {
      btn.style.background = 'linear-gradient(180deg, #3a2510, #2a1a0c)';
    });
    btn.addEventListener('mouseleave', () => {
      btn.style.background = 'linear-gradient(180deg, #2a1a0c, #1a0f06)';
    });
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      onClick();
    });
    this.card.appendChild(btn);
  }

  _addSlider(label, settingKey) {
    const row = document.createElement('div');
    row.style.cssText = ROW_STYLE;

    const lbl = document.createElement('label');
    lbl.textContent = label;
    lbl.style.cssText = LABEL_STYLE;
    row.appendChild(lbl);

    const value = this.settings.get(settingKey);
    const slider = document.createElement('input');
    slider.type = 'range';
    slider.min = '0';
    slider.max = '100';
    slider.step = '1';
    slider.value = String(Math.round((value ?? 0) * 100));
    slider.style.cssText = 'flex:1;accent-color:#c79b3a;cursor:pointer;';

    const pct = document.createElement('span');
    pct.textContent = `${slider.value}%`;
    pct.style.cssText = 'font-size:13px;color:#ffd770;min-width:42px;text-align:right;font-variant-numeric:tabular-nums;';

    slider.addEventListener('input', () => {
      const v = +slider.value / 100;
      this.settings.set(settingKey, v);
      pct.textContent = `${slider.value}%`;
    });

    row.appendChild(slider);
    row.appendChild(pct);
    this.card.appendChild(row);
  }

  _addSelect(label, settingKey, options) {
    const row = document.createElement('div');
    row.style.cssText = ROW_STYLE;

    const lbl = document.createElement('label');
    lbl.textContent = label;
    lbl.style.cssText = LABEL_STYLE;
    row.appendChild(lbl);

    const sel = document.createElement('select');
    sel.style.cssText = 'flex:1;padding:6px 10px;background:#1a0f06;color:#f5e9c9;border:1.5px solid #c79b3a;border-radius:6px;font-family:inherit;font-size:14px;cursor:pointer;';
    for (const [val, display] of options) {
      const opt = document.createElement('option');
      opt.value = val;
      opt.textContent = display;
      sel.appendChild(opt);
    }
    sel.value = this.settings.get(settingKey);
    sel.addEventListener('change', () => {
      this.settings.set(settingKey, sel.value);
    });
    row.appendChild(sel);
    this.card.appendChild(row);
  }

  // -- Hotkeys ------------------------------------------------------------

  _bindHotkeys() {
    this._keyHandler = (e) => {
      if (e.code === 'Escape') {
        e.preventDefault();
        this.toggle();
      }
    };
    window.addEventListener('keydown', this._keyHandler);
  }

  dispose() {
    window.removeEventListener('keydown', this._keyHandler);
    if (this.panel?.parentNode) this.panel.parentNode.removeChild(this.panel);
    if (this.pauseButton?.parentNode) this.pauseButton.parentNode.removeChild(this.pauseButton);
  }
}
