/**
 * TouchControls
 * -------------
 * Phase 9: on-screen controls for phones, tablets, and forced desktop QA.
 *
 * The overlay feeds the same Input.setDown/setUp surface used by keyboard and
 * gamepad input, so combat code stays input-device agnostic.
 */

const DPAD_SIZE = 'clamp(52px, 9.5vmin, 78px)';
const FACE_SIZE = 'clamp(50px, 8.8vmin, 72px)';
const UTIL_SIZE = 'clamp(46px, 7.4vmin, 60px)';
const DPAD_STEP = `calc(${DPAD_SIZE} + 9px)`;
const FACE_STEP = `calc(${FACE_SIZE} + 10px)`;

const BUTTON_STYLE_BASE = `
  position: absolute;
  display: flex;
  align-items: center;
  justify-content: center;
  user-select: none;
  -webkit-user-select: none;
  -webkit-tap-highlight-color: transparent;
  touch-action: none;
  font-family: 'Segoe UI', system-ui, sans-serif;
  font-weight: 900;
  color: #fff8df;
  text-shadow: 0 2px 3px rgba(0,0,0,0.7);
  border: 2px solid rgba(255,215,112,0.82);
  background: radial-gradient(circle at 30% 25%, rgba(255,215,112,0.52), rgba(40,20,8,0.66));
  box-shadow:
    0 8px 20px rgba(0,0,0,0.32),
    inset 0 1px 3px rgba(255,255,255,0.2),
    inset 0 -4px 10px rgba(0,0,0,0.28);
  cursor: pointer;
  transition: transform 55ms ease, filter 55ms ease, opacity 120ms ease;
`;

const FACE_BUTTONS = [
  { label: 'LP', action: 'punch_light', col: 0, row: 0, color: ['#ffba52', '#7a3308'] },
  { label: 'MP', action: 'punch_medium', col: 1, row: 0, color: ['#ff8a3a', '#641c08'] },
  { label: 'HP', action: 'punch_heavy', col: 2, row: 0, color: ['#ef4444', '#520707'] },
  { label: 'LK', action: 'kick_light', col: 0, row: 1, color: ['#5fa8ff', '#0b3678'] },
  { label: 'MK', action: 'kick_medium', col: 1, row: 1, color: ['#3b82f6', '#082663'] },
  { label: 'HK', action: 'kick_heavy', col: 2, row: 1, color: ['#2563eb', '#061947'] },
];

const UTILITY_BUTTONS = [
  { label: 'BLK', action: 'block', offset: -1.15, color: ['#9ca3af', '#1f2937'] },
  { label: 'HADO', action: 'hadoken', offset: 0, color: ['#f59e0b', '#5b2406'] },
  { label: 'DP', action: 'shoryuken', offset: 1.15, color: ['#facc15', '#78350f'] },
];

export class TouchControls {
  /**
   * @param {object} opts
   * @param {HTMLElement} opts.host
   * @param {import('./Input.js').Input} opts.input
   * @param {number} [opts.playerId=0]
   */
  constructor({ host, input, playerId = 0 }) {
    this.host = host;
    this.input = input;
    this.playerId = playerId;
    this.root = null;
    this._visible = false;
    this._buttons = [];

    this._isTouchDevice =
      typeof window !== 'undefined' &&
      ('ontouchstart' in window || (navigator.maxTouchPoints || 0) > 0);

    this._build();
    if (this._isTouchDevice) this.show();
  }

  show() {
    if (!this.root) return;
    this.root.style.display = 'block';
    this._visible = true;
  }

  hide() {
    if (!this.root) return;
    this.root.style.display = 'none';
    this._visible = false;
    for (const button of this._buttons) this._releaseButton(button);
  }

  toggle() {
    if (this._visible) this.hide();
    else this.show();
  }

  isVisible() { return this._visible; }
  isTouchDevice() { return this._isTouchDevice; }

  dispose() {
    this.hide();
    if (this.root?.parentNode) this.root.parentNode.removeChild(this.root);
    this.root = null;
    this._buttons = [];
  }

  _build() {
    if (!this.host) return;

    this.root = document.createElement('div');
    this.root.id = 'touch-controls';
    this.root.style.cssText = `
      position: absolute;
      inset: 0;
      pointer-events: none;
      display: none;
      z-index: 18;
      font-family: 'Segoe UI', system-ui, sans-serif;
    `;
    this.root.addEventListener('contextmenu', (e) => e.preventDefault());

    this._buildDpad();
    this._buildFaceCluster();
    this._buildUtilityCluster();
    this.host.appendChild(this.root);
  }

  _buildDpad() {
    const base = document.createElement('div');
    base.style.cssText = `
      position: absolute;
      left: max(18px, env(safe-area-inset-left));
      bottom: max(20px, env(safe-area-inset-bottom));
      width: calc(${DPAD_SIZE} + ${DPAD_SIZE} + ${DPAD_SIZE} + 18px);
      height: calc(${DPAD_SIZE} + ${DPAD_SIZE} + ${DPAD_SIZE} + 18px);
      border-radius: 24px;
      background: radial-gradient(circle at 50% 50%, rgba(255,215,112,0.10), rgba(0,0,0,0.04));
      pointer-events: none;
    `;
    this.root.appendChild(base);

    const buttonBase = {
      width: DPAD_SIZE,
      height: DPAD_SIZE,
      borderRadius: '14px',
      fontSize: 'clamp(22px, 4vmin, 34px)',
    };
    this._makeButton({ label: 'UP', action: 'up', style: { ...buttonBase, left: `calc(max(18px, env(safe-area-inset-left)) + ${DPAD_STEP})`, bottom: `calc(max(20px, env(safe-area-inset-bottom)) + ${DPAD_STEP} + ${DPAD_STEP})` } });
    this._makeButton({ label: 'L', action: 'left', style: { ...buttonBase, left: 'max(18px, env(safe-area-inset-left))', bottom: `calc(max(20px, env(safe-area-inset-bottom)) + ${DPAD_STEP})` } });
    this._makeButton({ label: 'R', action: 'right', style: { ...buttonBase, left: `calc(max(18px, env(safe-area-inset-left)) + ${DPAD_STEP} + ${DPAD_STEP})`, bottom: `calc(max(20px, env(safe-area-inset-bottom)) + ${DPAD_STEP})` } });
    this._makeButton({ label: 'DN', action: 'down', style: { ...buttonBase, left: `calc(max(18px, env(safe-area-inset-left)) + ${DPAD_STEP})`, bottom: 'max(20px, env(safe-area-inset-bottom))' } });
  }

  _buildFaceCluster() {
    for (const spec of FACE_BUTTONS) {
      const [hi, lo] = spec.color;
      this._makeButton({
        label: spec.label,
        action: spec.action,
        style: {
          width: FACE_SIZE,
          height: FACE_SIZE,
          borderRadius: '50%',
          fontSize: 'clamp(13px, 2.5vmin, 17px)',
          right: this._faceOffset(2 - spec.col),
          bottom: this._faceBottom(1 - spec.row),
          background: `radial-gradient(circle at 30% 25%, ${hi}, ${lo})`,
        },
      });
    }
  }

  _buildUtilityCluster() {
    for (const spec of UTILITY_BUTTONS) {
      const [hi, lo] = spec.color;
      this._makeButton({
        label: spec.label,
        action: spec.action,
        style: {
          width: UTIL_SIZE,
          height: UTIL_SIZE,
          borderRadius: '14px',
          fontSize: 'clamp(11px, 2vmin, 14px)',
          left: this._utilityLeft(spec.offset),
          bottom: 'max(20px, env(safe-area-inset-bottom))',
          background: `radial-gradient(circle at 30% 25%, ${hi}, ${lo})`,
        },
      });
    }
  }

  _makeButton({ label, action, style }) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.textContent = label;
    btn.setAttribute('aria-label', action.replaceAll('_', ' '));
    btn.style.cssText = BUTTON_STYLE_BASE;
    Object.assign(btn.style, style);
    btn.style.pointerEvents = 'auto';

    const entry = { el: btn, action, pointerId: null, source: null };
    this._buttons.push(entry);

    const onDown = (e) => {
      e.preventDefault();
      if (entry.pointerId !== null) return;
      entry.pointerId = e.pointerId;
      entry.source = `touch:${action}:${e.pointerId}`;
      try { btn.setPointerCapture(e.pointerId); } catch {}
      btn.style.transform = 'scale(0.91)';
      btn.style.filter = 'brightness(1.25) saturate(1.12)';
      this.input.setDown(action, this.playerId, entry.source);
    };
    const onUp = (e) => {
      if (entry.pointerId !== e.pointerId) return;
      this._releaseButton(entry);
      try { btn.releasePointerCapture(e.pointerId); } catch {}
    };

    btn.addEventListener('pointerdown', onDown);
    btn.addEventListener('pointerup', onUp);
    btn.addEventListener('pointercancel', onUp);
    btn.addEventListener('lostpointercapture', onUp);
    btn.addEventListener('pointerleave', (e) => {
      if (entry.pointerId === e.pointerId && e.buttons === 0) onUp(e);
    });

    this.root.appendChild(btn);
  }

  _faceOffset(steps) {
    if (steps === 0) return 'max(20px, env(safe-area-inset-right))';
    if (steps === 1) return `calc(max(20px, env(safe-area-inset-right)) + ${FACE_STEP})`;
    return `calc(max(20px, env(safe-area-inset-right)) + ${FACE_STEP} + ${FACE_STEP})`;
  }

  _faceBottom(steps) {
    if (steps === 0) return 'max(20px, env(safe-area-inset-bottom))';
    return `calc(max(20px, env(safe-area-inset-bottom)) + ${FACE_STEP})`;
  }

  _utilityLeft(offset) {
    if (offset < 0) return `calc(50% - ${UTIL_SIZE} - 76px)`;
    if (offset > 0) return 'calc(50% + 76px)';
    return 'calc(50% - 30px)';
  }

  _releaseButton(entry) {
    if (entry.pointerId === null) return;
    const source = entry.source;
    entry.pointerId = null;
    entry.source = null;
    entry.el.style.transform = '';
    entry.el.style.filter = '';
    if (source) this.input.setUp(entry.action, this.playerId, source);
  }
}
