import { SyntheticInput } from '../engine/SyntheticInput.js';

/**
 * AI
 * --
 * Rule-based opponent controller. Reads the fight state each frame and
 * emits synthetic input events the opponent Fighter's StateMachine
 * consumes — so the same code paths drive both human and AI fighters.
 *
 * Difficulty knob exists but only "medium" is fully tuned in this pass.
 *   easy   — slow reactions, often whiffs, rarely blocks
 *   medium — reasonable spacing, blocks predictable attacks, mixes lights
 *   hard   — punishes whiffs, mixes high/low, uses specials situationally
 *
 * The AI is intentionally simple: a priority list of conditions, plus a
 * per-decision cooldown so it doesn't spam attacks every frame. That's
 * enough to make Toofan feel alive without overengineering before the
 * full move/special system exists.
 */

// Attack pool weighted toward fast normals; heavies are rare.
const ATTACK_POOL = [
  'punch_light', 'punch_light', 'punch_light',
  'kick_light', 'kick_light', 'kick_light',
  'punch_medium', 'punch_medium',
  'kick_medium', 'kick_medium',
  'punch_heavy',
  'kick_heavy',
];

const DIFFICULTY = {
  easy:   { reactBlockMs: 280, decisionRange: [0.55, 0.95], blockChance: 0.45, attackChance: 0.55 },
  medium: { reactBlockMs: 160, decisionRange: [0.32, 0.65], blockChance: 0.78, attackChance: 0.85 },
  hard:   { reactBlockMs:  90, decisionRange: [0.18, 0.45], blockChance: 0.92, attackChance: 0.95 },
};

export class AI {
  /**
   * @param {object} opts
   * @param {import('./Fighter.js').Fighter} opts.self
   * @param {import('./Fighter.js').Fighter} opts.opponent
   * @param {'easy'|'medium'|'hard'} [opts.difficulty]
   */
  constructor({ self, opponent, difficulty = 'medium' }) {
    this.self = self;
    this.opponent = opponent;
    this.difficulty = difficulty;
    this.tuning = DIFFICULTY[difficulty] ?? DIFFICULTY.medium;
    this.input = new SyntheticInput();

    // Decision rhythm.
    this._actionTimer = 0;
    /** Current held action (mostly walk direction). null if none. */
    this._heldAction = null;

    // Threat-reaction delay: when the opponent starts attacking, we don't
    // teleport into block — we delay a beat first. Stored as a countdown
    // that ticks down only while a threat is observed.
    this._threatSeenAt = -Infinity;
  }

  /** Called once per frame, before the AI fighter's update. */
  update(dt) {
    this._actionTimer -= dt;
    const now = performance.now();

    const self = this.self;
    const opp = this.opponent;
    const myState = self.stateMachine.currentName;
    const oppState = opp.stateMachine.currentName;
    const distance = Math.abs(self.position.x - opp.position.x);
    const goRight = opp.position.x > self.position.x;
    const myHpRatio = self.hp / self.maxHp;

    const held = new Set();
    const pressed = new Set();

    // 1. Locked into an animation — let it finish.
    if (myState === 'hit' || myState === 'knockdown' || myState === 'ko' || myState === 'attack') {
      this._heldAction = null;
      this.input.set(held, pressed);
      return;
    }

    // 2. Reaction-delayed block when opponent is winding up an attack
    //    in range. We start a timer the first frame we detect a threat,
    //    then only commit to block after `reactBlockMs` has elapsed.
    const isThreat = oppState === 'attack' && distance < 2.0;
    if (isThreat) {
      if (this._threatSeenAt === -Infinity) this._threatSeenAt = now;
      const reactReady = now - this._threatSeenAt >= this.tuning.reactBlockMs;
      if (reactReady && Math.random() < this.tuning.blockChance) {
        held.add('block');
        this.input.set(held, pressed);
        return;
      }
    } else {
      this._threatSeenAt = -Infinity;
    }

    // 3. Standard decision tree on cooldown.
    if (this._actionTimer <= 0) {
      if (distance > 2.0) {
        // Far away — close the distance.
        this._heldAction = goRight ? 'right' : 'left';
      } else if (distance < 1.0) {
        // In range — swing.
        if (Math.random() < this.tuning.attackChance) {
          const move = ATTACK_POOL[Math.floor(Math.random() * ATTACK_POOL.length)];
          pressed.add(move);
          this._heldAction = null;
        } else {
          // Occasional micro-retreat to create whiff-punish openings.
          this._heldAction = goRight ? 'left' : 'right';
        }
      } else {
        // Mid-range: weight toward approach, but sometimes poke or step back.
        const r = Math.random();
        if (r < 0.6) {
          this._heldAction = goRight ? 'right' : 'left';
        } else if (r < 0.85) {
          // Walk-in poke — press an attack now AND keep walking briefly.
          const move = ATTACK_POOL[Math.floor(Math.random() * ATTACK_POOL.length)];
          pressed.add(move);
          this._heldAction = null;
        } else {
          this._heldAction = goRight ? 'left' : 'right';
        }
      }
      // Schedule next decision.
      const [lo, hi] = this.tuning.decisionRange;
      this._actionTimer = lo + Math.random() * (hi - lo);

      // When HP is low, bias toward defensive backstepping a bit more.
      if (myHpRatio < 0.3 && Math.random() < 0.25) {
        this._heldAction = goRight ? 'left' : 'right';
        this._actionTimer += 0.2;
      }
    }

    if (this._heldAction) held.add(this._heldAction);
    this.input.set(held, pressed);
  }
}
