import * as THREE from 'three';
import { StateMachine } from './StateMachine.js';
import { IdleState } from './states/IdleState.js';
import { WalkState } from './states/WalkState.js';
import { JumpState } from './states/JumpState.js';
import { AttackState } from './states/AttackState.js';
import { BlockState } from './states/BlockState.js';
import { HitState } from './states/HitState.js';
import { KnockdownState } from './states/KnockdownState.js';
import { KOState } from './states/KOState.js';
import { CrouchState } from './states/CrouchState.js';
import { HadokenState } from './states/HadokenState.js';
import { ThrownState } from './states/ThrownState.js';
import { ShoryukenState } from './states/ShoryukenState.js';
import { Projectile } from './Projectile.js';
import { Physics, AABB, STAGE_BOUNDS } from '../engine/Physics.js';

const DEFAULT_MODEL_FORWARD_OFFSET = Math.PI / 2;
const TARGET_FIGHTER_HEIGHT = 1.8;
const HURTBOX = { w: 0.7, h: 1.7 };

const HADOKEN_BY_ID = {
  abdullah_sherdil:  { color: 0xff8a3a, name: 'Sherdil Aag' },
  toofan_khan:       { color: 0x9b5cff, name: 'Toofani Bijli' },
  aslam_karachiwala: { color: 0xfff070, name: 'Karachi Punch Blast' },
  sher_khan_afridi:  { color: 0xff6b3a, name: 'Sher Garjna' },
  irfan_baloch:      { color: 0xffcc44, name: 'Reti ki Aandhi' },
  dr_hina:           { color: 0x6effe2, name: 'Hina Pulse' },
};
const HADOKEN_DEFAULT = {
  startupFrames: 14,
  activeFrames: 4,
  recoveryFrames: 24,
  perRound: 3,
  projectile: {
    speed: 6.0,
    damage: 80,
    hitstun: 24,
    chip: 12,
    lifespan: 2.0,
    radius: 0.25,
  },
};

// Chakra regen: spent Hadokens come back slowly during the round so a player
// who fires their 3 early isn't dead in the water. Cap stays at perRound.
const HADOKEN_REGEN_SECONDS = 14;

export class Fighter {
  constructor({ characterData, asset, playerId, facing, spawn }) {
    this.character = characterData;
    this.asset = asset;
    this.playerId = playerId;
    this.facing = facing;

    this.hp = characterData.stats?.hp ?? 1000;
    this.maxHp = this.hp;
    this.walkSpeed = characterData.stats?.walkSpeed ?? 2.5;
    this.weight = characterData.stats?.weight ?? 1.0;
    this.jumpVelocity = Math.sqrt(2 * 22 * (characterData.stats?.jumpHeight ?? 2.4));

    this.position = { x: spawn?.x ?? (playerId === 0 ? -1.6 : 1.6), y: 0 };
    this.velocity = { x: 0, y: 0 };
    this.isGrounded = true;

    this._currentAttack = null;

    this.rig = new THREE.Group();
    this.rig.name = `fighter_${playerId}_${characterData.id}`;
    this.rig.add(asset.scene);
    this._autoScaleAndGround();
    this.rig.scale.multiplyScalar(characterData.scale ?? 1.0);

    this._currentAction = null;
    this._missingClipWarnings = new Set();
    this.visualOffsetY = 0;
    this.forceVisualGrounding = false;
    this._modelForwardOffset =
      characterData.modelForwardOffset ?? DEFAULT_MODEL_FORWARD_OFFSET;

    this.stateMachine = new StateMachine(this);
    this.stateMachine.register('idle', IdleState);
    this.stateMachine.register('walk', WalkState);
    this.stateMachine.register('jump', JumpState);
    this.stateMachine.register('attack', AttackState);
    this.stateMachine.register('block', BlockState);
    this.stateMachine.register('hit', HitState);
    this.stateMachine.register('knockdown', KnockdownState);
    this.stateMachine.register('ko', KOState);
    this.stateMachine.register('crouch', CrouchState);
    this.stateMachine.register('hadoken', HadokenState);
    this.stateMachine.register('thrown', ThrownState);
    this.stateMachine.register('shoryuken', ShoryukenState);
    this.stateMachine.change('idle');

    this.hadokenCount = HADOKEN_DEFAULT.perRound;
    this._projectiles = null;
    this._sceneRef = null;
    this._hadokenCooldown = 0;
    // Regen: 1 stockpile refill every HADOKEN_REGEN_SECONDS while below cap.
    this._hadokenRegenTimer = 0;

    this._syncTransform();
  }

  _autoScaleAndGround() {
    const box = new THREE.Box3().setFromObject(this.asset.scene);
    const size = new THREE.Vector3();
    box.getSize(size);
    if (size.y > 0.0001) {
      const k = TARGET_FIGHTER_HEIGHT / size.y;
      this.asset.scene.scale.setScalar(k);
    }
    box.setFromObject(this.asset.scene);
    this.asset.scene.position.y -= box.min.y;
    this.asset.scene.position.y += this.character.yOffset ?? 0;
  }

  _syncTransform() {
    this.rig.position.set(this.position.x, this.position.y + this.visualOffsetY, 0);
    this.rig.rotation.y =
      this._modelForwardOffset + (this.facing === 1 ? 0 : Math.PI);
  }

  _groundAnimatedVisual() {
    if (!this.forceVisualGrounding) return;
    this.rig.updateMatrixWorld(true);
    const box = new THREE.Box3().setFromObject(this.asset.scene);
    if (!Number.isFinite(box.min.y)) return;

    const floorY = 0;
    const error = floorY - box.min.y;
    if (Math.abs(error) < 0.015) return;

    const correction = THREE.MathUtils.clamp(error, -0.9, 0.9);
    this.visualOffsetY += correction;
    this._syncTransform();
  }

  _detectHadokenMotion(input) {
    const recent = input.recentSequence?.(this.playerId) ?? [];
    if (recent.length < 2) return false;
    if (recent[recent.length - 1] !== 'punch_light') return false;
    const forwardKey = this.facing === 1 ? 'right' : 'left';
    let sawDown = false;
    let sawForward = false;
    for (let i = recent.length - 2; i >= 0; i--) {
      if (recent[i] === 'down') { sawDown = true; if (sawForward) return true; }
      else if (recent[i] === forwardKey) { sawForward = true; }
    }
    return sawDown && sawForward;
  }

  tryHadoken(input) {
    if (this.hadokenCount <= 0) return false;
    if (this._hadokenCooldown > 0) return false;
    const directHadoken = input.wasPressed?.('hadoken', this.playerId);
    if (!directHadoken && !this._detectHadokenMotion(input)) return false;
    this.hadokenCount -= 1;
    this._hadokenCooldown = 0.5;
    this.stateMachine.change('hadoken');
    return true;
  }

  refillHadoken() {
    this.hadokenCount = HADOKEN_DEFAULT.perRound;
    this._hadokenRegenTimer = 0;
  }

  _makeHadokenProjectile() {
    if (!this._sceneRef) return null;
    const idCfg = HADOKEN_BY_ID[this.character.id] ?? {};
    const cfg = {
      ...HADOKEN_DEFAULT.projectile,
      color: idCfg.color ?? 0xffcc44,
    };
    return new Projectile({
      owner: this,
      spawn: { x: this.position.x + 0.8 * this.facing, y: this.position.y + 1.05 },
      facing: this.facing,
      config: cfg,
      scene: this._sceneRef,
    });
  }

  getClip(gameName, fallbackNames = []) {
    const names = [gameName, ...fallbackNames].filter(Boolean);
    return names.map((name) => this.asset.clips[name]).find(Boolean) ?? null;
  }

  _warnMissingClip(gameName, fallbackNames = []) {
    const key = `${this.character.id}:${gameName}:${fallbackNames.join('|')}`;
    if (this._missingClipWarnings.has(key)) return;
    this._missingClipWarnings.add(key);
    console.warn(
      `[Fighter] Missing animation "${gameName}" for ${this.character.name}` +
        (fallbackNames.length ? `; tried fallbacks: ${fallbackNames.join(', ')}` : ''),
    );
  }

  playClip(gameName, {
    loop = true,
    fade = 0.18,
    timeScale = 1,
    animationStart = 0,
    fallbackNames = [],
  } = {}) {
    const clip = this.getClip(gameName, fallbackNames);
    if (!clip) {
      this._warnMissingClip(gameName, fallbackNames);
      return;
    }
    const action = this.asset.mixer.clipAction(clip);
    if (this._currentAction === action) {
      action.timeScale = timeScale;
      return;
    }
    action.reset();
    if (animationStart > 0) {
      action.time = Math.min(animationStart, Math.max(0, clip.duration - 1 / 60));
    }
    action.setLoop(loop ? THREE.LoopRepeat : THREE.LoopOnce, Infinity);
    action.clampWhenFinished = !loop;
    action.timeScale = timeScale;
    if (this._currentAction) {
      action.crossFadeFrom(this._currentAction, fade, false).play();
    } else {
      action.play();
    }
    this._currentAction = action;
  }

  faceOpponent(opponent) {
    this.facing = opponent.position.x >= this.position.x ? 1 : -1;
    this._syncTransform();
  }

  activeHitboxes() {
    const cur = this._currentAttack;
    if (!cur || cur.hasHit || !cur.isActive) return [];
    const hb = cur.move.hitbox;
    if (!hb) return [];
    const cx = this.position.x + hb.x * this.facing;
    const cy = this.position.y + hb.y;
    return [new AABB(cx - hb.w / 2, cy - hb.h / 2, hb.w, hb.h)];
  }

  activeHurtboxes() {
    if (this.hp <= 0) return [];
    if (this.stateMachine.currentName === 'ko') return [];
    return [new AABB(
      this.position.x - HURTBOX.w / 2,
      this.position.y,
      HURTBOX.w,
      HURTBOX.h,
    )];
  }

  takeHit({ move, fromX }) {
    const blocking = this.stateMachine.currentName === 'block';
    const isGrab = move.hitLevel === 'grab';
    const isLauncher = !!move.isShoryuken || !!move.launch;
    const willBlock = blocking && !isGrab;

    const damage = willBlock ? (move.chip ?? 0) : (move.damage ?? 0);
    this.hp = Math.max(0, this.hp - damage);

    const dir = this.position.x >= fromX ? 1 : -1;
    const push = (move.pushback ?? 0.5) * 3.5 / Math.max(0.5, this.weight);
    this.velocity.x = dir * push;

    if (this.hp <= 0) {
      this.stateMachine.change('ko');
      return { blocked: willBlock, damage };
    }

    if (willBlock) {
      this.stateMachine.change('block', {
        stun: (move.blockstun ?? 8) / 60,
        keepHeld: true,
      });
    } else if (isGrab) {
      // Caught in a daav — force a visible separation, then play the
      // 'thrown' clip and slide the defender backward over the throw
      // duration. Without this the two fighters look glued together.
      const visibleMinX = STAGE_BOUNDS.minX + 0.85;
      const visibleMaxX = STAGE_BOUNDS.maxX - 0.85;
      const clampX = (x) => Math.max(visibleMinX, Math.min(visibleMaxX, x));
      const START_SEPARATION = 0.42;
      const LAND_SEPARATION = Math.min(
        1.2,
        Math.max(0.95, move.throwLandSeparation ?? move.pushback ?? 1.05),
      );
      const startX = clampX(fromX + dir * START_SEPARATION);
      let targetX = clampX(fromX - dir * LAND_SEPARATION);
      if (Math.abs(targetX - startX) < 0.75) {
        targetX = clampX(fromX + dir * LAND_SEPARATION);
      }

      this.position.x = startX;
      this.position.y = 0;
      this.visualOffsetY = 0;
      this.velocity.x = 0;
      this.velocity.y = 0;
      this.isGrounded = true;
      const throwTuning = this.character.throwTuning ?? {};
      const throwFrames = (move.hitstun ?? 36) + (move.recovery ?? 24);
      const defaultThrowDuration = Math.min(0.5, Math.max(0.34, throwFrames / 140));
      this.stateMachine.change('thrown', {
        duration: move.throwDuration ?? defaultThrowDuration,
        startX,
        targetX,
        visualDrop: throwTuning.victimVisualDrop ?? move.throwVisualDrop ?? 0,
        arcHeight: throwTuning.victimArcHeight ?? move.throwArcHeight ?? 0,
        thrownAnimation: throwTuning.victimAnimation ?? move.thrownVictimAnimation ?? 'knockdown',
        thrownTimeScale: throwTuning.victimAnimationTimeScale ?? move.thrownAnimationTimeScale ?? 1.15,
        thrownAnimationStart: throwTuning.victimAnimationStart ?? move.thrownAnimationStart ?? 0,
        knockdownVisualOffset: throwTuning.victimKnockdownOffset ?? move.throwKnockdownOffset ?? 0,
      });
    } else if (isLauncher) {
      // Hit by a Shoryuken — launched into the air. Apply upward velocity
      // and let gravity bring them down. Hit state handles the airborne
      // hurtle and lands them in knockdown on touchdown.
      const launch = move.launch ?? { opponentY: 1.2, opponentX: 0.4 };
      this.velocity.y = this.jumpVelocity * (launch.opponentY ?? 1.2);
      this.velocity.x = dir * (launch.opponentX ?? 0.4) * 5.0;
      this.isGrounded = false;
      this.stateMachine.change('hit', {
        stun: ((move.hitstun ?? 24) + 24) / 60,
        low: false,
        launcher: true,
      });
    } else {
      this.stateMachine.change('hit', {
        stun: (move.hitstun ?? 12) / 60,
        low: move.hitLevel === 'low',
      });
    }
    return { blocked: willBlock, damage };
  }

  update(dt, input) {
    if (this._hadokenCooldown > 0) this._hadokenCooldown -= dt;

    if (this.hadokenCount < HADOKEN_DEFAULT.perRound && this.hp > 0) {
      this._hadokenRegenTimer += dt;
      if (this._hadokenRegenTimer >= HADOKEN_REGEN_SECONDS) {
        this._hadokenRegenTimer = 0;
        this.hadokenCount += 1;
      }
    } else {
      this._hadokenRegenTimer = 0;
    }

    this.stateMachine.update(dt, input);

    this.position.x += this.velocity.x * dt;

    Physics.applyGravity(this, dt);
    Physics.clampToStage(this);

    this.asset.mixer?.update(dt);
    this._syncTransform();
    this._groundAnimatedVisual();
  }
}
