/**
 * HadokenState
 * ------------
 * Locks the fighter into a fireball-throw animation. Spawns the projectile
 * at the active frame. Recovery returns to idle.
 *
 *   data.hadoken on the character: { startupFrames, activeFrames, recoveryFrames, perRound, projectile }
 *
 * The spawn happens at (startupFrames + activeFrames/2) frames into the
 * animation, so the projectile leaves the fighter's hand at the visual
 * apex of the throw.
 */
export const HadokenState = {
  name: 'hadoken',

  enter(fighter, _prev, _payload) {
    fighter.velocity.x = 0;
    this._t = 0;
    this._spawned = false;
    fighter.playClip('special_1', { loop: false, fade: 0.08 });
  },

  update(dt, _input, fighter) {
    this._t += dt;

    // Use per-character override if present, otherwise fall back to the
    // canonical defaults defined in Fighter.js (HADOKEN_DEFAULT).
    const cfg = fighter.character.hadoken ?? {
      startupFrames: 14,
      activeFrames: 4,
      recoveryFrames: 24,
    };

    const startup = cfg.startupFrames / 60;
    const active = cfg.activeFrames / 60;
    const recovery = cfg.recoveryFrames / 60;
    const spawnTime = startup + active * 0.5;

    if (!this._spawned && this._t >= spawnTime) {
      this._spawned = true;
      fighter._projectiles?.add(
        fighter._makeHadokenProjectile?.(),
      );
    }

    if (this._t >= startup + active + recovery) {
      return 'idle';
    }
    return null;
  },
};
