/**
 * KOState
 * -------
 * Terminal state for the losing fighter at round end. Plays defeat clip,
 * locks input. Game.js drives the round-end flow from here.
 */
export const KOState = {
  name: 'ko',

  enter(fighter) {
    fighter.playClip('defeat', { loop: false });
  },

  update() {
    // Stays here until the round resets the fighter.
    return null;
  },
};
