/**
 * MainMenu
 * --------
 * Title screen with clear mode navigation. Built as DOM and mounted inside
 * #ui-root so Windows Store reviewers land on an obvious playable surface.
 */
export class MainMenu {
  /** @param {HTMLElement} root */
  constructor(root, opts = {}) {
    this.root = root;
    this.branding = opts.branding ?? { displayName: 'Desi Street Brawler' };
  }

  show({ onQuickFight, onChampionship, onHowToPlay } = {}) {
    this.hide();

    const wrap = document.createElement('div');
    wrap.style.cssText = `
      position:absolute; inset:0;
      pointer-events:auto;
      z-index:60;
      display:grid;
      place-items:center;
      padding: max(22px, env(safe-area-inset-top)) max(22px, env(safe-area-inset-right))
        max(22px, env(safe-area-inset-bottom)) max(22px, env(safe-area-inset-left));
      background:
        linear-gradient(180deg, rgba(12,7,4,0.72), rgba(32,14,8,0.90)),
        radial-gradient(circle at 50% 22%, rgba(255,215,112,0.16), transparent 34%);
      color:#f5e9c9;
      font-family:'Segoe UI', system-ui, sans-serif;
    `;
    this._wrap = wrap;

    const panel = document.createElement('section');
    panel.style.cssText = `
      width:min(820px, calc(100vw - 36px));
      border:2px solid #c79b3a;
      border-radius:8px;
      background:rgba(20,12,6,0.82);
      box-shadow:0 18px 48px rgba(0,0,0,0.55), inset 0 0 0 1px rgba(255,215,112,0.14);
      padding:clamp(18px, 4vw, 34px);
      text-align:center;
    `;
    wrap.appendChild(panel);

    const title = document.createElement('h1');
    title.textContent = this.branding.displayName;
    title.style.cssText = `
      margin:0;
      font-size:clamp(30px, 7vw, 62px);
      line-height:0.95;
      letter-spacing:0.08em;
      text-transform:uppercase;
      color:#ffd770;
      text-shadow:3px 3px 0 #1b120a, 0 0 28px rgba(255,215,112,0.55);
    `;
    panel.appendChild(title);

    const subtitle = document.createElement('p');
    subtitle.textContent = 'Fight best-of-3 matches, climb the championship ladder, and prove your fighter is street champion.';
    subtitle.style.cssText = `
      margin:14px auto 22px;
      max-width:640px;
      font-size:clamp(13px, 2.5vw, 17px);
      line-height:1.45;
      color:rgba(245,233,201,0.86);
    `;
    panel.appendChild(subtitle);

    const actions = document.createElement('div');
    actions.style.cssText = `
      display:grid;
      grid-template-columns:repeat(3, minmax(0, 1fr));
      gap:12px;
    `;
    panel.appendChild(actions);

    const makeButton = (label, detail, handler, primary = false) => {
      const button = document.createElement('button');
      button.type = 'button';
      button.style.cssText = `
        min-height:112px;
        padding:16px 14px;
        border:2px solid ${primary ? '#ffd770' : '#8d6421'};
        border-radius:8px;
        background:${primary ? 'linear-gradient(180deg, #7a2c16, #4a1810)' : 'rgba(42,18,10,0.92)'};
        color:#ffd770;
        cursor:pointer;
        font-family:inherit;
        text-align:left;
        box-shadow:${primary ? '0 0 22px rgba(255,215,112,0.32)' : 'none'};
      `;
      button.innerHTML = `
        <span style="display:block;font-size:16px;font-weight:900;letter-spacing:0.12em;text-transform:uppercase;">${label}</span>
        <span style="display:block;margin-top:8px;font-size:12px;line-height:1.35;color:rgba(245,233,201,0.78);">${detail}</span>
      `;
      button.addEventListener('click', () => handler?.());
      actions.appendChild(button);
    };

    makeButton('Quick Fight', 'Pick two fighters and a stage for a complete best-of-3 match.', onQuickFight, true);
    makeButton('Championship', 'Choose one fighter and defeat the full ladder across multiple stages.', onChampionship);
    makeButton('How To Play', 'Controls, win rules, and match flow for keyboard, touch, and gamepad.', onHowToPlay);

    const footer = document.createElement('div');
    footer.textContent = 'Every fight is first to 2 round wins. Use Esc or the pause button during battle.';
    footer.style.cssText = `
      margin-top:18px;
      font-size:12px;
      letter-spacing:0.08em;
      color:rgba(245,233,201,0.62);
      text-transform:uppercase;
    `;
    panel.appendChild(footer);

    this.root.appendChild(wrap);
  }

  hide() {
    if (this._wrap?.parentNode) this._wrap.parentNode.removeChild(this._wrap);
    this._wrap = null;
  }
}
