const STORAGE_KEY = 'dsf.economy.v1';

const DEFAULTS = Object.freeze({
  coins: 0,
});

function readStored() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === 'object' ? parsed : {};
  } catch {
    return {};
  }
}

function writeStored(value) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(value));
  } catch {
    /* Storage can fail in private mode; economy should not crash the game. */
  }
}

export class Economy {
  constructor() {
    this._values = { ...DEFAULTS, ...readStored() };
    this._listeners = new Set();
  }

  get coins() {
    return this._values.coins ?? 0;
  }

  addCoins(amount) {
    const safeAmount = Math.max(0, Number(amount) || 0);
    if (safeAmount <= 0) return this.coins;
    this._values.coins = this.coins + safeAmount;
    writeStored(this._values);
    this._notify();
    return this.coins;
  }

  subscribe(listener) {
    this._listeners.add(listener);
    return () => this._listeners.delete(listener);
  }

  snapshot() {
    return Object.freeze({ ...this._values });
  }

  _notify() {
    for (const cb of this._listeners) {
      try { cb(this); } catch { /* Listener errors should not break gameplay. */ }
    }
  }
}
