import * as THREE from 'three';

/**
 * Juice
 * -----
 * The "feel" layer. Owns screen shake, slow-motion, hit-spark particles,
 * and a subtle camera dolly when the match gets close to KO. Nothing in
 * here changes gameplay state — it only modifies the camera and spawns
 * cosmetic geometry, so removing the Juice instance keeps the game
 * fully playable (just less satisfying).
 *
 * Combat code calls these high-level methods:
 *   juice.shake(amp, duration)
 *   juice.slowMo(strength, duration)
 *   juice.spawnHitSpark(worldPos, color)
 *
 * The main loop calls juice.update(realDt, lowHpRatio) once per frame
 * with the *unscaled* dt so shakes and slow-mo timers still tick during
 * slow-motion.
 *
 * getDtScale() returns the factor to multiply game dt by — 1.0 normally,
 * lower during slow-mo. main.js applies this to everything except the
 * juice update itself and audio.
 */
export class Juice {
  /**
   * @param {object} opts
   * @param {THREE.PerspectiveCamera} opts.camera
   * @param {THREE.Scene} opts.scene
   */
  constructor({ camera, scene }) {
    this.camera = camera;
    this.scene = scene;
    this._baseCameraPos = camera.position.clone();
    this._baseCameraLook = new THREE.Vector3(0, 1.2, 0);

    // Shake state.
    this._shakeAmp = 0;
    this._shakeTimer = 0;
    this._shakeDuration = 0.25;

    // Slow-mo state.
    this._slowMoStrength = 0; // 0..1, 1 = full freeze
    this._slowMoTimer = 0;

    // Camera dolly (zoom-in on low HP).
    this._zoomCurrent = 1.0;

    // Hit-spark particles.
    /** @type {Array<{mesh: THREE.Mesh, velocity: THREE.Vector3, lifespan: number, age: number}>} */
    this._particles = [];
    this._sparkGroup = new THREE.Group();
    this._sparkGroup.name = 'juice_sparks';
    scene.add(this._sparkGroup);
  }

  /**
   * Trigger camera shake. Multiple calls take the max amplitude/duration.
   * @param {number} amp       Metres of jitter at peak (~0.05–0.3 is the useful range).
   * @param {number} duration  Seconds.
   */
  shake(amp, duration = 0.25) {
    this._shakeAmp = Math.max(this._shakeAmp, amp);
    if (duration > this._shakeTimer) {
      this._shakeTimer = duration;
      this._shakeDuration = duration;
    }
  }

  /**
   * Trigger slow-motion. The Juice produces a dt-multiplier that the main
   * loop applies to all gameplay. Audio + this update tick stay realtime.
   * @param {number} strength  0..1; 0.7 means "30% speed".
   * @param {number} duration  Seconds in real time.
   */
  slowMo(strength = 0.7, duration = 0.4) {
    this._slowMoStrength = Math.max(this._slowMoStrength, strength);
    this._slowMoTimer = Math.max(this._slowMoTimer, duration);
  }

  /**
   * Spawn a starburst of small bright spheres at a world position. They
   * spray outward, decelerate, fade, and clean themselves up.
   */
  spawnHitSpark(worldPos, color = 0xffd770, count = 10, speedScale = 1) {
    for (let i = 0; i < count; i++) {
      const geom = new THREE.SphereGeometry(0.04 + Math.random() * 0.03, 6, 6);
      const mat = new THREE.MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 1,
        depthWrite: false,
      });
      const mesh = new THREE.Mesh(geom, mat);
      mesh.position.copy(worldPos);
      const angle = Math.random() * Math.PI * 2;
      const speed = (2 + Math.random() * 4) * speedScale;
      this._particles.push({
        mesh,
        velocity: new THREE.Vector3(
          Math.cos(angle) * speed,
          Math.sin(angle) * speed + 1.5,
          (Math.random() - 0.5) * 0.5,
        ),
        lifespan: 0.32 + Math.random() * 0.15,
        age: 0,
      });
      this._sparkGroup.add(mesh);
    }
  }

  /** Dt multiplier the main loop should apply to gameplay updates. */
  getDtScale() {
    if (this._slowMoTimer <= 0) return 1.0;
    return 1.0 - this._slowMoStrength;
  }

  /**
   * Per-frame update. Pass the REAL (unscaled) dt and the LOWER of the
   * two fighters' HP ratios so we can drive the low-HP dolly.
   */
  update(realDt, lowHpRatio = 1.0) {
    // Slow-mo countdown.
    if (this._slowMoTimer > 0) {
      this._slowMoTimer -= realDt;
      if (this._slowMoTimer <= 0) {
        this._slowMoTimer = 0;
        this._slowMoStrength = 0;
      }
    }

    // Camera dolly target: pull camera in when match is close to KO.
    // Below 25% HP on either side -> zoom factor 0.85 (closer).
    const targetZoom = lowHpRatio < 0.25 ? 0.85 : 1.0;
    this._zoomCurrent += (targetZoom - this._zoomCurrent) * Math.min(1, realDt * 3);

    // Shake countdown.
    let shakeFactor = 0;
    if (this._shakeTimer > 0) {
      this._shakeTimer -= realDt;
      const t = Math.max(0, this._shakeTimer / this._shakeDuration);
      shakeFactor = this._shakeAmp * t;
      if (this._shakeTimer <= 0) {
        this._shakeTimer = 0;
        this._shakeAmp = 0;
      }
    }

    const dx = (Math.random() - 0.5) * 2 * shakeFactor;
    const dy = (Math.random() - 0.5) * 2 * shakeFactor;

    this.camera.position.set(
      this._baseCameraPos.x + dx,
      this._baseCameraPos.y + dy,
      this._baseCameraPos.z * this._zoomCurrent,
    );
    this.camera.lookAt(this._baseCameraLook);

    // Sparks: integrate, decay, dispose.
    for (let i = this._particles.length - 1; i >= 0; i--) {
      const p = this._particles[i];
      p.age += realDt;
      if (p.age >= p.lifespan) {
        this._sparkGroup.remove(p.mesh);
        p.mesh.geometry.dispose();
        p.mesh.material.dispose();
        this._particles.splice(i, 1);
        continue;
      }
      p.mesh.position.x += p.velocity.x * realDt;
      p.mesh.position.y += p.velocity.y * realDt;
      p.mesh.position.z += p.velocity.z * realDt;
      // Gravity.
      p.velocity.y -= 8 * realDt;
      // Fade + shrink.
      const lifeT = p.age / p.lifespan;
      p.mesh.material.opacity = 1 - lifeT;
      p.mesh.scale.setScalar(1 - lifeT * 0.6);
    }
  }
}
