/**
 * JumpState
 * ---------
 * Airborne. Applies an upward impulse on entry (if grounded) and lets
 * Fighter.update + Physics.applyGravity handle the arc. Allows limited
 * air control on X via input. Returns to idle once the fighter lands.
 */
const AIR_CONTROL_SPEED_RATIO = 0.6;

export const JumpState = {
  name: 'jump',

  enter(fighter) {
    if (fighter.isGrounded) {
      fighter.velocity.y = fighter.jumpVelocity;
      fighter.isGrounded = false;
    }
    this._falling = false;
    fighter.playClip('jump_up', { loop: false, fade: 0.05 });
  },

  update(_dt, input, fighter) {
    // Limited air drift.
    const left = input.isDown('left', fighter.playerId);
    const right = input.isDown('right', fighter.playerId);
    let vx = 0;
    if (left !== right) vx = (right ? 1 : -1) * fighter.walkSpeed * AIR_CONTROL_SPEED_RATIO;
    fighter.velocity.x = vx;

    // Switch to falling animation once we pass the apex.
    if (!this._falling && fighter.velocity.y < 0) {
      this._falling = true;
      fighter.playClip('jump_fall', { loop: false, fade: 0.05 });
    }

    if (fighter.isGrounded) return 'idle';
    return null;
  },
};
